insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('55d22509-742c-5785-88bf-412ae93ac5cc', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '16:30:00', null, '通常 / ４級過去問２問目 魚の問題', '前回の問題①を最初に復習（どういう問題なのか、思い出しながらコードの見返しのみ）をしてから②の問題を行いました。 30分やってみて、半分できた様子でしたが、やはり日本語の壁がおおきいかなという印象。理解度自体はとても２年生にしてはよいのですが、文章で理解をしようと思うと、検定はちょっと今回は難しいかもしれないなと思います（一応検定の書類は渡しておきましたが。・・・）親御さんには次の回までもう少し勉強してから〜という方向性で伝えた方が良さそう', null, 'タイピング: 76%の正答率、あの年齢で5分間集中してタイピングをしているのはとてもすばらしい！
盛り上がり: ちゃんとやった部分をチェックし、文章の読み飛ばしがないかを確認していました！そういう部分は本当に2年生かな？と思うほどです！'),
  ('b480e880-2471-5769-aaaf-62671a5459fd', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-17', '16:30:00', null, '通常 / 単元別演習A-4,5 単元別演習で基本の確認をする', 'A-4はあっという間に理解して作成できていました。完成後、スプライトを変えたり、自分で動かせるようにしたりとアレンジをして楽しんでいました。 A-5の角度で回すところもすぐに理解できていました。 ドリル2問に熱中したせいか、そのあとは「今日はアレンジの気分」となって、99 サッカーPKゲーム＿見本を元にバスケットゲームに改造していました。', null, 'タイピング: 大会参加した後も、何度か練習して楽しそうにしていました。
盛り上がり: 条件分岐はよく理解できているようで、たっちゃん自身もスラスラとできるのが楽しそうでした。バスケゲームのアレンジを、とても一生懸命やっていました。'),
  ('d35dedca-1a58-5c82-8945-a8a1935ce456', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '17:30:00', null, '通常 / ペンツールを使って、図形を書く（四角の問題）', '角度の問題が結構得意なので、今回は新しくペンツールで図形を描くという新しい項目を学ぶことにしました。（ペンツールを使って欲しかった）四角を思い描く時にすぐ90度だということがわかりヒントを与えると、こっちの向きでしょと言っていたので角度の概念自体はとても理解している様子。ただ、〜度回すというコードがあまり使ってなかったので、そういう意味でも、今回のペンツールを使って角度を描くというのはいい勉強になった。', null, 'タイピング: 片手打ちではありましたが、だんだんとローマ字うちに慣れてきている感じがしています。
盛り上がり: 四角は90度、三角形は120度に回すを覚えてくれたので、今後はすこしずつペンツールで何か自分の作品作りに役立てて欲しいかなと思います'),
  ('8eeb2045-165a-5144-968b-c8c329d5279c', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-17', '16:30:00', null, '通常 / 前回の過去問の解答合わせ（過去問１、犬がトラックを回る問題）', '前回３級の特徴が掴みきれていなかったのか、最後まで終わらなかったので、最初からもう一度コードにミスがないか見返しながら最後までやってもらった後に答え合わせ。 制限時間との戦いではあるかなと思いますが、問題自体はよく読んで、解答もきちんとしていました、ただ送らなくていいところでメッセージを送ってバグにつながっている箇所が１箇所あったので、問題文に書かれてないことを間違って解釈しないようにと、アレンジ問題でやりすぎて減点にならないように気をつけてと伝えました。', '過去問②の問題', 'タイピング: 練習では準２まで行っていたそうですが、本番がミスしたと言っていました。
盛り上がり: アレンジに力を入れていて、自分でも面白がってやっていました。'),
  ('df309112-ec9b-55ee-bd27-d230dd19a018', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-17', '16:30:00', null, '通常 / 基本的なブロックの習得', '検定は受けない、と言っていました。それよりも自分の作品を作り込めるコンテストに興味があるそうです。 だるまさんがころんだの大まかな動きは理解できたようですが、細分化がまだ難しそうで、大量のブロックを一度に並べようとして非常に混乱していました。使用するブロックの選択は合っているので、「コスチュームを変える動き」「右に進む動き」など、一緒に細分化していく練習をしました。 細分化シートを書くことは嫌がらないのですが、こちらも大まかに一つの文で書いているので、箇条書きで細分化を意識していくことにもう少し慣れていきたい所です。', 'だるまさんがころんだのアルゴンの動きから', 'タイピング: 期間があいたので、少しゆっくりになっていましたが、最後まであきらめずに取り組んでいました。
盛り上がり: これまで作ったことのないパターンのゲームだったせいか、楽しそうに作成していました。ゲームの捉え方が大雑把で混乱していたのを、少しずつ細分化を意識して作成することで解決できる過程を、感心しながら喜んでいました。
備考: 4月からロボットをやめて、プログラミングを毎週希望です。 コンテストをとても楽しみにしているそうです。'),
  ('98412146-55c0-5989-9c85-7513bca77dc0', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-16', '17:30:00', null, '振替 / アルくんの冒険を進める', 'x座標とy座標がごっちゃになっている場面があったので、横に動かしたいときはx座標、縦に動かしたいときはy座標を変えるということを復習したうえで、ジャンプするときはどっちを変えるのかな？と質問すると、正しいブロックを選ぶことができました。 地面に着地しているかどうか判定するには色で見分ければいいということを理解してもらいました。また、スポイトで色を取ってくるやり方を覚えてもらいました。', null, 'タイピング: 今日はココアをやりたかったみたいです
盛り上がり: 比較的集中してやれたと思います。'),
  ('d2555f94-1249-5b7c-a3c7-27f995cd44c0', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-16', '17:30:00', null, '通常 / 検定練習', '先週解いた問題の答え合わせから行いました。変数項を使った座標の減少の仕方や修正するコードの複雑さで結構悩まされていました。1級の修正問題はパッと見でどんな行動をするかわかりにくいのでバグを探る感じで見てもらいたいです。 次に今日解いた問題は先週分のとき直しをしてからだったのでお手上げ状態でした。リストが複雑さが増していたのでわかりにくかったそうです。ここはしっかりと答え合わせをしてフォローすべきだと思います。', '本日分答え合わせ', null),
  ('6562f3aa-d36b-561a-8c57-f8d5ea765701', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-16', '17:30:00', null, '通常 / 検定練習', '検定のために2級の応用問題を解きました。解き終わった感想としては、変数の値とは何かわからないとのことでした。コードを見ると、正しく組めているが、変数の本質的な意味は理解できていないので、それはこれから授業で理解していけばいいと思います。また、不等号の向きが正しくなかったです。今回は不等号の演算が多かったので、多く失点になるでしょう。そして、前半は文章に線を引いていて読み飛ばすことなく作れていたが、後半に2か所読み飛ばしがありました。公判で集中力が切れたと思われます。 だから、読み飛ばし防止の集中力と不等号の対策はしておいたほうがいい。', null, 'タイピング: 早いです'),
  ('fe5cc302-0c32-5369-b5b9-5ded72bba8f8', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-16', '17:30:00', null, '通常 / 今までやったことを生かして作品作り', '他の子の「名前を動かそう」の作品を一緒に見た後、イメージがわいたそうなので作ってみました。今日の目標を設定し、作り途中に他のものに興味が移ってしまったときはその目標を思い出させました。「〇秒で座標を変える」「端に着いたらはねかえる」のブロックを活用して作っていました。最終的に2つの文字を動かすところまでいったので、来週はもっと多くの文字に手をつけたいです。', '続き', '盛り上がり: 自分のパソコンで文字の動きをお手本として見せたときなどに「楽しそう」と言っていました。'),
  ('df8322a5-881a-533b-b044-26f6f37de600', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-16', '17:30:00', null, '通常 / 検定練習', '検定のために2級の練習問題を解きました。出来具合は、コードはすべて完成していたが、試行中に作った余分なものが無駄に動いてしまい、上手く動いていませんでした。だから、そのような粗を無くすために見直しをしっかりしてほしいです。アレンジはどう変化させたかコード的に文章が欠けていてわかりやすかったです。', null, null),
  ('fccfb79c-270b-58de-a46d-50b7a8d4fd5f', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-16', '16:30:00', null, '通常 / 検定練習', '最初に前回解いた1級の練習問題の答え合わせをしました。文章量が多かったので1個だけ読み飛び出ししていただけで、ほかは完璧でした。次に、また1級の応用問題も解きました。普通に時間も余るぐらいでできていて、ひいろくんに一人で答え合わせをしてもらったが、完璧でした。もう1級は合格するでしょう。', null, '盛り上がり: 1級を軽々しく説いていてすごい'),
  ('5c6ef74a-0f08-58b9-a3a9-947382f4ee56', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-02-16', '17:30:00', null, '休み（未対象） / 発疹で病院にいくためとのこと。当日連絡のため振替未対象', null, null, null),
  ('e50c6bb0-a8c3-5508-97e7-999ca19530d2', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-14', '17:30:00', null, '通常 / ゾンビゲームを通してコード使い方を慣れよう', 'チュートリアル動画見ながらゾンビゲームを作りました。敵の動きやビームの発射に器用に使えていていました。ゾンビにHPをつけて作り変えでは、変数の入れる位置を正しく作れました。完成後に、お母さんに作ったゲームを共有できてとてもうれしがっていました。', null, null),
  ('b6cae5c2-8863-5e35-9495-92e1ce33b863', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, null, '2023-02-14', '17:30:00', null, '休み（未対象）', null, null, null),
  ('7a2abfb3-5839-5985-9e75-f39f363a89e2', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-14', '16:30:00', null, '通常 / 検定練習', '検定のために4級の第17回の問題を解きました。集中力が足らないです。ほかで起こっている出来事に気が飛んで行ってしまうので、目の前のやることに続けさせる努力が必要です。そのため、全体の7割しか解けていませんが、そこまでは1ミスでよくできていました。あと、文字を打つことをめんどくさがるしぐさもありました。', '集中して解く', '盛り上がり: 学校のPCで作ったジャンプゲーム上手に作られていた。'),
  ('0b0afefb-bb32-5e15-bb2d-b8ea9d0918b7', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-14', '17:30:00', null, '通常 / 基本操作コース03 アレンジ、基本操作コース04_追跡ゲーム', '世界を創造しようでは、座標で動かすブロックと背景を変えるブロック、音のブロックを使うことを課題にしました。 グリフィンが滑走路を使って宇宙に飛び立つプログラムを、熱心に作っていました。 無事にグリフィンが宇宙に飛び立って音楽が鳴った瞬間に、「できた！」と満足そうにしていました。 上記の時点で残りが20分強あったため、次の単元に進みました。ずっとお話を作ってきていたので、一度気分を変えてゲームに進もうと「サメから逃げろ」をプレイさせましたが、ゲームの意図がつかめないとつまらなそうだったので、追跡ゲームと比較させ、追跡ゲームを選びました。 追跡ゲームの方はそれなりにやる気になって、スムーズに「～に触れたら」の条件分岐まで進みました。', '追跡ゲームのスコアの変数作成から', 'タイピング: 1回だけチャレンジして、すぐにプログラミングをやるとやめていました。
盛り上がり: 興味が持てるものと持てないものがわりとはっきりしているようです。オリジナル作品は、とても熱心に作っていて、見せてくれる時も嬉しそうでした。 サメから逃げろと追跡ゲームをくらべた時のテンションの差もハッキリしていて、自分で選んだ追跡ゲームはよく頑張って作っていました。
備考: わんこ大戦争ゲームをずっとやっていました。'),
  ('9d008eb5-d29f-54a7-ae84-4ac7499dc999', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-14', '16:30:00', null, '通常 / 変数を使ったゲームを見て作ろう', '変数の使い方をゲームを通して検定の問題を細分化しながら作りました。ゲームを遊んでみたそれぞれのスプライトどうなっているか尋ねたところ、それなり答えられていたので、スプライトをオリジナルなものに変え、作り始めました、作り方に条件を出してみたが、さっき考え出したことからコードブロック的に文に言い換える上手くいっていませんでした。流れを図示してやっと伝わる程度でした。まっすぐ進むや回転するブロックなどの動きに関するものに感が鈍く感じました。', null, 'タイピング: スコア上位でした
盛り上がり: アルスパークスタッフにパンを投げつける発想は面白い'),
  ('ad8e6f02-4eb3-5e25-adb9-01dc39fa568f', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-13', '18:40:00', null, '通常 / 検定練習', '練習問題の最後のアレンジで、凝った面白いアレンジをしていました。ただ、そのことが原因で少しタイムオーバーしていたので、いつもだったらいいアイデアだけど検定のときだけはコンパクトなアレンジをするようにしようと声をかけました。また、アレンジの説明文がざっくりとしていて採点者に伝わるか分からないものでした。そのため、アレンジの意図を納得してもらうためにも、キーの名前なども入れて動作を具体的に説明しようとアドバイスしました。アレンジ以外は、細かい読み落としミスをした程度で、あまり問題なくできていました。', null, null),
  ('7f316430-3ad3-54c0-b137-227e98742039', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-13', '17:30:00', null, '通常 / 変数と繰り返しを使ってジャンプを作る', 'メッセージを使う問題1,2はすぐにできたので、変数と繰り返しを使う問題3,4に入りました。問題の状況がつかめていなかったようなので、変数という箱に数字を入れるイメージを説明しました。変数が4だったら4回繰り返す、変数が5だったら5回繰り返すというように、変数に何かの数字が入っている具体例を示すと理解したようで、自分でコードを書くことができました。 そのあと、変数の回数だけジャンプするのをやりました。変数回繰り返すという部分は直前にもやったのですぐにできたのですが、等速ジャンプに少し苦戦したので、過去に作った等速ジャンプのコードを見返してもらいました。', null, 'タイピング: アルファベットの羅列は打てますが、日本語の単語はまだ苦手なものが多いようです
盛り上がり: 分からないものはすぐに投げ出そうとしてしまう一方で、何をすればいいのか理解したものは頑張れました。'),
  ('2f900a23-fe4d-5ff3-9154-3c7e5025a108', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-13', '18:40:00', null, '通常 / 検定練習', '変数が様々な方法で使われている2級の⑪を解きました。変数の使いどころは1箇所除きすべて正しく組めていたが、番号の振り分けが読み飛ばしなのか1つのスプライトに固まってしまってほかの食べ物が消えないバグが残っていました。条件が難しくなってくるとただ単純につなげてしまう傾向があるので、そこを踏ん張ってもらいたいです。最後にバグつぶしの手順を軽く文章とコードを見比べながら順にたどっていくようことを共有しました。', '1級2回目', null),
  ('df532361-d13f-5f28-a393-60ebfb6792f3', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-13', '16:30:00', null, '通常 / 2級の答え合わせ復習', '先週解いた2級のロケットゲームの答え合わせ及び復習をしました。まず、たし算を問うところのでは「と」をつなげて変数を文章化することを理解していました。正誤判定では検定の文章からコードに置き換えることを補助しました。そして、オウスケ君一人で解いた時の散らばりでバグになっているのを直すために文章とコードの読み直ししました。これは、聞くだけ自分では探しはしないこの癖が直すために、オウスケ君自身で試して確認することを徹底させました。本人は若干詰まんなくなった感じていたが、自分で探す能力を伸せたと思う。 時間がなくてできてなかった雲と鳥を修正するとこでは自分自身で考えてスムーズに解くことができました。 わからない、覚えてないときの対処法が少し鈍いなと感じました。能力はあるがたくさんの作品を作っていない経験の差からくるものかなと思いました。質問形式に左の分類からイメージでたどっていくようにさせました。', null, null),
  ('26b9304c-6c0e-5838-ad44-8f6fba4587ff', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, null, '2023-02-13', '17:30:00', null, '休み（未対象）', null, null, null),
  ('55102b55-1e9b-5602-b8f7-5ed87591997b', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-02-13', '16:30:00', null, '休み（未対象）', null, null, null),
  ('817be55c-ce7a-5466-97f2-a9681c7f6345', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, null, '2023-02-13', '16:30:00', null, '休み（未対象）', null, null, null),
  ('3804975a-ed6e-583c-b59c-26683774852b', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-11', null, null, '通常 / レッスンを進める', '「アイスを食べに1」をすでにやったようなので、2を動画を見ながらやりました。だいたい順調に作れましたが、一か所間違えて軽いバグになっていたので、質問しながらバグ取りに取り組んでもらいました。ブロックを追加すればよいことはすぐわかったのですが、入れる場所が違っていたため、どのタイミングでそのブロックが欲しいか考えてもらい、無事直すことができました。 そのあと「ゾンビを倒せ1」に入りましたが、スプライトと背景を用意したところまでで終わりました。', null, '時間帯: その他
タイピング: キーを探しながら頑張りました
盛り上がり: ゾンビを倒せシューティングゲームにはけっこう興味がありそうです。'),
  ('38c19a45-7418-55a9-a871-e0a863237892', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-11', null, null, '通常 / 検定の練習を積む', '終わったあと、「機能はちゃんと動いてるから答え合わせはいいよ」と言っていましたが、機能があっていても問題文と一緒じゃないと点が入らないことを伝えて答え合わせをしました。 大体はできていましたが、ちょっとしたミスが見られました。「④のあと」に入れるブロックを違う場所に入れていたり、「相手の手=自分の手」と書けばすむところを難しく考えすぎていたりしました。 検定でアレンジが得点になることを知らなかったそうです', null, '時間帯: その他
盛り上がり: 淡々と解き進めていましたが、終わった時にいろいろしゃべっていました'),
  ('7a84e7c4-be73-5651-a8cb-f1ce414a381b', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-11', null, null, '通常 / 検定に向けて、問題文を読む練習', '前回の練習問題では自分で文章を読めるようになるのが課題だったので、問題文の終わったところに〇をつけるというのをやってもらいました。そうすることで、現時点で問題文のどこまで進んだのかは把握できたと思います。ただ、「①のあとの動作」などの指示を読み落としていて、その「①」がどこを指しているのかも誘導してあげて初めてわかっていたようでした。 その他にも「魚の動作を止める」と書いてあるときに、コードとしては何を止めればいいのかがわからなかったりしたので、コード全体の意味を把握することも必要だと感じました。 止まってしまった時間が多かったこともあって解き終われなかったので、次回もう一度やったほうがよさそうです。', '今回の答え合わせ、解きなおし', '時間帯: その他
盛り上がり: レッスン時間が終わった後のアレンジは楽しそうにやっていました'),
  ('794d53cc-259a-56b1-a459-391229bdd92f', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-11', null, null, '通常 / 基本操作コース2、3、6で学習した項目の見直し、基本操作コース04_追跡ゲーム', '前回から作成しているオリジナル作品の続きから入りました。メッセージと座標の復習をしつつ、コース表で、なつめちゃんができるようになったことを確認してもらいました。 メッセージで会話を続けていくのが楽しかったようですが、最後の方は若干惰性になっていたので、キリのいい所で一旦完成とし、追跡ゲームに入りました。 追跡ゲームを一度遊んだ感想は、「なんかよくわからないゲーム」でしたが、細分化を促すような発問をすると、きちんと答えてくれて、どんなゲームかということもわかってきたようでした。 座標の復習をしたため、矢印キーで動かすことはすぐに理解できたようでした。左右キーを一緒にやった後、ひとりで上下キーの動きができたときは、声を上げて喜んでいました。 変数は初めてのため、説明をしてから作成しました。', '基本操作コース04_04から', '時間帯: その他
タイピング: 安定してこなしています
盛り上がり: メッセージがうまく使えるようになって会話がスムーズに続くようになったときや、上下キーで動かすところが自力でできたときは、とても良い笑顔で声をかけてきていました。 今日は敢えてゆうかちゃんと席を別にして、進度の比較を意識させずにできたところを褒めるようにしたせいか、よく話してくれて、伸び伸びと楽しそうに取り組んでいました。'),
  ('79bf437b-a2ae-52bf-a7ab-5522cbcde7a6', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-11', null, null, '通常 / 基本操作コース2、3、6で学習した項目の見直し、基本操作コース04_追跡ゲーム', '前回から作成中の作品を完成させながら、コース表を見て自分が覚えたブロックを確認しました。 追跡ゲームの細分化をしました。ほぼ問題なくできていました。 作成したゲームを実際にプレイして不具合に着目することで、条件分岐に「ずっと」が必要なこと、変数の初期値設定が必要なことに自分で気づき、修正することができました。 「～まで待つ」のブロックは初出のため、説明をしました。', '基本操作コース04の06「背景が○○になったとき」から', '時間帯: その他
タイピング: 相変わらずノーミスです！
盛り上がり: 新しい課題に入ったことがうれしそうで、追跡ゲームも可愛らしいアレンジで楽しそうに作っていました。 細分化も特に抵抗なく取り組んでいました。 新しく覚えた「～まで待つ」のブロックできちんと背景が変わった時に、とても喜んでいました。'),
  ('6a684db3-4b3e-5a7c-b9f5-9a38e6d70db3', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-09', '17:30:00', null, '通常 / 一緒にできれば【Prg】28 まゆネコをさがせ', 'まさきくんがよく作っているゲームに似ている「まゆネコを探せ」を勧めましたが、興味は持たなかったようです。今日は時間になるといつもより早く自分のゲームの作成を始めていました。脱出ゲームを作っていました。ネコを動かしてタイルに触れたらタイルが点滅したのちに色が変わる、特定の条件を満たしたら背景を変えてゲームクリアにする、制限時間をカウントダウンするなど、ゲームとして面白い要素がいろいろ入ったものを自作することができました。', null, '盛り上がり: いつもよりすんなりと進めていた感じがします'),
  ('0810ed43-fa07-535a-99d9-df15b1bbc113', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-09', '17:30:00', null, '通常 / 検定練習', '最初に先週解いた問題の答え合わせをしました。ミスは1っか所だけで時間も余らせよくできていました。1かっ所のミスは、もし条件の範囲の違いでした。問題文の「～のとき」の適応範囲がそのあとに続く4文かその1文だけなのかの判断の読取りが上手くできていなかったです。2級以上の検定に頻出する表現なのでそこを注目してもらいたいです。 次に、2回目の1級の問題を解きました。時間的余裕はあったが、ビルの演算のところがわからなかったそうです。ほかのところはゲームを見た感じできているぽいので、合格には届きますが、確実性を増すために苦手なところをつぶしていければいいと思う', '答え合わせ', 'タイピング: やり直し癖が多い気がする'),
  ('ee6a33b7-5cb6-5982-a75d-aaa76417c200', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-09', '17:30:00', null, '通常 / 2級1回目S_S_3 見直し', '前回、ロケットの動きが全然できていなかったので、わからないところをチェックするため一緒に見直しをしていきました。 文字列と変数をつなげるブロックを使えていなかったため、「〇＋〇＝？」や「点数は△点だよ」の文章の中で、変数なのはどの部分か、というところから解説しました。1度目の説明で納得できたようで、「点数」の方は自分で作成することができました。 条件分岐や繰り返しの条件のブロックは作成できるのですが、どの動作までがその条件内に入るのかがかなり適当というか曖昧でした。検定に限っては、文章そのものがヒントとなっているため、文章の体裁を崩さずにブロックにしていくことを心がけることや、その条件の中ではどこまでの動作を実行するのかをよく考えることを伝えました。 前回手付かずだったスプライトの修正の方は大体できていました。（向きに着目できていなかったので、動かすブロックをx座標やy座標を変えるブロックに置きかえていました。）', null, 'タイピング: タイピングは相変わらずとても速いです
盛り上がり: 使うブロック自体は大体あっていたため、順序に着目して入れ替えるとうまく動くようになり、そのときは嬉しそうでした。 文章を素直にブロックにしていくことに慣れれば、もう少しできるようになるのではないかと思われます。'),
  ('5e289892-a22e-5a1b-91d9-e78f209159f3', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-09', '17:30:00', null, '通常 / 前回の続き', '前回同様にお手本の動きを見てから取り掛かることで、興味を持ち完成をイメージすることができたと思います。背景の切り替えをするところで、自分で描いてみたいと言ったので描き方を伝えました。また、「〇秒でどこかへ行く」の使い方を身に着けました。以前使ったブロックをもう一度使うことになったとき、「これ前にもやらなかったっけ？」と聞くと、「あれだ！」と嬉しそうに思い出していました。', '基本操作コース03,06の続き', 'タイピング: このキーってどこにあるっけ？と思い出しながら練習していました
盛り上がり: 「ニンテンドースイッチの背景を描きたい」「マイクラみたいなゲームを作ってみたい」など創作意欲があるので、プログラミングの習得にうまく落とし込んでいきたいです。'),
  ('461722be-36a3-5f70-a5a0-b8be9d987573', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-09', '16:30:00', null, '通常 / 検定練習', '最初に先週解いた検定の問題の答え合わせをしました。コードがわからないなどのミスはなく、凡ミスが2個あるだけでした。やった手応え的にも日色君自身は難しいと感じていないそうです。 次に、2回目の1級の問題を解きました。時間はアレンジも含めて10分以上余らせて終わっており、難易度も前回のものと変わらなかったそうでした。なので、ヒイロくんは1級レベルの問題に対しても特に困ることがない能力を持っていると思います。', '答え合わせ', 'タイピング: 毎パソ機関化が明けてスコアが伸びていた
盛り上がり: アレンジを作っているときはとても楽しそうな雰囲気でした。'),
  ('87c05186-548d-57d5-a310-286c41e8e6a1', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-09', '16:30:00', null, '通常 / 宇宙バトル続き 条件分岐の使い方に慣れる', '本人の希望で、先週のゲームクリアに続き、ゲームオーバーの動きを作成しました。 まだ、何も見ずに条件分岐を作成することには迷いがあるようですが、前回の敵スプライトで作成したコードと同じように作成するということは覚えていて、参照しながら自作していました。 ゲームオーバーやゲームクリアの音がうまく流れないと悩んでいたため、「終わるまで音を鳴らす」ブロックを勧めました。これにより、背景が変わるタイミングがずれたのに気付いたので、順次処理の説明をしました。 自機のパワー=0の条件だとうまく発動できなかったので、不等号の使い方を教えました。', null, 'タイピング: ココアタイピング内の検定に1度だけ挑戦しました
盛り上がり: ゲームオーバーの後のアニメーションのアイディアがうまく実行できたことが嬉しそうでした。発想が言葉でどんどん出てくるので、それをブロックでどう実行させるか、少しずつ考えられるようになってきました。'),
  ('62950ec5-b493-5528-8d1b-8cd7823cd09c', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-07', null, null, '休み（未対象） / 検定問題のお渡し', null, null, '時間帯: その他
備考: 2023/2/7お渡し分 ・3級応用課題7_B23 ・3級応用課題8_B24 2022/11/4 お渡し分 ・3級応用課題2_B18 ・3級応用課題3_B19 ・3級応用課題5_B21'),
  ('22af9944-3665-54f2-b57b-c87d8432e806', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-07', '17:30:00', null, '通常 / 単元別演習D メッセージの使い方に慣れる', 'メッセージは合図ということで理解したようでした。 D3は、ボタンのスプライトに「矢印キーが押されたとき」を使っていたので、「ボタンを使おう」と促すと、「そういうことか」と気づいたようでした。文章から問題の意味すべてを読み取るのはまだ難しいのかもしれません。', null, 'タイピング: 毎パソの後、ココアタイピングにも熱心に取り組んでいました
盛り上がり: メッセージの使い方にはだいぶ慣れてきたようで、「こんな風にできた」とちょっと得意げに見せてくれていました。'),
  ('9d8c1bc1-487a-5e9a-9f4d-dcd0bd61e843', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, null, '2023-02-07', '17:30:00', null, '休み（未対象）', null, null, null),
  ('9aa8fab5-5b02-5742-90aa-997b8c50ffae', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-07', '17:30:00', null, '通常 / 検定問題に慣れる', '検定の問題を見せたところ、とてもモチベーションが上がって楽しそうに解いていました。4級の問題が時間内にアレンジまでできて、「簡単だったので次の級の問題を見てみたい」とのこと、3級の問題を20分で解き終えて、「楽しい」との感想でした。 ゲーム中のBGMとクリアしたときの音楽が思うように鳴らないとのことで、「このスプライトのほかのスクリプトを止める」ブロックと、音楽を鳴らすコードの場所に着目することを意識するよう指導しました。ゆずとくんも納得したようでした。', '3級の違うタイプの問題に取り組む', 'タイピング: 1回だけ練習して、よい結果が出たので、すぐに本番にチャレンジしていました。
盛り上がり: しばらく低迷期？だったようで心配していましたが、今日はとてもやる気で頑張っていました。問題文をしっかり読んでその通りにブロックを組むのは楽しいらしく、試験中から答え合わせの時まで、終始楽しそうでした。 検定を受けることでモチベーションが上がっているので、3級にチャレンジさせても良いと思われます。
備考: 前回の検定問題チャレンジの頃よりも伸びています。次回3級問題を解いてみて、もっと練習がしたいようなら問題を持ち帰ってでも、3級をやりたい！という感じでした。'),
  ('af0fc8aa-baa3-592b-ae02-3d0ad14f498f', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-07', '17:30:00', null, '通常 / 世界を創造しようの続き', 'コスチュームを変える際の注意点(〇秒待つ)、移動させるときには初期位置の設定をすることを説明しました。音と大きさを同時に変化させるプログラムを作ったときには、とてもこだわって作成できていました。使う背景・スクリプトにきちんと世界観があるようです。来週は今回まで学習したことを使って作品を作ってもらう予定です。あらかじめ見本をみせるといいかもしれません。', '作品を作る予定です。', 'タイピング: うまくいかないとキーをガタガタしがちです。'),
  ('e6c75105-74bb-5563-83a5-cab8a805fe50', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-07', '16:30:00', null, '通常 / 宇宙バトル2(復習)', '先週やったことを復習したあと、宇宙バトル2をチュートリアルを見ながら進めました。前回戦闘機を上下に動かした方法は角度と歩数で動かしたので、チュートリアルをみつつ、x、y座標を変更することで戦闘機を動かせることを確認しました。敵HPも事前に変数に注目できていたので良かったです。最後に「=0」としたところに疑問をもってくれました。時間がなくて扱えなかったので残念です。', null, 'タイピング: ノーミスでタイプできていました！すごい！！
盛り上がり: 検定の制度について聞いてくれました。1級より上に興味があるみたいです。'),
  ('d61a15b3-d37b-5451-9ffd-4eb9c7ebec26', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-07', '17:30:00', null, '通常 / プログラミング検定問題 2級 最初にやるもの', '43分ほどかけて取り組んでもらいました。途中分からなくなってしまった部分があるものの、自分で振り返って取り組めたようです。時間中、とても集中して取り組めていました。難しかったようですが、確認したところミスはゼロでした！！アレンジに取り組む時間まではなかったようです。2級を受験しても大丈夫かと思います。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 黒のWindowsPCが相当嫌いなようです。'),
  ('80076ec0-015d-5251-b795-fd6136fe034c', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-07', '16:30:00', null, '通常 / 検定4級 (応用課題1)', '時間中、質問することなくほぼ自力で解くことができました。a, bと順序付けていることや、「以下のように」などの表現には戸惑うことがあったようです。文章の読み飛ばしはありませんでしたが、「~まで繰り返す」がでてこなかったり、「他のスクリプトを止める」が分からなかったりしていました。スクリプトについては細かく説明しました。', null, null),
  ('7d06b5d7-572b-57a1-b008-37a740325547', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-07', '16:30:00', null, '通常 / 単元別演習C：変数の使い方の復習', '算数的な問題になると、何から手を付けてよいのか全く思いつかなくなってしまうようで、C-2（1から100までの足し算）は最後まで何をしているのか自分でもわからないようでした。説明はしましたが、「合計」と「足す数」の違いや関係も、図解をしても？？？という感じでした。 一方で、C-3やC-4のような問題はイメージが付きやすいのか、自力で解こうと頑張っていました。 変数の初期値の設定と繰り返しの位置、変数を変化させるブロックの位置の関係が、まだあやふやなところがあります。', null, 'タイピング: 本番にチャレンジしました
盛り上がり: さらちゃんにとっては苦手分野のドリルだったにも関わらず、途中で投げ出さずに「最後までやる」と頑張っていたのは偉かったです。面倒なこと、苦手なことでも向かい合って頑張っていました。'),
  ('d00317c6-e746-5f49-b9aa-fb71f940518e', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-04', null, null, '通常 / タイピング検定3部門、プログラミング検定3級の問題に挑戦', '問題は自分でこれがやりたい、と選びました。 時間内にできていましたが、つりばりが動き続けてしまうバグが直せなかったそうです。 コードを並列でかく傾向があったため、つりばりを動かすコードが動きっぱなしになっていました。問題の書き方がヒントにもなっていることで納得して、すぐに直すことができました。', null, '時間帯: その他
タイピング: 英文A、和文A、和文Bの本番をしました
盛り上がり: 検定を楽しんでやっている様子です。 色々な問題にチャレンジできるのも楽しそうで、問題を選ぶときもワクワク感がありました。
備考: 3月の検定は見送って、7月に2級にチャレンジすることになりました。7月までの間に2級の練習をしていく予定です。'),
  ('21b05a46-b3e7-53cb-9928-be9d363c0ce4', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-06', '18:40:00', null, '通常 / 定義・リストの確認/検定練習', '最初に、1級の検定に必要となる定義とリストの理解を深めました。「掛け算」ところでは定義がどのように使われているか説明してもらいました。そして、コードの重複を省く利点も共有しました。また、占い」ではリスト自体を知らなかったので、コードを見ながら変数との違いや、取り出し方など基本的なことを共有しました。 次に、1度やって事のある2級のじゃんけんゲームを解きました。時間的には大丈夫で、勝利条件は理解はできていたが不足いたり、多少の読み飛ばしがありました。肝となるじゃんけんの勝利条件は時間はかかりつつも理解はできていたので、考えた後の読み飛ばしを注意してもらいたいです。', null, null),
  ('36bb2493-c31d-5dd3-8eed-9b0035c08e99', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-06', '18:40:00', null, '通常 / 検定３級 応用17', '寝坊して、遅れてきたので問題のみ。 最後に感想で聞いてみたところ、本人的にはあまり難しいと感じなかった様子。 ざっとみした感じだと演算の使い方はとてもよくできているので、次回は変数の問題が合わさった問題19をやりたいと思います', '次回は回答合わせと、問題19をおこないたい', 'タイピング: なし
盛り上がり: アレンジをする時にもう１個スプライトを追加して、コードを書いていました。単純に複製した感じはありましたが、ある意味アレンジはアレンジなので、本人に自信がついていればよいかなと思います。'),
  ('2cfd36b0-3fe9-54c6-ba8e-e652365a08a9', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-06', '17:30:00', null, '通常 / 脱出ゲームの完成', '先週に続いて脱出ゲームを作っていきました。敵の動きをもう少し凝ってほしいと思っていたが、自分で作るが優先し、結局見ないで作りました。敵や通路外に触れたら止まる仕組みもしっかりと自分で考え出せていました。最後、ゴールにたどり着いた時に場面転換することに時間を費やしましたが、完成できました。', null, 'タイピング: 最近は敵も強くなってきて負けて終わることが多くなってきました
盛り上がり: ゴール後の母子が出会うドラマを作っていてほっこりした。'),
  ('8a8c0e75-ea44-56b2-b3c5-85c155127bb4', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-06', '17:30:00', null, '通常 / 検定を受ける上での課題を克服する', '先週の検定の解きなおしからやりました。本人は問題文を正しく読めているつもりでも実際は読めていなさそうなので、一番最初の文から順に読んでもらって確かめていきました。その結果、似ているブロックを勘違いして使っているミスが多かったです。例えば「コスチュームを～に変える」と「次のコスチュームにする」、「～回繰り返す」と「～まで繰り返す」、「変数を～にする」と「変数を～ずつ変える」などです。問題文を読みつつ、問題文の途中にある「使うブロック」を確認することを促しました。 そのあと、先週はできなかったアレンジをやってもらったのですが、難しいアレンジばかり挑戦しようとするので、検定では制限時間内に終わるような簡単なアレンジにしようとアドバイスしました。 最後に演習問題に取り組みました。そのとき変数の初期化を忘れていたので、「変数を使うときに最初にやることって何だっけ？」と聞くと思い出していました。', null, 'タイピング: 時間になると潔くゲームをやめてタイピングに切り替えていました。先週までの毎パソの形式に慣れすぎてちょっと大変だったそうです。
盛り上がり: 先週よりも集中できていて、ミスにも自分で気づけることが多かったです。'),
  ('0463826a-f57b-5567-aade-66a996276613', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-06', '16:30:00', null, '通常 / 検定問題２級をやってみて、どれぐらいできるのかを確認する', 'やはり演算の部分でかなりつまずき、りんごとばななの演算、変数のルールの使い合わせがやったことがないからか、最後までバグを潰すことができなかった様子でした。 答え合わせをした際に、どうしても２級特有の「それぞれのブロックのルールが書かなくてもすぐわかる」が詳細に書かれてないとぱっとは思いつかない感じなので、来週も答え合わせをしてみて、再度３級に戻るという手順にいきたいと思います。', '回答合わせ&３級の問題のどれか', 'タイピング: なし
盛り上がり: 自分が使ったことがないブロックに戸惑いながらも、難しいから集中するという部分のフェーズになっていたので、今日はある意味彼にとってよかったと思います。'),
  ('112c23db-f420-5c69-a3c5-17cf7afc6969', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-06', '16:30:00', null, '通常 / 検定の答え合わせ＆練習', '前回やった2級検定の答え合わせからやりました。はるちゃん自身は全体的に自信がなかったが、いざ答え合わせしてみるとミスは2か所だけでよくできていました。１つは初めて点火したときの条件が抜けていて、もう1つは不等号の向きが逆でした。修正するところでも特に不安といっていたが、見落としやすい向きなども修正できていて文章通り読み取って正しいコードを組み立てられていました。 次に検定練習のじゃんけんゲームを解きました。出来具合としては、じゃんけんの勝利条件が演算が全く分からなかったそうです。なほ追記：じゃんけんの部分は判定が難しく、変数を箱の理論で考えないといけない▶︎頭だけで考えてもダメだよということ、紙に書いて整理すると良いとのことを伝えました。また「または」のコードの使い方が何個も重ねる部分がどうしても使い慣れてないからか、理解と習得には時間がかかりそう▶︎演算のまたは、かつ〜を使う練習をした方がいいかも', '検定練習', 'タイピング: 毎パソの効果が出たのかミスタイプが減っていました
盛り上がり: 出来栄えが不安だったことに反して実際はよくできていたので自信をつけさせました。'),
  ('1797b873-b9e4-5ae1-a9c5-d435360cd569', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-02-06', '16:30:00', null, '休み（未対象）', null, null, null),
  ('761446e3-80e2-54ed-83fe-923176c9e349', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-02-04', null, null, '通常 / 前回の復習と応用で作品作り', '佑香さんと一緒に前回の復習をしました。前回の内容を一問ずつ確認しましたが、しっかり身についているようでした。その後「3回以上会話をする」「あとから何かが登場する」という条件でオリジナル作品を作りました。もう少しで完成なので、次回で完成できると思います。', 'オリジナル作品を完成させて、その後次の単元に行くのが良いと思います。', '時間帯: その他
タイピング: コツコツできてます。
盛り上がり: 完全にオリジナルの作品を考えるのはまだ苦手なようでアイディア構築のためのサポートが必要ですが、振り返りの際には自由にキャラクターや背景を選んで、楽しそうにしていました。創作意欲がわくように、うまく褒めて自信をつけてあげたいです。
備考: 佑香さんがアイディア豊富なので、その辺をひけめに感じて自信を無くさないように、夏芽さんの良さを褒めていきたいです。'),
  ('44b54070-fa08-5a4d-94df-8d1831f451b8', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-02-04', null, null, '通常 / 前回の復習と応用で作品作り', '夏芽さんと一緒に前回の復習をしました。前回の内容を一問ずつ確認しましたが、しっかり身についているようでした。その後「3回以上会話をする」「あとから何かが登場する」という条件でオリジナル作品を作りました。創作が好きなようで意欲的に受賞に取り組んでいました。', '次回は夏目さんのオリジナルの作品作りが少し残っているので、その間オリジナル作品のブラッシュアップをして、その後２人で次の単元に行くのが良いかと思います。', '時間帯: その他
タイピング: コツコツできてます。
盛り上がり: オリジナル作品作りは、どんどんアイディアが浮かんできて楽しそうでした。 上手にアイディアを形にできていました。絵をかくのも好きなようです。 オリジナル作品も完成しました。'),
  ('32eddb87-235b-5f70-83c2-acf13c741f22', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-04', null, null, '通常 / プログラミング検定4級初回E_S_3 日本語をプログラミング言語に翻訳する練習', '一人で文章を読むのはまだ不慣れなようで、一人にしておくと手が止まったりもしていましたが、こちらが文章を読めばほぼできるので、まず自分でやってみる、ということに慣れさせていきたいところです。 「～まで繰り返す」の下に「もし～なら」を入れてしまうので説明をしましたが、何度か同様の問題をやらせたいところです。 馬の表示非表示を切り替えて、ネコから逃げるのを楽しんでいたので、それをコードにして「ゲーム」にしてみようと誘ったら、とても喜んでアレンジをしていました。', null, '時間帯: その他
タイピング: ぴゃ行の練習をしていました
盛り上がり: ゲームのアレンジをとにかく楽しんで、一生懸命やっていました。 アレンジの過程で、音のブロックの使い分けやコスチュームの編集を覚えることができました。
備考: 伊藤先生作のゲームで盛り上がっていました。'),
  ('9720a67f-c03f-5e56-a5a2-c887d85d7115', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-04', null, null, '通常 / 単元別演習G 演算の復習', '単元別演習の教材を見たとたんにちょっと面倒という反応を見せたので、検定の上級やこれからのゲーム作成のために演算式やタイマーの使い方ができているかチェックしようということで、納得して始めました。 「コスチューム#」のブロックが自力で見つけられなかったようで、なぜか「コスチュームのx座標」のまま進めていて、うまく点数が入らないと悩んでいました。 コスチューム2のときしか表示されない舌の色と、コスチューム3のときという矛盾した条件を指定していたので、思うような結果にならないときは条件をよく見るよう勧めました。 タイマーとテキストをつなげるブロックは、前回の足し算ロケットでよくわかったと言っていて、問題なくできていました。 不等号には一瞬迷いを見せましたが、ブロックを見比べて選択することができていました。', null, '時間帯: その他
タイピング: 淡々とこなしていました
盛り上がり: 「知っていることをドリルでやるのは面倒」と言いつつ、作り始めたら熱中して頑張っていました。ゲームが少し難しくて、得点が入らないのがプログラム上のバグなのか、自分のゲームの腕なのか迷っている節がありましたが、一緒に検証しようと誘うと段々盛り上がってきて、作成したコードの説明も積極的にしてくれました。（得点が入らなかったのは、両方の理由でした…） こちらが一緒にやっていると、意見を活発に言ってくれるようになって、バグ探しも頑張ってくれました。'),
  ('4224cd2a-70d1-5721-99c4-48b29825c2e6', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-01-31', '17:30:00', null, '通常 / 何か取り組む！！', '先週宇宙バトル１をほぼ作り終えていたので、「２」の続きへ。動画をみて作るのは性に合っているみたいです。 変数が登場し、変数名を入力しなければならないシーンで固まっていた。「どうした～？」と声をかけるも反応がないので、あえて手を貸さず「わからなくなったら声かけてね」と伝え様子みる。数分後も全く同じ状態だったので、「もしかして入力できない？」と聞くと、はじめてうんと反応してくれました～！ 反応がないのを、あまり質問せず、回答をあげないで「しばらく待つ」ということをしていきたいと思います。', '続きか、もう少し簡単なゲームを。アルスパークのチュートリアルが適しているようだ', 'タイピング: 自分で画面を立ち上げてすすめます。ももたろうは好きみたいです。大文字と小文字の区別がついているのか？迷いはなさそうです。
備考: お父さんには反応について話をし済み。待つようにすること、そのため時間がかかりそうというのを了解していただいてます。むしろ感謝しているので。プログラミングスキルアップより、彼のペースで彼の興味の分野を少しずつ体験すること、人との関わりがあることを重視してしばらくやっていきましょう。'),
  ('63752b49-08ad-5495-a22a-0e1e1a51d56e', '7d01236e-620e-5177-a6f4-af325a582aae', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-01-31', '17:30:00', null, '通常 / 基本操作06 物語を作ろうで使ったコードを復習し、オリジナルを作れるようになる', '先週、一通り「③基本操作コース_06」をやり、最初に先週やったコードの復習をしたところ、ほぼ全てを覚えていてすごいです！ １点、「メッセージを送る」だけ混乱しています。 「７秒まってうごく」というメッセージの名前を作り、それを送ると「７秒待つ」となると勘違いしている。これは先週も同じ勘違いをしており。その際に「メッセージの名前をあああ」にして動かしてみると「あっ、これでも動くんだ」と理解したかと思っていたのですが。理解度がやや低かったみたいで、今週も同じ勘違いをしていました。 時間的に、じっくりとやった方がいいと思い。今週はメッセージ以外のコードを復習し、それらを使ってオリジナル作品つくり。 キャラクター２つで会話／何かがおきたら背景が変わる／何かで新キャラ登場 この条件で作品を作りました。', '単元別で「メッセージ」をしっかり理解したいと思います。', '盛り上がり: ちょっと周囲の様子を気にして、照れながら「録音」機能を使っていました。
備考: 先週やったことをほぼ全部覚えていてすごいですと、お父さんに伝えました。'),
  ('a1e73b3e-5adb-5fcc-bc41-6ee56490dd64', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-03', '18:40:00', null, '通常 / 検定の問題に慣れる', '検定の主旨は理解しきれていなそうでしたが、素直に問題を解いていました。 「～の後」などの記述の意味で迷っていたので、途中少し問題文の読み方の説明をはさみましたが、簡易なアレンジを含めて時間内で終了していました。 最後の中問2つくらいを残した時点で、コスチュームの編集で遊びだしていたので、声かけをして問題に戻らせました。 試験の後、再度検定について説明し、今回の問題が解けたこともあって一気にやる気になっていました。 素直にブロックを並べていくので、集中力が途切れて脱線しなければ、そこそこいけるかと思われます。', null, 'タイピング: 伸ばし棒を使った単語の練習をしました
盛り上がり: 問題ができたことが、とても嬉しかったようでした。その後、歩数の数値を変えたりコスチュームを編集しまくって、とても楽しそうにしていました。'),
  ('0b18c7db-d593-54a7-b695-836c06f94f59', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-03', '18:40:00', null, '通常 / タイピング検定、１級過去問', '時間がありませんでしたが、制限時間10分程度残した状態でほぼすべての問題を解き終えていたので、概ね問題の意図などは理解している様子です。 クローンの部分がちょっと苦手な感じなので、そのあたりをもう一度確認した方が良いかもしれません。 また定義、モーションセンサーもおさらい必須', '今回の問題のアレンジの部分だけ15分やって、回答合わせにしたいと思います', 'タイピング: タイピングは１級を目指していた様子でした。練習でも１問間違えただけなのに！と話していたぐらいなので相当タイピング自体は自信がある様子でした。'),
  ('1665a0b6-32c5-55f3-b2db-b74be08c24eb', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-03', '18:40:00', null, '通常 / タイピングテスト、３級過去問2回目', '2回目の問題も問題なく、できていました。ただ、アレンジの書き方が人に伝わるように書くことに慣れていないので、最初にアレンジを見た時に分からず・・・というのがありました。 今後はその部分を少し練習した方がいいかな。 本来であれば２級でも十分合格できるとは思いますがアレンジの部分では、もう少し準備した方がいいのでこのまま３級受験で良いかと思います。', null, 'タイピング: タイピングとても正確に打てていました。
盛り上がり: アレンジを自分でうまく描ける、色々なバリエーションができる'),
  ('27f9ece7-38ca-5706-aea0-e780478c4059', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-03', '16:30:00', null, '通常 / 検定の問題に慣れる', '検定の主旨と動画の見方の説明の後、最初の2問だけ一緒に解いて解き進め方を説明してから開始しました。 2つ目のスプライト（馬）の、メッセージ「スタート」を受け取った時の動作以降が終わりませんでした。 基本的には問題通りにできるのですが、指定するコスチュームや座標の正負など、細かいミスが3つあったので、問題にチェックをするだけでなく、数値やコスチューム名などが出た時はアンダーラインを引いたりして見直し時にチェックすることを勧めました。 検定も、やってもいいという反応でしたが、それよりも、前回作成した宇宙バトルのアレンジを家でずっとやっていたらしく、その作品を見せたい！という感じでした。', null, 'タイピング: うでだめしにチャレンジしました。文章が長くなると時間もかかっていましたが、途中で集中力が切れることもなく、一生懸命やっていました。
盛り上がり: 検定も合格点には達しそうでしたが、作品のアレンジがとても楽しい時期のようで、宇宙バトルに付けたセリフや乱数を使った敵の動きの変化などを、とても得意そうに見せてくれました。ビームをもう少しかっこよくしたいというので、宇宙バトル3のクローンを提案したら、とても乗り気になっていました。
備考: 検定もいけそうですが、隔週なのと、今の興味が自分の作品作成に向いているので、コンテストに向けて自作のためのスキル獲得を目的に検定問題を取り入れていっても良いかもしれません。'),
  ('96db2783-c4c4-5019-bff0-8a7ff82cbf8c', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-03', '17:30:00', null, '通常 / 前週があるくんの冒険だったので、ジャンプを向き＋〜歩で動く▶︎座標で動かす', '前週があるくんの冒険だったので、ジャンプを向き＋〜歩で動く▶︎座標で動かす 途中までのコードは前週のコードをみて、おさらい▶︎ジャンプの部分だけを座標に変えるんだよ〜と伝えてコードが多少変わっても同じ動きができることを学びました。 敵を動かす方法もスタート地点、〜秒で座標が動くことを再度学び、向きだけでなく座標でも縦横を動かすことを集中力を持って取り組んでいました。', null, 'タイピング: だんだんと打ててきている様子です。
盛り上がり: 少しずつ、コードの理解が進んできている様子です。以前よりも、文字をきちんと読むことができていると思いました。'),
  ('84e5b553-e8ad-5e0f-b137-9b1936eba4a2', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-02-03', '17:30:00', null, '通常 / 3級2回目 動画と確認しつつ往復', '動画を何回も見直せることについて、かなりしっかり説明しました。 時間を5分余らして終えました。内容を一緒に確認しました。プログラムの順番が違う点が2つありました。2点目は、ひとつのセクションを表しているのが「もし」の全てであるということに気が付けていなかったようです。 アレンジとして色の変化をいれてくれました。紙に書くように伝えましたが、あまり得意ではないようです。アレンジ内容を加味に書く必要があるかもしれません。', null, 'タイピング: 授業最後に少し取り組みました。
盛り上がり: 集中して取り組めていました！'),
  ('797165d1-358f-5762-98c0-7bd3590afc53', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-02-03', '17:30:00', null, '通常 / タイピングテスト、検定４級過去問2回目', '最初から丁寧に問題を解いていました。ただ、〜まで繰り返すのコードを〜回繰り返すのコードに選択間違えていました。そのせいで動かなかった感じで、どうしてそれがうごかないのか？を最後まで見つけることができなかった様子でした。 それ以外は、問題なかったので、コードの選択をする際もちゃんと見る、確認することを学んだようです。', null, 'タイピング: ホームポジションの検定、地道にタイピングして練習では最高８級まで行っていました。どうなるかな？'),
  ('ad9066fe-2cd3-57f2-8ea8-3711c4fc1196', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-03', '16:30:00', null, '通常 / 検定の問題に慣れる', '検定の主旨と動画の見方の説明の後、最初の2問だけ一緒に解いて解き進め方を説明してから開始しました。 2つ目のスプライト（馬）のコードが作成途中でした。本人は、時間が足りないと少し不安そうでしたが、問題への慣れもあると説明しました。 繰り返しと条件分岐の再確認ができたので、試験対策を意識させるよりも、色々な作品を作りながら習ったブロックの復習をしていく体で進めていくのも、たくやくんには効果があると思われます。', null, 'タイピング: ローマ字の大会参加をしました
盛り上がり: 「検定」という単語には、まだピンと来ないようでしたが、いろんな種類の作品を問題を読みながら作るのには興味を示して、楽しそうにしていました。'),
  ('04e48a6c-460a-558e-8484-0f48ddb83683', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-02-03', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('7a6e6a38-38fc-5790-be89-e2f43bf03588', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-02', '17:30:00', null, '通常 / 前回の完成', 'ステージが変わった時にうまく動作しなかったのですが、その原因は鍵の変数の値をリセットすべきところでしていなかったことだと自分で気づくことができました。バグを直し、未完成のところを作り、無事作品が完成しました。終わったところで疲れたようで、残りの時間は教室にある本を読んでいました。', null, '盛り上がり: 隣のまさきくんにツッコミを入れていました'),
  ('3939136b-8b97-5fbc-878b-17417c23a505', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-02', '17:30:00', null, '通常 / 検定の練習＋毎パソ本番', '検定のために2級の練習問題ロケットゲームを解きました。本人の出来具合は、計算の答えの演算のところあたりがわからなかったそうです。そして、それに時間をかけすぎて雲や鳥の動きのところは全く手がつかなったそうです。なので、次回は雲や鳥のところを考えてから答え合わせをした方がいいと思います。', '解き残りから答え合わせ', 'タイピング: 練習のときも初段に行けて、本番も満足げでした。
盛り上がり: 毎パソが上手くいったみたいでとても喜んでいました。'),
  ('1b78c736-6205-54dc-a787-b110b7599236', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-02', '17:30:00', null, '通常 / 一緒にできるなら、【Prg】23 走り幅とびゲームを作ろう', 'いつも通り自由作成になりました。最初のほうはグロテスクなコスチュームを作って遊んでいたのですが、せっかくならコードを書いてほしいなと何回か言うと、新しい作品を作り始めました。10匹くらいのネコが走るアニメーションで、ネコの色、向き、走る速さはそれぞれ変えていました。クローンを使うとこれと同じようなものを簡単に作れるけど興味ある？と促しましたが、やるには至りませんでした。', null, '盛り上がり: せいくんと隣の席ですごく楽しそうでした'),
  ('76735313-e326-53d7-9f02-867a8d2185e7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-02', '17:30:00', null, '通常 / 検定の練習', '検定のために1級の練習問題シューティングゲームを解きました。本人の出来具合は、1通りできたけど、敵の動きに不安があることでした。そして、アレンジも含めて5分余らせていました。完成したものを見た感じよくできていたと思います。次回答え合わせをして、実力を確認してみます。', '1級の答え合わせ', 'タイピング: 上手くいかず気持ち撃沈してました。
盛り上がり: 検定終わった後もあんまり疲れてなかった感じがしました'),
  ('4c51e672-f603-5a5a-bb76-cca972203218', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-02', '16:30:00', null, '通常 / 宇宙バトルの作り込み、クリア画面の作成', '途中でお腹の具合が…とのことでトイレタイムがあったため、いつもより時間が短くなってしまいましたが、「今日はクリア画面を作る」という明確な目標をたてて頑張っていました。 前回学習した、条件分岐の結果によりスクリプトを止めるタイミングなどはよく覚えていて、アレンジするべきコードの場所などもすぐに見つけて書きかえることができていました。 クリア画面の作成と、背景の切り替えを完成させていました。 ローマ字表を見ながら文字を打つことがマイブームのようで、いそいそとローマ字表を出してきて、背景名をわかりやすく変えていました。（良い傾向と思われます！）', null, 'タイピング: 今日も寝起きで来室したため、記録が落ちそうと気にしていたので、気楽にできる道場の方を勧めました。やっているうちに盛り上がって頑張っていました。
盛り上がり: 来室時は眠そうで、テンションも低めでしたが、作りかけの宇宙バトルをやり始めたらどんどん目が覚めてきて、そうちゃんのイメージで何度か背景を描きかえながら、楽しそうに作成して、みずきくんに見せていました。'),
  ('5a16ebee-331a-5f47-86e4-29052475cdd8', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-02-02', '17:30:00', null, '通常 / 基本操作コースを進める', '基本操作コース02の終わっていないところから始めました。先週は気が散りがちだったのですが、これから作る作品のお手本をパソコンで見せたところ興味を持ってくれました。作っている途中、「動き」「イベント」などブロックのジャンルの名前を口にしていて、スクラッチがどんどん身についてきているのがわかります。 基本操作コース02が終わって03に入り、最初はセリフを表示するのをやりました。そこでかずまくんが「自分の声をセリフにするのはできないのかな？」と言っていたので、声を録音する方法を教えました(ここで06の内容を先取り)。', '基本操作コース03,06の続き', 'タイピング: 基本的なキーの練習をしました。ココアタイピングがとても楽しいようで、レッスンが始まる前と終わった後にもやっていました。
盛り上がり: 好奇心旺盛なところはそのままに、テキストの内容もしっかりできるようになってきました。ファイルの中の今日やったところにスタンプを押すと喜んでいました。'),
  ('21e03212-2ea2-5ff4-a483-4713404a68a9', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-02-02', '16:30:00', null, '通常 / 検定1級問題に挑戦', '検定問題自体は、アレンジとその記述まで余裕をもって、5分前くらいに終わらせて見直しをしていました。 授業時間が過ぎていたため、見直しは次回に持ち越しとなりましたが、プログラム自体は問題なく動いているようでした。 本人も問題自体が楽しかったようで、2級の本番の問題より簡単だった！と、珍しく感情を顔に出して満足そうに話していました。', '今日の問題の見直し', 'タイピング: 自転車で飛び込んできたため、手がかじかんでいたようですが、数回練習して本番に取り組んでいました。
盛り上がり: とにかく楽しんで解いていました。「満足した！」という気持ちを珍しく表面に出していました。'),
  ('736e4adf-dda1-5719-9e2b-ab0579e591ce', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-02-02', '17:30:00', null, '通常 / 検定の練習', '検定のために2級の練習問題ロケットゲームを解きました。検定中しゃべってしまうのはいけないが、1か所のミスだけで時間も余裕を持ててできていました。数字を全角で打ってしまったのを半角に直す時間があるほどに。文章の読解力がこのレベルでは対応できていたのでさらに上の級を目指してもいいと思います。', null, null),
  ('815058f8-5890-526b-bf6d-9376dfc843dc', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-31', '17:30:00', null, '通常 / 3級検定応用課題2', '時折休憩をはさみつつも、時間も余裕で終わらせることが出来ました。正解と見比べましたが、見落としにより「このスクリプトをとめる」がうまくプログラムできていませんでした。ミスはこの1点でした。本人いわく「簡単だった」そうです。 後半は作成中のプグラムを見せてもらいました。「スペシャルゲージ」が加わった敵を倒すゲームを作っているそうです。スペシャルゲージの表現の仕方が工夫されていました。', null, 'タイピング: 集中して取り組めていました。あまりタイピングは好きではなさそうです。
盛り上がり: スプラトゥーンにはまっているそうです。'),
  ('1a5b6789-29b3-5e30-9a60-7c1813f80956', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-31', '17:30:00', null, '通常 / 世界を創造しよう（基本操作を学ぶ）', 'ひとつずつ丁寧に進められました。ブロックが1箇所に固まって表示されるのが好きみたいです。x座標、y座標についても名前は知っていたそうです。横に動かすのはX座標であることを説明しました！左右に動かしたあと同じ要領で上下にも自然と動かせていました。 04ではたくさんアレンジを加えて作品を作ってくれました。音楽の追加やコスチュームの変化に加えて、あるくんの自然な拡大・縮小を表現して3D空間を演出できていて素晴らしかったです。作品は最後に披露しました！！！', null, 'タイピング: 集中して取り組めていました。まだあまり慣れないようです。'),
  ('f63219ed-f83a-5ab7-b6c9-a1af2780ad03', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-31', '16:30:00', null, '通常 / 検定4級準備(動画の見方など) ジャンプの復習（座標）', '検定(4級応用課題1)準備をする予定でしたが、本人がどうしてもやりたいというので「アクションゲーム」を作りました。ジャンプを再現したかったようです。最初はとにかく自分で進めてもらいました（なかなかうまくいかないことを実感してもらいたかったため）右へ動く、左へ動かす操作はバッチリでした。 今までの認識ではジャンプとは「上と下へ順に動くもの」といった様子でしたが、今回のゲームで重力が必要になることを説明しました。「難しい」というコメントをくれましたが、作りたいものの目標がはっきりしたと思います。 作っていもらうなかで気づいたことですが、急いてしまう性格と相まって、プログラム全体の想像ができないのかもしれません。細分化への慣れが必要かもしれません。', '検定準備', 'タイピング: dの位置に少し困っているようでした。タイプミスも多かったです。
盛り上がり: 自分で悩めた時間は多かったので良かったです！！スプラトゥーンも遊んでいました！'),
  ('de5fab43-dca4-5178-b24b-03f90a336940', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-30', '18:40:00', null, '通常 / 2級の問題にチャレンジしよう', '検定のために、2級の練習問題のロケットのゲームをチャレンジました、できはアレンジができなくて40分丸々かかりました。ゲームは動きは出来上がっていました。ただ、背面に下げてなかったり、鳥の向きがおかしかったりして地味なミスをしてました。また、「初めて点火したとき」のような間接的な演算の条件文が少し読み違いがありました。このような文章は2級から増えていくので気を付けることを意識させました。それ以外のところが文章通りできていたので、練習を重ねれば時間の問題は解決すると思います。', '2級の練習', 'タイピング: 手の動作がよくなっていました。'),
  ('59eb74af-5307-5405-8099-6e30f3f774e8', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-30', '18:40:00', null, '通常 / 検定の練習', '途中「ステージの動作」をスプライトのコードに書いてしまい詰まっていましたが、それ以外は比較的すらすらと作っていました。きちんとした答え合わせは来週やりますが、ざっと見せてもらったところ、無事に問題を解き切ることはできたようです。', '答え合わせ', 'タイピング: 集中していました。
盛り上がり: 落ち着いた様子で問題を解き進められていました。'),
  ('ade896a4-2503-5d1b-9ee4-60f01ab6268d', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-30', '18:40:00', null, '通常 / タイピング検定のみ', 'タイピング自体は練習してから検定をしました。何回かおこなってミスタイピング自体をなくすことでスコアが上がることに気がついたあとは、レベルが上がっていたので、検定自体はうまく行ったように思います。', null, '盛り上がり: プログラミング検定自体は受けるのか？をお母さんに話しました。本人は受けてもいいのかなと思っているようではいました。'),
  ('05854ef8-fc53-5b38-9ad3-a06ad16053ac', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-30', '17:30:00', null, '通常 / 座標の利用になれよう', '脱出ゲームを作っていきました。遊んだ時にこれなら作れると動画見ずに作り始めました。敵の動きを色判定で動かそうとしたがわからなくて過去の作品をあさっていたがそれでもわからなくて気が付いたら捨てていました。それで座標を時間移動させるコードに変換しました。へーげるの動かし方に時間をかけてしまい、それが出来上がったら疲れた様子でもうゲームに移ってしまいました。次回はしっかりと敵の動きを完成させ、変数を利用したアレンジもできたらいいと思います。', null, 'タイピング: 制限時間が短い敵に苦戦していました
盛り上がり: これならできると自信を生きこんだところは良かった'),
  ('c646f374-314d-5e71-befe-3a2657412329', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-30', '16:30:00', null, '通常 / タイピング、検定２級の問題、', '問題を解くだけで今日は終わり。本人の感想としてはコードの修正削除〜の最後の問題あたりが難しかったと話していました、要はバグをつぶそうとすることが苦手っていうことなんだと思います。', null, 'タイピング: 検定自体は概ねうまくできた様子です。結果が楽しみだと話していました。'),
  ('9f3f5b12-d280-55d0-8cef-b31cdc076f66', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-30', '18:40:00', null, '通常 / 検定問題１級、前回の続き', '前回の時間内で終わらなかったので、引き続き自分で回答を続けてもらって、その後答え合わせにしました。 文章の読み間違い、使うブロックを確認していない、不安な気持ちからか余計なブロックを使ってしまう▶︎読解力の問題かもと見受けられます。', null, 'タイピング: なし
盛り上がり: 算数の問題系は概ねできているので、そういう部分は自信がありそうでした。'),
  ('f3b93307-4fa4-52bb-be8b-4c1b9326561e', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-30', '17:30:00', null, '通常 / 検定の練習', '検定の問題を解くか脱出ゲームを作るか選んでもらい、前者に決めました。途中、問題文がよくわからないところがあったみたいで、しっかり読み返すことを促しました。その後も作り続けましたが、わからないところが解決できずに終わってしまいました。今日はあまり集中力が保てていないように見えたので、来週の答え合わせでは吸収してほしいです。', '答え合わせ', 'タイピング: 数回練習したあと本番に挑戦してもらいました。結果が出るのは少し後ですが、自己ベストを出せたかもしれないと言っていました！
盛り上がり: タイピングのときは楽しそうでしたが、検定の問題を解いているときに少し疲れを見せていました。'),
  ('fd4d033b-28e6-54ac-8a01-1932d98e8a34', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-30', '16:30:00', null, '通常 / 3級の練習をしよう', '検定の練習のために3級の練習問題をやりました。多少簡単な気がしましたが、予想通り簡単にできていました。しゃべりながらやり、迷うことなく10分以上アレンジも含めて時間を余らせていました。次は2級へ飛び級していいと思います。', '2級の検定の練習問題', null),
  ('75ffee9b-e1a9-53ad-8d15-11ebdd9c3652', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2023-01-30', '17:30:00', null, '休み（未対象）', null, null, null),
  ('03e85d43-c0ce-5dce-865d-15179a811974', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, null, '2023-01-30', '16:30:00', null, '休み（未対象）', null, null, null),
  ('7fac0336-cdd2-511c-83d5-94ccdfbf2a26', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-28', null, null, '通常 / 物語を作る', '最初に物語の全体像をイメージしてもらおうとしましたが、難しかったようなので作りながら考えてもらいました。ストーリーは少し時間をかけながら考えていましたが、「この人たちは公園で何して遊ぶの？」などと問いかけるとアイデアが出てきたようでした。「～秒待つ」やメッセージでキャラに会話をさせることができました。また、キャラを移動させたり新しく登場させたりと移動の方法も使いこなしていて、ストーリーに合わせて背景を変えるのもやっていました。', null, '時間帯: その他
タイピング: こつこつ練習できています
盛り上がり: 詰まったときもありましたが、軌道に乗ったあとは楽しくお話を作り続けていました。'),
  ('64c1fa9f-33b5-5bf5-8cbc-b2f01c3d3bda', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-28', null, null, '通常 / 物語を作る', '作る前に、物語を細分化して全体像をつかんでからやってもらいました。メッセージを使ってキャラクター同士を会話させることができました。そのあとのストーリーをどうしようか迷っていたので、背景を変えたりキャラを移動させたりしたら面白いお話ができるんじゃない？と提案すると自分なりに作ることができました。そのときもメッセージをうまく活用していました。キャラを途中で隠すのも自主的にやりました。', null, '時間帯: その他
タイピング: 集中していました'),
  ('22856c3c-844c-54ad-ab79-fdbb90678a78', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-28', null, null, '通常 / 基本操作コース09 ジャンプの途中まで', 'あおしくんとクイズ形式で、答えるようにしながらコードを作成してもらいました。 向きの理解をおさらい、キーで動くのおさらい、座標のおさらいなどをし、ひとまずジャンプし、敵に当たったら、消すというコードで習学しました。 ある程度行いあおしくんの作品を最後鑑賞。 自分でもできるかも〜という感覚にさせてあげてから、ゲームにうつってもらいました。', '場面の変化、条件分岐などどれかできそうなもので', '時間帯: その他
タイピング: タイピングに慣れるためにFとJを繰り返し練習。初めてだったので多少イライラしていた感じでしたが、これから毎回でなくとも少しずつやってあげる方がいいかなと思います。
盛り上がり: ゲーム感覚でやることで復習になり、定着が良くなった感じ？がしました。'),
  ('8dbf71bb-e092-5065-8f08-cc395d87fd39', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-28', null, null, '通常 / 基本操作コース09 ジャンプゲーム', '敵が出てきて、ゴールするところまで。 ①向き＋歩数②向き＋座標＋条件分岐でジャンプの表現 敵の動き 座標を〜秒で行ったり来たりする ゴール・敵 条件分岐を使って 概ね条件分岐とXとYの概念はわかっていた様子でした。やはりそうすけくんに教えながらやった方が自分もやらないといけないし、教えないといけないしという状況になり集中して最後まで行えていました。', '音、変数、ゴールになったら止まる&場面が変わる', '時間帯: その他
タイピング: なかなかタイピングをやろうとしないので、ある程度、〜行まで練習すると決めた方がいいと思います。
盛り上がり: 自分がわかる部分をそうすけくんに教えるということがある方が、自分が優位に立っているという状況になり、ある意味良かった思います。'),
  ('b9097f44-8146-5af3-984c-049a1b29873b', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-27', '18:40:00', null, '通常 / 検定１級の見直し', '一緒に見直して、いくと文章にない部分を不安なのか追加してしまうことが多く、それでバグになっている状態ですが、今の状態でも合格ラインには到達していると思います。', null, 'タイピング: 和文準１級！すごい！
盛り上がり: 変数スイッチの部分がどう作用するのか？がとても理解してくれたようでした。'),
  ('64d48cc7-89ad-54b1-a878-6ad24fb81a4a', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-27', '17:30:00', null, '通常 / アルくんの冒険1 https://app.arspark.jp/contents/2857', '途中までビデオをみて、下に行く時に問題にしてみて、角度の問題なんだよということを理解してもらいました。上と同じ動きだけど角度だけ変えればジャンプに見えるということ', null, 'タイピング: あ、か、さ、た行まで練習
盛り上がり: 自分でアレンジしたい部分があって、それを今まで使ったコードでやってみるというお題を出しながらやってもらいました'),
  ('ad48e2ff-c234-508f-ac22-a8ec2fa621dc', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-27', '16:30:00', null, '通常 / 検定３級の過去問（1回目）', '難しかった様子で、終わる時間までだいぶ粘っていました。 ただ、動き的にはちゃんとできていたので、受験し合格ラインには到達しそうです。', '次回は回答合わせ', 'タイピング: ３級までは到達した様子、自分でこだわりがあるようで、何回もやっていました。'),
  ('f74f9a16-d427-58e9-b037-9aec655e0549', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-27', '16:30:00', null, '通常 / かけ算クイズ（ちょうど2年生でかけ算やったはずなのでー）', 'まずチュートリアル通りに作成（エキスパートのランクなので定義などは出てきますが、乱数などのちょうどいい復習に） 最後まで作成することができましたが、乱数の意味を忘れてしまっていたので、もう一度サイコロをだして乱数の意味をおさらい、しました。', null, 'タイピング: ３級まで到達することができた様子。2年生でそこまでいけるのは素晴らしい
盛り上がり: 掛け算問題自体は簡単と言っていたので、ちょうどよかった感じでした。ちゃんと数字が乱数で出てくるために〜この乱数を使うなど、理解をしたようでした。'),
  ('10bb048e-3500-5f9f-a29d-35812f769477', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-27', '17:30:00', null, '通常 / 4級検定問題', '最初に、オリジナル要素なしに文章だけを読んで取り組んでほしいことを伝えました。25分ほど時間をとりました。自分ひとりで取り組めていたので素晴らしかったです。答え合わせをすると、「何番（③など）のあとにプログラムをするのか」を読み切れていなかったこと、「～に触れるまで繰り返す」を正確にプログラムできていなかったことが分かりました。それ以外の部分はとてもよくできていました。最後まで終わりました！「面倒くさい」とは言っていましたが、何回か練習を積めば合格できそうな気がします。', null, 'タイピング: ミス1でした。集中して取り組むことができていました！！'),
  ('64769b9c-a921-5ced-9617-464d2f01b3d7', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, 'c7feab9d-7535-5e62-bd4f-8381ce161801', '2023-01-27', '17:30:00', null, '通常 / 3級挑戦', '途中で挫折してしまっていました。変数でつまかかっていました。「移動量歩あるく」の表現が、あまりしっくりこなかったようです。時間も十分にありましたが、中盤で詰まってしまったため、最後まで進めることができなかったようでした。序盤に詰まっていた部分は、10分ほど悩み、自分で解決できていました。「移動量を減らす」という表現にも困っていたので、「～にする」と「～ずつ変える」の違いを細かく説明しました。 このままだと3級が少し心配です。問題文も十分には読めていないようでした。問題を増やせば慣れるでしょうか？', '最後まで答え合わせが終わっていません！最終ページが残っています。', 'タイピング: 集中して取り組むことができてました！高得点でした！！
盛り上がり: 以前よりも自分で考えることができるようになってきたと思います。'),
  ('e69da146-0c8a-5c44-be21-b62d012800a6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-27', '17:30:00', null, '通常 / 検定問題４級 18番', '問題が簡単なためか集中力が途中で切れてとうきくんの問題の答えを言おうとしたり、なかなか問題に集中するタイミングが遅かった。 ただ、注意をしてからはきちんと文章を読み、使うコード見本がなくてもきちんとどのコードを使うかの理解はできていたようでした。', '次回は試しに３級の問題２をやってみて、集中を試すのとどれぐらい基礎が身についているのか？をみてみたいと思います。', 'タイピング: うでだめしで、上位３％のうちに入るようになって自分でスコアを気にするようになってきました。次回は普通にマイパソを受けてもいいかなぁと思うのですが、お母さんたちと要相談かなと思います。
盛り上がり: 人に対して教えること自体は好きみたい。これがスキルにつながってもらえるといいんだけどなぁ'),
  ('f85dd7dd-f7d3-5d10-97b7-a77f5212b7a5', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-21', null, null, '通常 / オリジナル作品作成を通して、基本的な操作の習得をはかる', '座標の指定に慣れてきて、配置を一生懸命指定していました。 前回学習した中で気に入った「色の効果」と「まわす」をうまく使って、華やかな作品に仕上げていました。 意図したタイミング通りに会話をさせたいという要望から、メッセージを使いました。', null, '時間帯: その他
タイピング: 丁寧に取り組んでいます
盛り上がり: 自分が思った通りの作品ができることが、とても楽しそうでした。 座標を指定して赤ちゃんのスプライトをすべらせることができて、自分でウケていました。'),
  ('950e5f2b-925a-5f62-8cf8-6efcbb40a9f1', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-21', null, null, '通常 / 世界を創造しよう メッセージの使い方に慣れる', 'デジタル絵本を作るという課題を喜んでいました。 スプライトのコードを実行するきっかけを、自分でキーを押すパターン、旗が押されてから秒をカウントして調整するパターン、メッセージの受け取りをきっかけとするパターンを使い分けることを、興味を持って学習できていました。', null, '時間帯: その他
タイピング: 丁寧に打てています。
盛り上がり: ゆうかちゃんの好きな世界観で、との指示で、背景やスプライトを楽しそうに選んでいました。途中からストーリーがふくらんできて、それに合わせてスプライトを選びなおしたりと工夫していました。'),
  ('2c7e8cb5-3f4e-5bc6-b4c9-ee42dad60dad', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-21', null, null, '通常 / 検定問題に慣れる', '試験自体は特に問題もなさそうに取り組んでいました。 途中で何度も問題をめくりながら画面と見比べていたので、問題用紙にチェックを入れることを勧めました。 残り時間10分になったところで、大問1つをまるまる残したまま悩んでいるようだったので、できるスプライトは先に作っても構わないと助言をしました。 結果、作品自体は完成しましたが、ゴール判定がうまくいかない点が残ってしまったのと、アレンジが未着手でした。他のコードはしっかりできていたので、得点的には問題ないと説明しました。 上記の問題は、座標の演算式を不等号ではなく等号で書いていたところでした。条件分岐の条件部分が一瞬で変化するような場合は等号だとうまく判定できないことがあるため、条件部分を過ぎても判定できるように不等号を使うと良いと説明し、とても納得していました。', null, '時間帯: その他
タイピング: 順調に結果を出せています。和文も英文も、楽しそうに取り組んでいました。
盛り上がり: 試験自体は本人も好きなのか、興味をもって取り組めていたようでした。キーバーの動きを残り5分くらいで作っていたのですが、完成したときはとても満足そうでした。
備考: 授業後に英検2級の受検があるとのことで、授業時間を15分前倒しで対応しました。'),
  ('c7b313d6-8540-5807-9e9b-cf6a4a0ee735', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-26', '17:30:00', null, '通常 / 基本的なコードを習得する', '大きさを変えたり踊らせたりと基本操作コースの内容をやりつつ、自分の興味を持ったことをやっていました。 注意の対象が色々なところに移っていましたが、お手本のプログラムを見せたときは集中してくれました。スプライトを大きくするために「大きさを10ずつ変える」のをやったあと、小さくするときは10を-10に変えればいいということに気付いていたので、少しずつプログラミングを理解してきていると感じます。 スプライトの複製やBGMのつけ方が気になったみたいだったので方法を伝えて、実際にできると嬉しそうにしていました。', '基本操作コース02_06以降', 'タイピング: f,g,h,jキーの練習をしました。大文字と小文字の対応をつけるのが難しいのかまだ割と詰まってしまいますが、少しずつ覚えてきています。レッスン前も自分からやって、プログラミングのレッスン途中もタイピングをやりたいと言い出すくらい好きみたいです。(タイピングのタブ消してからプログラミングを始めたほうがいいかもしれません)
盛り上がり: 今回もあらゆることに興味をもっていて興奮気味でした。脱線しがちではありますが、楽しめているのはいいことだと思います！'),
  ('d3e64cef-fd0e-5484-a3df-f38f9aaf96d8', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-26', '17:30:00', null, '通常 / 変数クローンの使い方になれる', '先週残っていた少し残っていたバグの解説をしました。バグになって起こっている現象からたどっていき質問形式で紙に書いて進めていき、何がいけなかったが探っていきました。原因はメッセージでコードが並列に進行するとき、条件の内容がリセットされないことが原因でした。 次に、眉ネコを作っていきました。自力で作るか聞いた時に若干不安げだったからコードを作る要素は答えられていたので作らせてみました。時間がかかるものではないので、見た目は同じ動きをするところまでは作れました。クローンの使い方がただクローンを作成するコードしか使っていなく「クローンが作成されたら」のコードが使えていなかったのでそこをしっかりと詰めていくのもいいと思います。ゲームからコードを読み解く力は上がってきたと思います。', null, 'タイピング: ミスがもう少し減らせば段に届くレベルになりました
盛り上がり: 音楽に乗ってはまっていました。'),
  ('f81155ad-96b0-522e-8989-05597d46ca9b', 'b2246586-4496-52f9-a825-be2488a00a31', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-26', '17:30:00', null, '通常 / 一緒にできれば、【Prg】28 まゆネコをさがせ', '授業30分前に入室してきたあと、スマホゲームを始めたので、教室内ではScratchのみと話をしたところ、素直にしまっていました。授業後もスマホを取り出した時点で教室ではダメということを諭しました。 授業時間内は、ひたすら自作ゲームを作っていました。時間経過で背景が変わるところに力を入れていて、楽しそうにしていました。 自キャラと敵キャラの動きが単調だったので、時間経過によって緊迫感が出るようにしてほしい、など、ところどころで要望を出す形でアレンジを考えさせました。', null, '盛り上がり: 背景のお絵描きがとにかく楽しそうでした。'),
  ('a261e26a-7631-575d-af0b-843c7022b941', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-26', '17:30:00', null, '通常 / クローンや変数の使い方を慣れよう', '前回に続いて脱出ゲームを作っていきました。あと少しで完成だったので、動画を見ずに取り組んでもらいました。特に困ることなかったです。ただ、1面をクリアするとゲームが終了してしまうバグが発生しました。メッセージや変数や条件が複雑で絡み合っているので、回析するのは後回しにしました。 次に、眉ネコを作ってもらいました。完成したゲームを見て、クローンや変数の使い方がある程度把握でき答えることができたので自力で作りました。色を付けてアレンジも加え、助言を加えることなく作り上げて完成しました。この程度のレベルならもうサクサク作れる能力になっています。', 'バグの解析', 'タイピング: 精度を高める練習をしました
盛り上がり: 自作で作ったボカロのMV風の文字のエフェクトがすごかったです。'),
  ('c3cfa096-1a55-570a-9c0d-b24476300903', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-26', '16:30:00', null, '通常 / 宇宙バトル１～2 繰り返しと順次処理の整理', 'ローマ字表を見ながら変数名などを自力で入れられるようになりました。 宇宙バトルのアレンジとして、敵からビームが飛んでくる動きを作成しました。「～まで繰り返す」対象の動きはどれで、条件を満たした時に実行したいブロックをどこに置くのか、ビームが端までついたらどうしたいのか、など、なるべく動きを細分化してブロックの位置を考えさせました。前回よりは理解してコードを作成できました。 こちらが口頭で細分化した文章を話すと、それをどのブロックにするのかは、わりとスムーズにできています。ただ、自分がやりたい動きの細分化が難しそうなので、定番の動きや条件分岐を覚えて、そこの細分化ができていけることを目指しました。本日の「～に触れたら」の条件分岐はマスターできたようです。', null, 'タイピング: 今日は寝起きで成績が悪くなりそうだからやめておきたいとのことでした
盛り上がり: 前回に比べて、自分でも少しコードが整理できたのか、丁寧に考えて作成できていました。今回はアレンジ部分の作成だったため、チュートリアルは使用しませんでしたが、課題や見直すポイントを指示すると、課題が終わるまで自走できるようになってきています！ ゲームが動くようになってきたので、嬉しそうにお迎えのお母さんとみずきくんに見せていました。'),
  ('cfde3c93-8b33-521c-b11f-26a7a9c54733', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2023-01-26', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('7c513f19-82ea-5583-8f2b-f8db7b1d97bd', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-23', '17:30:00', null, '通常 / 前回の完成', '最初は戦闘機と敵の動きを作ったのですが、思った以上に詰まってしまいました。移動する方法として「～歩動かす」と「〇座標を～ずつ変える」を正しく使い分けることができていない感じだったので、動かす方法っていくつかあったよねと誘導しました。ただ、「端に触れたら跳ね返る」は覚えていて、自分から使うことができました。 そのあと、前回作った時のバグを直しました。複雑に考えすぎていて、重複した内容のコードもあったので、まずはいったんリセットしてシンプルに考えることを促しました。その結果、まずは右に動かし、次に条件が満たされたら止めるというように順序だてて作り直すことができました。', null, 'タイピング: 目標のステージまで終わろうと粘って結構長いことやっていました。
盛り上がり: 試行錯誤して頑張っていました'),
  ('6053651c-122c-5f0c-afb3-96f472d012b6', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-01-24', '17:30:00', null, '通常 / 何かとりくむ！', '最初、お母さんに連れられながら入室を嫌がっている様子。お母様も、今日は来るのを嫌がったということだったので、落ち着くまで入口で座ってお茶を飲んでもらいました。 20分ぐらいたったら、入ってきてPCの前に座り、ゲームを探して始めました。 何かやるか話しかけても、首をふるばかりだったので。しばらくそっとしておきました。 残り30分だったので、お兄ちゃんが作ってた宇宙バトルのチュートリアルを見せたら手を動かし始めました。 画面をのぞいた時に、宇宙バトル①の最後まで作りおわっており。凄い！終わったの～と声かけると、初めてちょっと笑顔が出ました～。良かった(^^)v 1つ仕上げたことが嬉しそうでした。 ここまで嬉しそうな顔は初めてかも。', 'エンジンかかるのが遅いのかも。 チュートリアルを見ながらは、性に合っているのかもしれない。 今後、しばらくアルスパークのチュートリアルで進めてみるのはいいかも。', 'タイピング: なし
備考: お母さんと少し話をしたところ。何か一つ、お稽古事を続けることができるようになるといいな、と思っているとのこと。最後、本人が晴れやかな顔をしていたので、少し本人のペースでゆっくりになるが様子を見ましょうと言うことになりました。'),
  ('08abc41e-4637-5775-9435-a6c9ddc3e76f', '7d01236e-620e-5177-a6f4-af325a582aae', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-01-24', '17:30:00', null, '通常 / 基本操作コースを少し戻り：メッセージを使いこなす', 'ゲーム系の教材を進めていたのですが。最初の方を飛ばしていたので「メッセージ」のコントロールができることを目標に。今週と来週で２回ぐらい定着させたいところ。 ▶ゲームのRGBとかでよくあるような、キャラクターの会話や場面を変化させることができるようになろう、という目的を伝えたところ。一瞬目が輝きました。 ▶最初に「③基本操作コース_06のアレンジ」で見本を見せた。次に、③基本操作コース_06_01,_02_,03とそれぞれの動きを分割したものを画面で見せてつくってみた。今回は見本を見つつ作る方法で実施。 ▶そもそも、「座標」をまだ学校で習っていないので、座標で動かすのがわからなかった。Scratchの座標の考えを説明したが、ここは次回も丁寧にやるといいかも。 ▶「メッセージ」は、はじめ「メッセージ」に書いた文言がそのまま命令になると勘違いしていたようで。「メッセージ名」を「００００」でも同じ動きだよと伝えると。「じゃあ、あああああ、でもいいんだ」と明快な回答があったので。私の方が嬉しかったワ(^^)v', '▶単元別で、「座標」だけやる。座標でスプライトを動かす方法を定着させる ▶単元別で「メッセージ」を復習したい。 ▶次回、これらの操作を使ってストーリーを何か作るから考えて来てね、と伝えてあります。', 'タイピング: 時間になったら１人でアクセスして黙々とこなしていました。タイピングは結構好きみたいですね。画面は大文字、キーボードは小文字でも抵抗なく進めています。
盛り上がり: 新しいコード「メッセージ」と「録音」が楽しそうでした。'),
  ('be05dbb0-40cc-5f5a-ada3-be34424fec89', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-24', '17:30:00', null, '通常 / 復習して自分の名前を動かす 3つか4つの勉強した動きを入れるように！', '「〇度にする」と「〇度まわす」の違いについて詳しく説明しました。集中して取り組めていました。最後に、カラフルな背景で、面白いギミックのある作品に仕上げてくれました！音が最初のみしか鳴っていませんでしたが、本人の納得のいく出来栄えだったようです。（音を流すブロックについても補足しておおきました）最後にご両親に見せました。', null, 'タイピング: タイピングがあまり得意ではないようです。ヘルプのキー表示を出したら、すこし正解率が上がりました。'),
  ('25bb6ad6-98d6-5ee9-a3e8-e25efdd535fe', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-24', '16:30:00', null, '通常 / 久しぶりなので、宇宙バトル1で基礎の確認。 バトル2以降は細かく一緒にやる。 ・味方も動かせるように ・体力の設定', '前回つくった作品を一緒に確認した後、宇宙バトル1を進めました。「上を向く」のところで角度を忘れていたようで少しつまりました。動画をみつつも、自分でよく考えて取り組めていたので素晴らしかったです。一通り終わったあと、味方を上下に動かすようにアレンジしてもらいました。「～キーを押したら」はすぐに出てきましたが、動かし方で詰まってしまいました。向きに対する意識が少し薄いかもしれません。', null, 'タイピング: 楽しく取りくんでいました！
盛り上がり: 楽しそうに取り組んでくれました！'),
  ('464581b2-c3d5-5622-a8c1-2d440c7bb625', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-24', '17:30:00', null, '通常 / 3級検定問題。レベルチェック。', '最初はすんなりできたようでした。途中で敵がでてこなくなり、つまずいたようです。困った部分はプリントの裏面で長文で制御のブロックが入り組む部分であり、読みながら混乱してしまったようです。一緒に確認すると修正することができました。最終的にはうまくプログラムすることができました。時間的な問題は少なそうです。ひとつずつ読んで丁寧に取り組む必要がありそうです。', '‼ 3/1の検定までに、検定3級の問題をあと2, 3回。受験級はできれば2級を目指したい！（本人と確認ずみ）', '盛り上がり: スプラトゥーンを良くプレイしています！'),
  ('9441fe81-00e4-570c-b712-83885d9b0a66', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-24', '16:30:00', null, '通常 / 宇宙バトル3：連射（～ではない）', '宇宙バトル2で得点がたくさん加算されてしまう現象、弾丸が人魚に当たっても消えない現象を改善しました。とくに後者は全て自分で考えられていました。次に宇宙バトル3を進めました。「連射したい」といっていたのでとても嬉しそうでした。キーを押し続けても弾丸がでてこないことを確認してもらい、完成したコードからその理由を考えてもらいました。よくわからなかったようです。クローンの仕組みと合わせてかなりしつこく説明しましたが、理解してくれたかは不安です。', null, 'タイピング: 集中して取り組めていました。'),
  ('0af4bb2c-8bea-5ed1-b0f2-0343eb7aa145', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-24', '17:30:00', null, '通常 / 宇宙バトルで復習。 バトル2以降はリクエストして作ってもらう。 ・味方も動かせるように ・体力の設定', '宇宙バトルを作りました。長期休みに自分でゲームを作っていたようで、チュートリアルを見ずに自分で進められていました。弾の動きに困っていたようですが、シンプルに考えることと、方向を考慮することを伝えるとうまくコントロールできました。メッセージの復習・スクリプトを止めるブロックの復習をすることができました。 宇宙バトルレベル3を作りました。プログラム完成後、連射の部分に注目してくれたので、「長押しでも弾が出続けない理由」を聞いたところ、的確に答えられていたのでとても良かったです。', null, 'タイピング: 集中して2回ほど取り組みました。
盛り上がり: 今までのことをよく覚えてくれていました！'),
  ('953e093a-be6b-52b2-a185-b33e53016efc', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-23', '18:40:00', null, '通常 / ジャンプゲームの応用', '前回につないで、ジャンプゲームの応用を取り掛かりました。背景の草のコードでは、最初から座標を使ってk理科絵師の条件を作れていました。そこで、端に触れるが駄目なり理由もきいたところ、右端にも同じ判定があるから左流れないと答えることができました。ただ、演算式に等号を使っていたので座標の条件では不等号が範囲が広く使いやすことを伝えました。ジャンプの動きについては前回の学習が身についており、手を止まらすことなく作れました。障害物も草野同様に作れいました。ジャンプと木の流れるスピードに事細かい調整をしていて、プログラマー基質だと感じた。ジャンプの使い方の基礎をこれでしっかり身についたと思います', null, 'タイピング: スコア伸びていました。
盛り上がり: 最初に勢いよく上がる癖のあるジャンプがよかった'),
  ('751aa48a-171e-51a4-b9e9-5a487a78ead5', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-23', '18:40:00', null, '通常 / キャッチゲームを復習して応用する', '最初はキャッチゲームの復習をしました。自力で思い出すのは難しそうだったので、テキストを見て作りながら思い出していきました。 そのあとはキャッチゲームを応用して星取りゲームを作りました。コスチュームを変える場面がいくつかありましたが、「次のコスチュームにする」と繰り返しブロックを使ってうまく作れました。スコアが5以上になったら動くようにするところで「スコア>5」としていたので、これだと5が入らなくない？と聞いてみると考えて修正することができました。', null, '盛り上がり: 「一度星を落としてしまったらゲームオーバーにしよう」と提案したときに「初心者に優しいゲームにしたいからそれはしないほうがいい」と返してきて、少し独自性を感じました。'),
  ('a093a210-ced0-54f2-bb39-26f0d7e50be4', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-23', '17:30:00', null, '通常 / ジャンプと背景の動かし方を確かめる', 'ジャンプと背景の動かし方を確かめるために、ジャンプゲームを作りました。まず、草の背景の動かし方で、左へ流れを繰り返す動きを作るとき、条件で端に触れるだといけないことを実際に作らせて、その理由を実感させました。座標は難しいからヤダを否定する根拠になったので、座標の演算の条件にスムーズに取り組め始めました。どこまで行けばいいかが、悩んでいたがしっかりと画面を観察させ、自力で見つけさせました。演算式も不等号を最初から生かせていました。ジャンプの動きでは回繰り返すとあげり幅と下がり幅の考え方が少し立ち止まっていました。障害物の動きも草と同様にすればいいときがついていたので、すぐ作れました。', null, 'タイピング: スコアが伸びずうーんでした'),
  ('a1c630c5-6f15-5807-b3ee-ad7d071a02ac', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-23', '16:30:00', null, '通常 / ジャンプの仕方を理解しよう', 'ジャんっぷの理解を通して座標の使い方を深めるためにジャンピングゲームを作りました。ジャンプという動きが座標の変化の仕方について尋ねたところ、y座標が大きくなって小さくなると理解できていました。コード作成では、最初はヒント伝えず何秒で座標を動かすブロックを使っていて、ジャンプの動きをマネできていました。その後、回繰り返すを用いて、回数と上げ幅でジャンプを調節しやすいことを伝えました。障害物では繰り返し左に流れる動作では端にたどり着いたらの条件分岐が使えていて順調に作れました。体力の変数をつけリンゴで体力を回復したり、音やゲーム結果の画面も作れて今までのアレンジが凝集駆できていました。最後に、ジャンプの仕方を確認しましたが、自分の言葉で答えることができました。', null, 'タイピング: スコアがあまり伸びず浮かない顔でした
盛り上がり: 今年がウサギ年でウサギを選ぶのかわいい'),
  ('fafb0124-add6-5482-922d-a7d000cff8a7', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-23', '18:40:00', null, '通常 / 検定１級の練習問題', '点滅、クローンを作るの部分がわからなかった様子。 制限時間内にすべてが終わらなかったので、今までやってきたことを再度おさらいするといいのかなぁと思います。特に点滅やクローンに関してはあらたくんはあまりやってない単元なのかもしれません', '来週は一緒に回答を作成する', 'タイピング: なし'),
  ('7e0e7268-a45b-5b49-b8a4-5ecc0aba9775', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-23', '16:30:00', null, '通常 / PRG 09ネコとネズミの追いかけっこをスイッチ(https://app.arspark.jp/contents/11504)がヒントだという話をしてから説明 →スイッチを以前やったところを出してから▶️当たる判定と、当たった後の判定を変数でやることの理解を深めるのが目的', 'スイッチをまだ理解していなかったのもあるのか、難しく考えてしまうこともある様子。 ただ、考え方自体に関してはどちらのスプライトに描くと、リレーションでメッセージを送らないといけないなど、自分でやりながら考えられる力がついてきたと思います。', null, 'タイピング: 1回目の点数が49点、2回目が41点 少し集中にかけるとタイピングミスが目立つ様子。
盛り上がり: 最後に、スペースキーを押したらこんにちは、こんばんはを切り替えるのを作成してもらって、それをスプライトに当たったら変更するというコードに書き換えてもらうアレンジをしました。そうするとやはりちゃんとできるので、もう一度スイッチ変数を数多くやってあげるべきだったなと思いました'),
  ('4c15d6fb-d27b-570e-aca2-c2a2f67a17cc', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-23', '16:30:00', null, '通常 / PRG 09をスイッチ(https://app.arspark.jp/contents/11504)がヒントだという話をしてから説明 →スイッチを以前やったところを出してから▶️当たる判定と、当たった後の判定を変数でやることの理解を深めるのが目的', 'まずはじめに、変数の使い方のおさらい＞＞スイッチの使い方で動きが動く動かないを理解した上で、ゲームを作成。見本と同じコードを使ったわけではないが、きちんとスイッチを使って動く動かないを表現できていた。', null, 'タイピング: 時間を決めて集中しながらタイピングをしていました。
盛り上がり: スイッチ変数に慣れてきた様子で、とても素晴らしい！'),
  ('19b8be3b-a807-5190-820a-ae51633a7c89', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '25840600-1a86-5fb0-b223-dec47cec8c48', '2023-01-21', null, null, '通常 / ジャンプの応用③ アル君の冒険', '授業の直前まで寝ていたようで、なかなか授業に集中できなかった。 本人も「疲れている」と言っていた。 前回、宇宙バトル１を制作し終わっていたので、宇宙バトル２を提案したが、やりたくないということだったので本人の希望で「ジャンプの応用③ アル君の冒険」にチャレンジ。 ゲームの要素に「ジャンプ」「左右の動く」「敵が動く」「地面に乗る」「ゴールする」があると答えていて、細分化はできていた。 そのあと「ジャンプ」から作りたいということでチャレンジしたが、課題を決めるのに時間がかかったこともあり、時間切れで途中で終わっってしまった。', '次回は基礎問題など難易度を下げた問題を出して、基礎の習得、考える癖、モチベーションアップを促したい。', '時間帯: その他
盛り上がり: 考えることが面倒くさくなってしまっている様子。'),
  ('abea852f-6e3f-55e5-9f2b-2278ba56a4e7', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-14', null, null, '通常 / 基本的なコードの確認 宇宙バトル1', '前回まで、新しいカリキュラムに沿ってチーズを探せまでできていたので、少し迷路からはなれてコード探求の「だるまさんがころんだ」を見せ、本人も面白がったため、これを教材にしようとしましたが…何から手をつけたらよいのか、まったくわからないとのこと。冬休み前のことを忘れているのと、少し気持ちが緩んでいることもあり、基礎に戻るのと、自走の練習を目的に、宇宙バトル1に取り組むことにしました。 脱線のおしゃべりが多く、大人が目を離すとこっそりScratchで遊んでいたりもしましたが、なんとか宇宙バトル1を完成させていました。理解力がないわけでもないのですが、慣れてきたせいか、少し甘えも見られました。', '複数の課題を自走させてまとめて答え合わせやチェック、というのが難しそうな状況なので、次回はステップごとに確認をして達成感を持たせ、モチベーションのアップをはかりたいと思います。', '時間帯: その他
盛り上がり: プログラミングが嫌になったというほどでもなさそうですが、全体を見て細分化して、一つ一つ作成していくというのが難しく、面倒になってしまったようでした。宇宙バトル1のように細かく指示をされて、その通りに作ることはできるので、そこにはやりがいも感じられたようでした。'),
  ('9b79e6d6-ef09-5358-be70-301aa3114fc1', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-20', '16:30:00', null, '通常 / 基本的なコードの確認 宇宙バトル1～', 'チュートリアルを見なくても、なんとなく先が想像できるようで、たまに先に作成していたりもしましたが、その後自分でチュートリアルを見直して確認ができていました。 座標の使い方やスプライトの向き、変数やメッセージも自力で使えていました。 お迎え待ちの間にオリジナルスプライトを作成して楽しそうにしていました。', 'クローンも喜びそうなので、このまま宇宙バトル3をやらせてあげようと思います。', 'タイピング: まだ導入部分のせいもあるのか、比較的余裕にクリアしていました。
盛り上がり: 自力で作成できるのが楽しかったようで、終始笑顔で取り組んでいました。'),
  ('b9b3fec7-bc07-5e70-a05c-45808d9011e0', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-20', '18:40:00', null, '通常 / 基本操作コース09ジャンピングゲーム', 'ジャンプの動作を座標を使って丁寧にできていました。面白い動きをプログラムできていました。触れたら卵を止めるプログラムを作っているとき、プログラムの実行順の影響で不具合が生まれましたが、「スクリプトを分けて調節する」ということを覚えてくれていたので、自力で解消することができました。 スコアを設定した後も卵の動きにこだわって、ハードゲームを製作していました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 遅刻してきましたが、授業は集中して取り組めていました！'),
  ('2607f17d-314e-5bc8-b5ea-cca2c1e1fb55', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-20', '17:30:00', null, '通常 / 宇宙バトル2, 3（条件分岐・クローン）', '前回作ったものに、戦闘機の上下の動きを加えてもらいました。「ずっと」「もし」を使ってうまくできていました。HPの表示はいやそうだったので、バトル3に進みました。一度遊んでもらった後「クローンを使う」という発想がでてきたので良かったです。完成させた後、爆弾などの他のスプライトを追加してアレンジしていました。とても面白い作品になり、満足そうでした。', null, 'タイピング: 集中して取り組めました。
盛り上がり: 楽しく取り組めていました！'),
  ('5d2dcd1a-c3aa-5058-80b5-799652f7441f', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-20', '16:30:00', null, '通常 / 基本的なコードの確認 宇宙バトル続き、単元別ドリルA', '前回作成した宇宙バトルで、弾丸が単発でしか出ないため、敵に当たるのが大変という感想を言ってくれたので、目的がはっきりした状態でクローンを使用する宇宙バトル3へ進むことができました。 チュートリアル通りに弾丸のクローンを作成したあと、自機自身がクローンを作成しながら自分でアタックするようにアレンジして、大ウケしていました。 宇宙バトル3が完成したあと、そのまま単元別ドリルに入ったため、1問やって「もう疲れた」とだれてしまいましたが、5分間の約束で野球ゲームをしたら、その後はドリルに戻って2問クリアすることができました。', null, '盛り上がり: コードのどこをいじったらどこが変わるか、というのがずいぶんとわかってきたようで、自分なりのアレンジをとても楽しんでいました。'),
  ('316be211-5dd7-51ad-9128-304cc32350a3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-20', '17:30:00', null, '通常 / 宇宙バトル2（条件分岐）', '前回作った作品に①戦闘機の上下の動き、②スコアを設定しました。①はまだ座標への意識が低いようです。座標の種類と数字の正負で混乱していました。②は「どこにプログラムするのか」を考えることができていました。「0にする」「1ずつ足す」を正しく配置することができました。クリア条件をプログラムするときに、＜と＞の向きで混乱していたので、その数字が含まれないことも含めて少し詳しく説明しました。', null, 'タイピング: とても集中して繰り返し挑戦できていました。自分から進めたいと言ってくれました。本番は1回だけで、1回きりに実力を出す必要があることを伝えました。
盛り上がり: 授業後にScratchで楽しく遊んでいました！'),
  ('702fc354-335b-53cd-b1d9-635bc21f3d93', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-20', '18:40:00', null, '通常 / 検定1級（変数と条件分岐の組み合わせ）', '一通り最後までみた後に、うまくいかないところをプログラムしたそうです。 敵の動きがうまくいかないとのことでした。時間通りに終えると授業時間を超えてしまいそうだったので、5分前に一度ストップして一緒に復習しました。 数字の正負の見間違えたり、プログラムを分けてしまったりしていたのを確認しました。正解と思われるプログラムも、アレンジがたくさん加わって条件分岐が見にくくなっていたこと、残り時間が少なかったころから、また来週再度確認することにしました。 プログラムの大枠はできていそうでした！', '確認からやりたいです。', 'タイピング: 丁寧に取り組めていました！！
盛り上がり: 長時間でしたがよく集中して取り組めていました。'),
  ('5d8f2349-d266-562a-b31d-22f068a6d47a', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-20', '18:40:00', null, '通常 / 宇宙バトル1～ 基本的なコードの確認', '動画を見るとあるていど先が予測できるようで、各ページの最初の解説を聞いたら自分で先行して作成できていました。 座標による動きも自分ででき、変数の作り方も覚えていました。 動画の冒頭である程度予測がつく一方で、動画の先で直す部分がわからずに悩む場面もありました。（敵スプライトの向きを0度にすると、回転方向を固定しないと敵が横向きになってしまうところ）', '宇宙バトル2の、クリア背景を作るところから', 'タイピング: 早打ちにチャレンジしていました。
盛り上がり: このレベルの教材だと、ほぼ自力でコードの作成ができるようで、楽しそうに先に進めていました。 スプライトや背景をオリジナルに変えるところが特に楽しそうでしたが、きちんと授業に戻ってこられるところが素晴らしかった！'),
  ('16b2c4fd-f9cc-5f11-be8d-40b5270cfeae', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-20', '17:30:00', null, '通常 / とらくんと同じようにPRG09 をすべて写経させる', 'ハルくんの場合は写経となった場合に、意味を理解しながら写すのではなく、単純に写しているだけになってしまいました。 途中でストップして、０と１で動きが止まるのは何故か？スイッチの変数と同じで以前やった作品で同じ部分があったのでは？と一度止めて、理解をしてもらいました。', '来週から変数だけのコードを使うような教材を多くやることがいいと思います', 'タイピング: 腕試しもいたに付いてきましたが、以前よりもかなりいい加減にタイピングしている感じが増えてきています、ただミスタイプは少なくなっているので、その時の調子でかわるのかなぁと思います。
盛り上がり: 最後に自分でアレンジをしてもらい、条件分岐を使ってさらに難しくするというコードを書いてもらいました。なので条件分岐自体はとても良く出来ていると思います。'),
  ('6f4a42fb-8c85-54e7-94e1-03ea4e42a03f', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, null, '2023-01-20', '17:30:00', null, '休み（振替対象）', null, null, '備考: 2/16に振替予定'),
  ('6d7b9ba8-2f6b-5d3b-bc9f-57310a1f6158', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, null, '2023-01-20', '16:30:00', null, '休み（未対象）', null, null, null),
  ('cea15d04-36a4-5c25-a359-8087276e3a2e', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, null, '2023-01-20', '16:30:00', null, '通常 / 基本操作コース09 ジャンプ', 'ジャンプ▶︎Yが縦だから、座標を使ってジャンプのように見せることを説明できる 障害物▶︎横の動きもX座標ということを理解している すべてを作成するまでに、時間もかからない', '来週はジャンプの演習をやってもらう', 'タイピング: 割と慎重にタイピングする子なので、タイピングの文字数自体は多くはないもののミスはすくなめ。
盛り上がり: コードの理解と、座標の理解などすべてが、今までやっていることが身についている、少しだけヒントを言えば自分でアレンジができる'),
  ('427caef4-3ad5-58cd-920a-5cfeadc52938', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-20', '16:30:00', null, '通常 / PRG09を最初にゲームをして、写経しながら説明アンド自分でアレンジまで', '最初にどのようなコードを書いているのか？を考えながらやってねと伝えていたので、猫の動きのコードを作成終わったときに説明をしてもらいました。 止まる動きが変数を使っていること、その変数で他のスプライトも一緒に連動しているのかをみてもらいました。バグになりやすい部分を見本で見ることで、自分がいつもやってしまうような動かなくなってしまう部分を確認と理解。 概ね説明も問題なく出来ていたので、コード自体の理解はしている様子です。ただ、連動の部分になると他のスプライトが動かなくなるまでアレンジしてしまうので、今後は、複製しない→コードが別々になることを確認していく作業が必要なのかなと思いました。', null, 'タイピング: ローマ字自体のタイピングは問題なし、ミスは少し目立つものの、合否に関わるところではないので、今後の練習次第
盛り上がり: アレンジ自体はとても楽しそうにしていました。そこでも動きがバグることはなくできるようになっていたので、一定に基礎が出来ているゲームをアレンジすることは得意なのかなと思いました。'),
  ('5083d41e-00a0-52eb-9beb-475a84d858bc', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-16', '18:40:00', null, '通常 / これまでの復習、クローン', '動画を見ずに弾のクローンを作ることに挑戦していたのですが、クローンの作成はやっているもののクローンされたときの処理が書かれていませんでした。そこで動画に沿って作ってもらい、クローンを使うときは「作る」のとそれを「動かす」のを別々に書かなければいけないことを共有しました。 キーを長押ししても弾が連射されないようにするとき、前に作ったゲームで同じようなことをやったけど覚えてる？と聞きました。そうすると自分の過去の作品一覧を見て、100m走を作る時にやったことを思い出していました。', null, '盛り上がり: だいきくん個人的には、シューティングゲームでは弾が大量に出たりして無双できるほうが楽しいらしいです'),
  ('7920db41-7937-53fc-b949-ad3844f32ab4', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-19', '17:30:00', null, '通常 / ゲームから読み解いて作ろう', 'アイテム脱出ゲームを作っていきました。最初、遊んでもらった時、ボールが滑っていく動作に対して、常に減速するようなコードを作ればいいと気付けていました。動きの細分化がよくできています。動画を見ずに作りました。独自で作っていたので、条件分岐で矛盾があったりしたが、時間がかかり作ることができました。作り終えて、疲れた感じしていたので、次回に正解のコードを見せて見比べることもした方がいいと思います。', null, 'タイピング: 手こずっていました。'),
  ('6078e9d7-b796-50ec-b613-c97143ef18b5', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-19', '17:30:00', null, '通常 / コードの復習と作り変え', '前回に引き続き、動画を見ながらアイテム脱出ゲームを作っていきました。早々に作り終えることができたので、3面を作るようにアレンジを提案しました。3面を加えるにあって、どのコード変更すればいいかほとんど気付けていました。だが、ステージ変換のコードのところで詰まってしまいました。ただ写しているか不安だったので、コードの意味を聞いたがしっかり理解していました。だから、バグを一緒に探しましたが、発見には至らなかった。 演算や変数、メッセージの使い方が復習になったので新しいことに進んでいいと思います。', null, 'タイピング: だんだんと詰まることがなくなってきました'),
  ('75cbd2b3-6251-5fde-8f0a-10bab5396e5e', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-13', '16:30:00', null, '通常 / 宇宙バトル1、2', 'レッスンのチュートリアルを見ながらしっかりとできていました。 特に迷ったり混乱したりすることもなく、よくできていて、声をかけると嬉しそうに「こんなふうにした」などと見せてくれました。', null, '盛り上がり: このレベルであれば、スラスラとストレスもなくできるようでした。'),
  ('275efd2d-8ad3-5d90-8681-2de424577581', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-01-19', '17:30:00', null, '休み（未対象）', null, null, null),
  ('d28305bd-bdea-5f22-9567-23eec0f29db7', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-19', '17:30:00', null, '通常 / 教室に慣れる、パソコンやScratchの操作に慣れる', 'とにかくすべてのブロックが気になって仕方ないようで、全部使ってみたい！！！という感じでした。テキストの操作を一つすると、すぐに「じゃあ、これは？！」といろいろいじってみたくなるようでした。 体験会でやったネコの動きをよく覚えていて、同じような動きを作りたがったので、基本操作コースのテキストの内容に体験会の内容を足しながら、本人の希望に沿いつつも、最低限の基本操作を覚えたらゲームが作れる、ということを目標に取り組みました。 繰り返しを含めたブロックの位置を少し動かすだけで、実際の動きが変わることを実感としてわかってもらえました。 基本操作コース02の内容の他、背景の変更をしました。', '基本操作コース02 04～', 'タイピング: 初めてのタイピングでしたが、アルファベットは大体読めるとのことでやってみました。ホームポジションに人差し指を置くこと、Enterキーの押し方、FGHJのキーの位置を覚えました。とても楽しかったようで、授業後に自主的に再チャレンジしていました。
盛り上がり: とにかくすべてに興味津々！という感じでした。1時間休憩もとらず、ひたすら感心しながらパソコンと向き合っていました。 楽しすぎて興味があちらこちらにいってしまう傾向はありますが、少し落ち着くと軌道修正にものってくるので、焦りすぎずに進めていきたいと思います。'),
  ('b6195706-a303-546e-b2c8-52b6b9b1210d', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-19', '16:30:00', null, '通常 / 宇宙バトル1より 条件分岐、繰り返しの位置など', 'ライフル弾がドラゴンに当たった時の判定やと、アレンジでドラゴンが出すビームを作成しました。 作成中にどんどんやりたいことが湧いてくるのですが、そのアイディアから、自分が直近で習ったことで応用できそうなアレンジはどれかを考えて選んでもらいました。 ライフル弾で作成したコードを読み解きながら、ドラゴンのビームを作成していきました。ライフル弾と違ってビームはランダムに出したいということで、乱数を使うところまではできたのですが、どのブロックを繰り返しの中に入れるかなどで混乱しているようでした。', 'ビームの動きの完成', 'タイピング: 相変わらずタイピング検定にはまっています。
盛り上がり: アイディアを話しているときがとても楽しそうです。やりたいことを怒涛のように文章で話す傾向があるので、少しずつ細分化してアイディアを出していけるようにしていきたいところです。'),
  ('114a0311-9e5b-50b6-a3ba-e709e375e90e', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-19', '17:30:00', null, '通常 / 自由作成', 'クローンを使ったアニメーションを動画を見ながら作ってもらおうとしたのですが気が向かなかったようで、自由作成をしました。作ったものはむらっちを大量に複製して動かすというものだったので、クローンを使ってやってみない？と言ってみましたが、結局スプライト自体の複製でやっていました。', null, null),
  ('61c34b20-e4ef-5798-8b5c-e4e9f92f1ea5', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-19', '16:30:00', null, '通常 / 変数のいろいろな使い方など', '走り幅跳びは20分ほどで作成していました。スピードの変数が難しくて、元ゲームを参考にしたそうです。 観客の動きのタイミングを少しずらしたりしてアレンジしていました。 連打系のゲームは好きなのか、前回に続いての連打系でもやってみたい、とのことで、自分で走り幅跳びを選んでいました。 トランポリンは、動画を見ながら作成していました。', 'トランポリンの続き', 'タイピング: 2級相当の結果が出せています
盛り上がり: 最近少しずつ口数が増えていて、以前よりも楽しそうに作成しているように見えます。 使えるコードが増えてきたのと、ゲームを見たら自分である程度形にできるようになったのが、自信につながっているようです。'),
  ('65c1030a-13d4-5b44-9aa8-7950472c6f35', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-19', '17:30:00', null, '通常 / 脱出ゲームを進める', '前回は動画を見ながらだったので今回も動画を見せようとしたのですが、今日は自分の力で作りたいと言ってくれました。条件分岐を使い、変数(かぎの数)の値によってステージを変えることができました。ただ、ステージが変わった時に鍵が隠れたままだったりと抜けているところがあったので、そのときの処理をメッセージを使って作ろうと助言しました。せい君は必要以上にたくさんのスクリプトを作る癖があるみたいなので、読みやすいコードを書けるようになると上達につながると思います。', null, '盛り上がり: 先週よりやる気があったと思います'),
  ('adae23e1-0180-5835-9b4c-721b2d30a097', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-12', '16:30:00', null, '通常 / ひとりで説明を聞きながら作成にチャレンジしてみる', 'そろそろ一人で説明を聞いてチャレンジできるかな？と声掛けをしたところ、「お兄さん扱いされた！」という感じで、「僕は長男だしね～」と得意げに取りかかってくれました。 最初に宇宙バトル3のゲームをしたところ、「難しそう」と言っていましたが、1からの説明は丁寧すぎたのか、「このくらいわかる」と得意そうに進めていました。 敵のスプライトをドラゴンにしたため、レッスン通りのコードだとドラゴンの向きが思うようにいかずにかなり苦戦していました。ここはどうしても妥協したくなかったらしいのと、y座標を〇ずつ変える、-〇ずつ変えるの2種類を使うというところまでは自分でできたので、変数をつかって一緒に解決していきました。', '敵が弾丸に当たった時の動きから先を作成します。', 'タイピング: ココアタイピング内の検定ランキングにはまっています。お母さんからはタイピング検定の相談がありましたが、検定ランキングの結果にかなり一喜一憂していて、下手にチャレンジさせるとせっかくのモチベーションが下がってしまうかもしれないので、もう少し自信をつけてからの方が良い結果につながると思われることを説明したら、納得していただけました。
盛り上がり: いつもより自走時間が長かったため、「自分で作った」という達成感があったようでした。 ドラゴンの向きのところではなかなか思うようにできずに少しだれましたが、あきらめないで自分なりにコードを考えて、y座標を変えるコードを2つ持ち出してきたところまで、よく頑張っていたと思います。'),
  ('a8519b41-7caf-5f56-b7af-c0fd200b65a8', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-12', '16:30:00', null, '通常 / 単元別ドリルF続き～条件分岐の確認、走り幅跳び', 'ドリルは自分のペースで楽しんでやっているようです。課題通りに作成したら、ひっそりとアレンジをして、こちらが驚くのを見て嬉しそうにしていました。 F6は、レベルを3択で選べるようにして、少し満足気でした。最近そうちゃんとの会話に入ってくることがあるので、そうちゃんを呼んでF6ゲームにチャレンジさせたところ、丁寧に説明してあげていました。', null, 'タイピング: 淡々とやっています。
盛り上がり: 大会を経て、だいぶ自分の思ったコードが作れるようになったせいか、ドリルもアレンジも楽しそうに、良いペースでできています。'),
  ('c607893a-7a33-5f97-8c32-3bddea9f26a2', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-01-17', '17:30:00', null, '通常 / 教室に慣れる、Scratchの操作に慣れる（基本操作コースⅠ 02_名前を動かそう）', 'まだ慣れていないのか、口数は少ないですが、レッスン後半には少しずつコメントを話してくれるようになりました。 ブロック内の数字を入れ替えることにとても興味を持って、角度や繰り返し、効果の数字を頻繁に変えては動き方の違いを楽しんでいました。', null, 'タイピング: ローマ字はまだ自信がないそうですが、キーを打つのは少しやったことがあるそうで、最初のステージはA以上でクリアできていました。
盛り上がり: 極端な数値を入れたときに少し得意げにこちらに見せてきたりと、レッスンには慣れてきてくれたかな、という感じでした。 選んだファイルやペンの色から、黄色やオレンジ系が好きなのかな？ 授業が8分前くらいに終わったので、マイクラをやっていました。'),
  ('f2484c67-0aca-54e9-92b7-0872e5e1b94a', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-17', '16:30:00', null, '通常 / 宇宙バトルを使って復習 レベル2まで進めたいな！！ 去年作ったプログラムもみてもらう！', '一度プレイしてからプログラムの構造を考えて言ってもらいました。「～歩あるく」や「触れたら消える」「スペースキーがおされたら発射」など、ブロックにある言葉を使って説明できていました。「久しぶりに来たので忘れていることが結構ある」とのことでした。背景・スプライトもよく考えて選べていました！！プログラムする場所に困ることが多かったです。 動画のスピードが速すぎるそうなので、チュートリアルを見て進めるのはようくんにとってあまりプラスではないかもしれません。歩かすときに角度を調節するのも覚えていて良かったです！！', null, 'タイピング: 集中して取り組めていました！！！100点がとれていて楽しみです。キーの位置をそろそろ覚えてきているので、PlayGramに移動しても良いかもしれません。一話分終わらせました！'),
  ('e4396ee9-2b49-51f6-a405-bb08dae1be17', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-17', '17:30:00', null, '通常 / 宇宙バトルを使って復習 去年作ったプログラムを確認', '忘れてしまっていたようなので、チュートリアルを見て取り組みながら思い出してもらいました。プログラムするスプライトを間違えたとき、自分で間違いに気づけていたので良かったです。一通り作ったあと、戦闘機の上下とスコアをプログラムして追加してもらいました。 上下のプログラムは、方向の意識が薄く、思うように動かず困っていました。 スコアのプログラムは、「変数」を使うということを覚えてくれていましたが、具体的な内容は忘れてしまっていたようです。 一通り復習することができたと思います。', null, 'タイピング: 授業開始前から熱心に取り組んでいました！！'),
  ('b6473b8c-8e2c-5d9e-b3d6-5d09ac5cf870', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-17', '17:30:00', null, '通常 / 前回の復習（スプライトを左右に動かす、コスチュームを変えるなどをやった）ので、「スプライトを歩かそう」で思い出してもらったり、ついでに場面追加・音の追加をしたりする。', 'かなりお疲れの様子だったので、パソコンを触るだけでした。計画してたことは来週やってみたいと思います。会話はあまり進みませんでしたが、言葉以外で少しコミュニケーションが取れたので良かったです。', null, 'タイピング: 最後に少し取り組んでくれました。fとjはしっかり打てていました。'),
  ('166949ce-34e0-56ba-8f5e-a0b91633d4c3', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-17', '17:30:00', null, '通常 / 宇宙バトルを使って復習（レベル2から） クローンの下準備 単元別演習F-5から', 'スムーズに取り組めていました。宇宙バトル2を作っているときに「連射したい」という希望があり、宇宙バトル3では連射ができるようにアレンジしていました。さらに他のアレンジとしてゲームクリアの画面やスコアの調整をしてくれました。スコアの調整は、=を使って表していたためうまくいっていませんでしたが、こちらがコメントすると気づけたようです。 単元別演習は、紙面に書いてあること以上を表現しようとしてくれていました。焦っていたのか読み込み不足なところはありましたが、指摘するときちんと修正できていました。', null, 'タイピング: スコア記入は忘れてしまったようですが、かなり素早くタイピングできていたようです。
盛り上がり: Scratchのスプラトゥーンにはまっているようです。'),
  ('12c1e4ec-f649-53ad-88cf-7b351ddea6d8', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-16', '17:30:00', null, '通常 / 今までの内容の復習をしながらシューティングゲーム作成', '動画を見ながら作ることを提案しましたが、以前同じものを作ったこともあって、全て自力で作ることを選びました。キーが押されたときに出るビームの動きを主に作りました。「端に触れるまでビームを右に動かす」コードを作ろうとしているときに、「～まで繰り返す」を忘れていたため、使えそうなブロックが「制御」の中にあるけどどこかな？と聞くと、無事思い出すことができました。 だいたいのコードは書けたものの、ビームが発射されないバグが出てしまったため、どこかでスクリプトを止めてみるといいとヒントを出しました。来週はバグ直しの続きからになりそうです。', '宇宙バトル 続き', 'タイピング: 期間が空いたためか調子が悪かったみたいで、そのことを残念そうにしていました。来週はまた慣れていつも通りにできるよと声をかけました。
盛り上がり: タイピングからプログラミングに移るのを少しためらっている時間がありましたが、プログラミングを始めた後は比較的集中してできていました。'),
  ('38400721-0d57-5e24-aaa0-9e9dbbc77ab8', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-16', '17:30:00', null, '通常 / 動画を見ながらコードの復習をしよう', '期間が空いたので、動画を見ながらコードを復習し、宇宙バトルをつくりました。動画見ながら作るよって伝えた時、「動画嫌だ自分で作る」といって作り始めてしまったが、しゅうくんが作るコードは偏りがあるので、同じ動きでも違うコードの表し方があることを都度都度刷り込ませながら、動画通りに作っていきました。ただ作っているだけにならないために、たびたび同様コードを作っているが説明させながら作りました。その説明は、最初の答えはまだ浅いが、深いる質問をすることで具体的に説明でできていました。順調に進んでいき、クローンの連射の動画を見終えて、完成することができました。', null, 'タイピング: はじめての練習だったがそれなりにいい記録は出せた'),
  ('a8626041-3bca-517e-b946-74f1096ce990', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-16', '16:30:00', null, '通常 / 動画を見ながら復習し、クローンに取り組もう', '期間が空いたので、動画を見ながら宇宙バトルを作っていきました。そして、肩を鳴らした後にクローンを使ったところをゲームを見て作ってもらいました。動画を見ていたところは簡単だったので、なんの困ることなく進んだが、わざわざ動画をゆっくり見て時間稼ぎをしていることが目に留まりました。クローンを用いたゲームでは特にクローンの使い方に迷うことなく、クローンのブロックの付け替えはうまくいきました。ただ、球の連射は長押しでできるようになっていたので、そこを直してもらおうとしたとき、「どうすればいいの？」ときいてくるのはいいが、そこは一度やったことがあるので、過去の探すように指示しました。オウスケ君はいい疑問を持ってくれることは素晴らしいが、聞けば答えが返ってくるのようなスタンスが若干垣間見えるので、探す自主性高めてもらいたい。', null, 'タイピング: 久々にやってシルバー級からゴールド級に上がっていました。'),
  ('f489f441-c59f-52ee-bbb5-bf3f21d09101', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-16', '18:40:00', null, '通常 / 宇宙バトル２〜３ クローンの使い方と〜ではないまで待つの使い方を思い出す', '２は動画をみながら、３に関してはクローンの部分が意味がわかっていない（親と子分の動きが別で書いてあげないといけないということ）個々別々の働きをさせてあげないといけないという説明をしました。 〜ではないまで待つに関しては以前のレースゲームを読んでもらい、答えを導き出してもらいました。', '次回からは検定１級の準備を始めたいと思います', 'タイピング: 誤タイピングが目立つ様子。マイパソ自体は受験したくないとのこと、お母さんにも相談済み
盛り上がり: 自分でできる範囲がだんだん増えてきていることは理解している感じ。'),
  ('77338b3c-b56c-5a28-aa84-ee76d9c99efd', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-16', '16:30:00', null, '通常 / 宇宙バトル１〜２', '１と２どちらも、動画を見てもらいながらやっていたことを思い出してもらいました。 １に関しては、条件分岐で動きがとまることを思い出していたようでしたが、２に関しては上下に動く飛行機の動きを、キーのイベントと旗で動くことを混同してた感じではありました。 もう少し条件分岐の部分を深くやるのがいいのかも。', null, 'タイピング: だんだんと特訓コースでローマ字打ちがすんなりできるようになってきました。以前よりもローマ字表を見なくても大丈夫そうなので、今年中にはタイピングテストをやってみるのもいいかもしれません。
盛り上がり: 自分でコードを予想しながら作成することができ、説明もきちんとできていました！'),
  ('92b97acc-b98d-515a-9e43-615f84b97383', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2023-01-16', '18:40:00', null, '休み（未対象）', null, null, null),
  ('aeff7ff5-f5be-5f77-8456-94aaa0215cdb', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-16', '16:30:00', null, '通常 / 宇宙バトル２を先に映像を見て作成▶︎３は自分でできるところまで作成しその後答え合わせ クローンをうまく使えるかand〜ではないまで待つを使い切れるか？', '２に関しては思い出しながら、はるちゃんにとっては簡単だった様子▶︎３を自力で作成してもらいました。 クローン：あまり使ったことがないので、親と子の動きを作成しなければならないことが忘れてしまっていた様子 〜ではないまで待つ：レースゲームのときにやっていたことは忘れていた、もう一度見返してもらって、宇宙ゲームに挿入その後答え合わせ 旗が押されたら〜条件分岐で弾が出るという部分をどうしても、スペースキーが押されたらで書いてしまう▶︎悪くはないが、動作敵にバグのもとになるのでその部分を再度認識してもらいました。', null, 'タイピング: 何回か練習し、慣れてきたらタイピングの速さも早くなっていました。
盛り上がり: かなり自分でできる範囲が増えていることに気がついてもらえたこと、またちゃんとクローンの動きで、バグが出たときに「動かない場所の問題点」を説明できたこと'),
  ('36cc4412-1b4d-576f-827b-c389a71248aa', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2023-01-16', '17:30:00', null, '休み（未対象）', null, null, null),
  ('6353d790-ef62-5c34-b2b0-68ec049fdaf5', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-14', null, null, '通常 / 自分の名前を動かす！！（続き）', '自分からとっても積極的に取り組めていました。回転はできていましたが、移動させるのに苦戦していたので、「初期位置を決めてから時間をかけて移動させる」という話を伝えました。音楽がなかったのでつけることを提案しました。丁寧に選んで、工夫して音楽を流すことができました。本人いわく、完成だそうです。 授業はじめとは全く違った完成となりました。自分で考えながらブロックを動かすことが出来ていました。すばらしい！', null, '時間帯: その他
タイピング: 何度か取り組んでくれました。プレイグラムは見たことがあったようです。最後はミス率が0になっていました！
盛り上がり: おすすめしたScratchゲーム（かたつむりが動くもの）が気に入ったようです！！'),
  ('9019527e-f2ea-5629-af1b-aefc91f4a35b', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-14', null, null, '通常 / 初回！！教室になれる。', 'あまりScratchには触れたことがなかったようです。大きさ、色の変化はスムーズに変えられていました。「～回繰り返す」などのブロックも説明しました。座標についてはほぼ知識がないようです。 明るい雰囲気です。面白い挙動のするスプライトに対してはしっかり笑ってくれました。スプライトのチョイスにも世界観がありました！', '06ですが、私の説明ミスで「キー」ではなく「クリック」で動かしてしまいました。もしよければ次回再度説明していただきたいです。申し訳ありません。', '時間帯: その他
タイピング: レベルはちょうどよさそうでした。 何回か取り組んでくれました。
盛り上がり: 授業前後もScratchでしっかり遊んでました！！楽しそうでした。'),
  ('7061a108-1322-5483-b311-847d7fef9013', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-13', '18:40:00', null, '通常 / 宇宙バトルで基本操作の復習', '宇宙バトル2＆3→チュートリアルをみつつ取り組んでもらいました。宇宙バトル3ではおそらく教室で初めてクローンを扱いました。「親」と「子分」が存在し、親は子分を排出するだけで実際に動くのは「子分」であるという考え方を紹介しました。 単元別演習→どちらもよくできました。F-6では特に、「～でないまで待つ」を使うことを自分で考えられていてとても良かったです。スプライトが「負けたー」というアレンジに挑戦していました。変数の使うタイミング＆条件分岐が入り組んでいたため、混乱してしまって時間内に完成させることができませんでした。次回続きをやると良いかもしれません。', 'F-6をアレンジ部分を中心に見直し。', 'タイピング: 正答率が少し低かったです。本人曰く、ミスタッチが多かったようです。
盛り上がり: ひとつずつ組み立てて考えていてとても良かったです。'),
  ('08fef6b1-0a70-55ab-85a4-5049676a8ed7', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-13', '18:40:00', null, '通常 / 宇宙ゲーム、まゆ猫を探せ（条件分岐、クローンを再度復習）', 'シューティングやまゆ猫などのゲームに関しては、とてもよく覚えてちゃんとできていいました、その後に少し単元別演習G 演算でジャンプを滑らかに動かそうをやりました。 やはり、〜まで繰り返すや、演算を組み合わせる、変数との関係性になるとあやふやではあったので、そこをもう少しコードモンキーと組み合わせながら、繰り返しした方がいいのかなと思いました。', null, 'タイピング: ローマ字、和文Aともにスコアはとても良くできていました。すでに何回か練習していた体と思います。
盛り上がり: 以前作成したジャンプ作品をもう一度見直したときに、やはり楽しそうに遊んでいました。 そういう意味では、変数を使う、演算を使うなど難しく考えるのではなく、楽しくやるためのツールだという認識はある様子です。'),
  ('fae5e273-d622-5186-8019-5acfbc270a77', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-13', '17:30:00', null, '通常 / 宇宙バトルで復習', 'チュートリアルを見ながら取り組んでもらいました。途中「何をどこにプログラムしているのか」を忘れてしまう場面がありましたが、遊んだゲームを思い出して考えてもらいました。集中して取り組めていました。最後ゲームクリアの表示が消えず困っていましたが、ゲームスタート時にも背景を設定することで問題解決できていました。', null, 'タイピング: 集中して取り組めていました。2級を取れてとても嬉しそうでした！！ 何回も繰り返しチャレンジ出来ていてとても良かったです。
盛り上がり: オリジナルのスプライトを選んで楽しそうでした！！'),
  ('81321c1c-300e-537c-8c2c-32e126b0dee2', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-01-13', '17:30:00', null, '通常 / 宇宙バトルで復習', 'バトル1はスラスラ取り組めていました。休み期間中、家でもScratchを動かす機会があったようです。 バトル2もスムーズに取り組めていました。変数の部分に濃いアレンジをしたので、ゲームが終わらないのですが、集中して取り組めていました。 家で描いてきたキャラがアルスパーク上に取り込まれ、とても満足そうでした！！他の人がリアクションしてくれたのも嬉しかったようです！', null, 'タイピング: 集中して取り組めていました。正答率も高く良かったです。
盛り上がり: 集中して取り組めていました！！'),
  ('80e6fdcb-72ef-5583-b8ef-ea733ffef262', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-13', '16:30:00', null, '通常 / 宇宙ゲーム１〜２ 昨年の復習', '動画をみて、そのままコードを入れることは得意＝考えなくていいものに関しては集中してできるという意味になる。 その場合、どこまで理解ができているか？だが、キーで動かすなどの部分は理解、使いこなせている、変数の得点のあたりまでは大丈夫そう。 ただし、スプライトを止めるというメッセージのやりとりなどは、まこちゃんの場合あまり考えることをしないので、やや不安が残る部分ではある。', null, 'タイピング: マイパソは受験したくない▶︎漢字検定があるそうでそちらに集中したいとのこと、 ただタイピングの速さ自体はとても良いので、次回時間があるときにできたらいいなと思います。
盛り上がり: あまり考えなくても良いことに関しては、こなしてやろう！というやる気がとても見られていました。'),
  ('8d3c28fe-6295-5b6c-b5c4-28897dd43909', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-13', '16:30:00', null, '通常 / 宇宙ゲーム１〜２', '色々自分でアレンジ（キャラクターと音など）をかなり集中して行っていました ゲーム性ということを重視というよりかは、見た目などの方をアレンジしたい▶︎そのせいで少し疲れてしまった様子。', null, 'タイピング: タイピングはかなり得意な感じ。お兄ちゃんよりも結構できていたので、若干検定の結果が出た時が心配
盛り上がり: アレンジを加える部分はとても素晴らしい！ただ、そこに意識が向き過ぎて、宇宙ゲーム１を終えるのが1時間では精一杯だったので、少しずつゲーム性のコードの量をやることを次回から、先生側が意識したほうがいいのも。'),
  ('21cb57e9-44ef-5038-b870-c1a9ed743288', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-17', null, null, '振替 / ロボットクラスのクイズ', null, null, '時間帯: その他'),
  ('20d9638e-a4a3-5a8e-ad94-7a551adcc75f', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-01-13', '16:30:00', null, '通常 / 宇宙ゲーム1~3までをやってもらって、復習（〜ではないまで待つ、クローン）', '動画を見ながらどこまでできるか？がとらくんの問題でしたが、やはり動画をみる＝負けるみたいな意識があって、最初から全てをみるということをを拒んでいました。 もちろん途中で回答を見ていいんだよ（動画）と話しても、という感じなので、少しずつシンプルなところからやってみたら？という声がけをしながら、なんとか敵を動かす部分までできました。 ステージ３を先にやってしまったがためにそこに標準を置き過ぎてしまったのかなぁと・・', null, 'タイピング: 正答率はまずまず、何回か練習し、タイピングのやり方に慣れるほうから 自分でもスコア自体に関しては悪くないと思っている様子ですが、多少ミスタイピングがあるようです。
盛り上がり: 少し今日はとらくんにとっては辛かったかも・・・ でも詳細のコード自体は、ちゃんとこの動きというのは覚えているので全体との関係性と連携を考えるような指導に変える方がいいのかも・・'),
  ('ac83bb5c-fdf3-58c9-bdcc-884c896abcbb', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-12', '17:30:00', null, '通常 / 自由作成', '敵から逃げるゲームを作っていました。いつも通り作り途中のものは基本的に見せてくれなかったのですが、バグが起こってしまったときは助けを求められたので一緒に考えました。書いていたコードの意味を言葉にしていくと、おかしいところに気付くことができました。変数の値によって背景を変えるというアイデアは良かったですが、背景を変える条件として使った不等式が間違っていたようでした。', null, '盛り上がり: この前のくじで取ったお米を食べてるけどなかなかなくならないと言ってました'),
  ('0d948887-111a-5c75-ac1e-7a30b82ff50c', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-01-12', '17:30:00', null, '通常 / 間が空いたので復習する', 'ゲームを遊んでもらった後、ボールはキーを押したときに加速し、キーを押さないと減速していくことを一緒に確認しました。 動画に沿ってやったので基本的には大丈夫でしたが、不等号を使うところに等号を使ってしまっていたので、「～が～より小さい」と日本語に直すと気づいてくれました。 途中バグが起こってしまいましたが、スクリプトの上から順に動画と見比べながらチェックしていくと間違いを発見できました。', null, null),
  ('b2f0374b-dbe3-5111-bdb2-73d361b5855b', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-12', '17:30:00', null, '通常 / 動画を見ながら作り復習をしよう', '正月明けで期間が空いたので、動画を見ながら脱出ゲームを作っていきました。最初、遊んでもらったとき、3回程度のミスで2面ともクリアできていてすごかったです。動画見て作っていき、滑るコードを作り終わった時、これはどうゆう動きをすると思うと聞いたところ、すぐ止まるのではなくスーとなると言葉足らずながらも感覚的に答えることができました。これで、滑る動きのコードを理解できたと思います。途中で、バグが発生してお手本と見比べながら探してもらい、動画で見落としやすいマイナスの有無があって、時間もかかりながら修復できました。', '次回で完成すると思う', 'タイピング: 一段と早くなっていました。'),
  ('b83195ad-1521-5a73-aaa3-b000f40d77cb', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-01-12', '17:30:00', null, '通常 / 動画見てつくりながら復習をしよう', '正月明けで期間を空いたので動画を見ながらだ出ゲームを作りました。最初、遊んでもらう時はボールの滑る動きに苦戦して、なかなかクリアするのに時間がかかっていました。この動きはどうやってプログラミングすればいいか聞いたところ、変数を使ってどうにかするというところまで考えがついていて頭が冴えていました。動画を見ながら作っていき、滑るように減速させるコードではいったん作ってこのコードがどうゆう意味をするか聞きました。すぐに止まらず徐々に減速して止まると答えることができたので、新しく「滑る」動きを理解できた思います。だが、途中バグが発生してぱっと見つからないので、本人に探してもらいました。細かい違いがあって直せました。', '次回で完成に持っていけると思います。', 'タイピング: ミスって途中でやり直すことは多かったがスコアが上がっていました'),
  ('3dc2badb-4c2d-51e6-81ca-38c9b5f78ca6', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-17', null, null, '通常 / 福引クイズにチャレンジ', '福引クイズにチャレンジしたいとのことで、問題文を一緒に読み、ヒントを出しながら3問目までがんばりました。 「1秒待つ」などを入れることにはすぐに気が付いていましたが、ブロックを入れる位置などはとりあえず一番下など適当なところに入れてしまうこともあるので、ブロックが上から順に実行されるとき、新しくさせたい動作はどこに入るか、会話形式で一緒に考える必要がありました。', null, '時間帯: その他
盛り上がり: クイズは年長さんには難しいものでしたが、モチベーションも最後まで保て、一生懸命取り組むことができていました。 課題解決型はやる気が出るのか、途中でだれずに一気に完成させて喜んでいました。'),
  ('beed030b-1afd-5981-ac46-a216891ad1ce', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-20', '17:30:00', null, '通常 / 世界を創造しよう 基本操作の確認', '横に動かすときはx座標、縦に動かすときはy座標を使うことを説明しましたが、本人が理解できているかはかなり怪しいです。大きさや「キーをおしたときに～」の復習もしました。後者については忘れかけていたようです。秒数を変えてはやく動かしたり、大きさを極端に変えたりして試していました。コミカルな動きを表現するのが好きそうな印象です。', null, 'タイピング: 少しずつですが、打てるようになっている気がします！'),
  ('71998736-5847-50ca-8de2-2f1e61f43616', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-20', '17:30:00', null, '通常 / 基本操作コース（さあ踊ろう） or イライラ迷路', '基本操作コースを進めることになりました！！ コスチュームを変化させるときの「時間」をプログラムをするのは忘れがちなようです。動きを見てからおかしいことに気づき、自分で訂正できるのは良かったです。メッセージについても新しく学習しました。一度やった後にアレンジでもメッセージを活用し、使い方について再確認しました。なんとなく理解できたようです。 型抜きしたようなスプライトを作るには明るさを変化させればいいことを、自分で発案できていて素晴らしかったです。', null, 'タイピング: 授業前後もとても熱心に取り組んでいました！'),
  ('fd98a6b7-0691-5690-acdb-9242d7141e51', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-20', '16:30:00', null, '通常 / 復習も兼ねて福引問題', '楽しそうでなによりでした。つまづいてしまうところも、細かく分析してどこがうまくいかない原因なのかを考えることが出来ていました。感だとしても、とりあえず手を動かして挑戦していたので良かったです。 くじびきの問題は難しいようでした。条件分岐が込み合ってくると、混乱してしまうようです。最後に一緒にプログラムを上から確認しました。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 福引でチキンラーメンを当て、嬉しそうでした。サンタさんについてもくわしく教えてくれました！！'),
  ('aa5d2c3d-cdf2-5d40-b444-65e444448c3c', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-20', '16:30:00', null, '通常 / 復習しながら福引問題に挑戦', '自分で考える場面もありましたが、しょうたくんのやつをチラッと見たり、こちらにすぐ答えを求めたりして、少し残念でした。文章も読んで勘違いしたまま進め、こちらが指摘しても気づかないことが多かったので、検定問題をやるときにかなり注意が必要かなと思いました。 中級問題は積極的に手を動かしていたので良かったです。', '参加賞が嬉しそうでした！！', 'タイピング: 少しタイプミスが多かったです。'),
  ('e7b34ea9-5022-5f0a-bb00-7b7ad32a575d', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-19', null, null, '通常 / くじ引き問題', '今までやったことを思い出しながら問題を解いていきました。変数の使い方はよくできていました。スペースキーを押している間だけセリフを表示する問題では、「～ではないまで待つ」を使いこなせていました。まだレースゲームなどキーを連打するゲームは作っていないようですが、そのようなゲームを作る時もこのブロックを使って作れそうです。', null, '時間帯: その他
盛り上がり: くじを引こうと頑張っていました'),
  ('c32a8d45-e335-5018-826d-e0a38135bb57', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-19', '18:40:00', null, '通常 / 自由作品', 'くじの問題は、条件の範囲に余裕そうに気づいていて解けていました。そのあと、100m走のバグ修正するか自由作品するか決めたところ、自由作品をしたい気分でした。それで、入会したらやるダイヤのゲームのアレンジをしました。このゲームは大貴君にはやったことないらしくそのまま進めさせました。アレンジを見ると、大きさを変化させることがdきたり、通路に触れると、進む方向と逆方向に飛ばされたり、面白いアレンジがありました。ただ、壁抜け出きたり、位置が分かりにくかったり、多少のバグもはっせしていました。そして、演算や変数を使ったアレンジも見たい感じでした。本人は満足して作っていたので、ゆるい指摘程度にとどめましした。 大貴君が自由に作ると、学んだ知識は多く読み解くことはできるのに、それを活かしきれず感がします。', null, null),
  ('a23933eb-5cb2-577a-9e0e-dee402731175', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-17', null, null, '通常 / 教室に慣れる、Scratch導入', '初回の授業にも関わらず、福引クイズに積極的にチャレンジしていました。初級問題は、うまく動かない理由を言葉で言ってもらい、それに対してどうすれば良いかを説明してもらって、それに対応するブロックを紹介する形で進めました。どうすればバグが修正できるかほぼ理解できていたので、とてもスムーズにできていました。 チャレンジ問題も、飴とかごの例を見せたら何をすればいいのか理解できていたので、変数の作り方とブロックの紹介だけでクリアできました。', '基本操作コース02_名前を動かそうの予告をし、名前の文字スプライトだけ用意してあります。', '時間帯: その他
盛り上がり: 楽しそうにクイズにチャレンジしていました。一気に新しいブロックをいくつか紹介することになりましたが、終始熱心に、楽しんでできていました。'),
  ('c987aad3-743a-5c66-9eb5-26eef63929fa', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-19', '17:30:00', null, '通常 / 単元別演習の続き', '①くじびきの問題では、特殊な場合から順に処理することでバグをつぶすことができました。 ②単元別演習は先週の続きからやりました。ゲーム途中でスプライトを隠すコードを書いたときに、旗を押した直後に表示させるのを忘れていたので「このままもう一回遊んだらどうなるかな？」と言うと気づいてくれました。「〇秒で～に行く」と「もし～に触れたら隠す」を1つのスクリプトで同時に行おうとしてバグになったときがあったので、この2つは同時にはできないよねという話をすると違うスクリプトに分けて作ることができました。以前作ったレースゲームに似た問題があり、それを解くときに「レースゲームではこうやったな」と思い出し、「～ではないまで待つ」を活用してキーの長押し防止のコードを書けました。', null, '盛り上がり: えにしくんと仲良くしています'),
  ('61c7448b-204a-5ef7-b0fd-cc0525abb1cd', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-19', '18:40:00', null, '通常 / 自由作成 プログラミングを楽しむ', '福引クイズは、「より大きい」「以上」の違いで混乱していたようなので、そこを一緒に整理しました。 自由作成したいゲームがRPGか対戦系とのことだったので、アルスパークを探して「キューブの戦い」をアレンジすることにしました。 それぞれのキューブに大きな武器を持たせて動くようにしたいとのことで、スプライトの動きや向き、キーによる動きなどを作成しました。 もともとの作品が、左右の向きに変数を使っていたので、それを利用して武器の向きが変わるようにできたときは嬉しそうにしていました。', '武器のスプライトの角度が、左向きの時に思い通りにいっていないので、見直しをしたいところです。', 'タイピング: 申込をいただきました。
盛り上がり: 自由作成でゲームアレンジをしていく過程はとても楽しそうでした。 武器の向き、動きと、一つずつ光くんのやりたいことができていくたびに、一緒にテストプレイをしたがって、満足そうでした。'),
  ('66457a77-ccbb-57eb-8d4c-0aad4493f03c', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-19', '18:40:00', null, '通常 / コードモンキー for文の習得、関数の導入', 'Scratchとコードモンキーを選んでもらったところ、コードモンキーになりました。 本来は74からだったのですが、結構忘れているとのことで、for文の最初の61からやり直しました。 No.74で、ワニを各島の方に向けないといけないと思い込んで、turnToのあとに複数のオブジェクトが入れられないと悩んでいました。ワニが外側の各島の方を向いても、中心の筏を向いても結果は同じというヒントで先に進むことができました。 No.74以外は、ほぼヒントなしでスラスラと解いていました。 関数についても、今日の範囲は問題なく使えていました。 数問、「もっと短いコードで作成できる」と表示されることがありましたが、先に進むほうを優先したいようで、解き直しはしていませんでした。余裕があれば、星2つでクリアしたところは振り返ってみてもよいかもしれません。', null, 'タイピング: 文章にもチャレンジしていましたが、結果、ローマ字だけでよいとのことです。
盛り上がり: 1か所悩んでいた以外はよく解けていたので、あらたくん自身も熱心に進めていました。 1問1問がすぐに解決できるので、やりがいありそうにしていました。'),
  ('da41d798-dc8a-5e0d-aaca-916bb6b37411', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-19', '17:30:00', null, '通常 / くじ問題にチャレンジ＋アレンジ', '最初にくじ用問題にチャレンジしました。このくじ引き用の問題は順序を入れ変えればできてしまうので、コードが完成したときに修正した理由を聞いてみました。最初はなんとなくと答えられていしまったが、もう1度考えてもらい、条件の範囲の違いと順序に気づくことができていました。くじ引きは参加賞だったが、この問題を気に入ったのかそのコードを使ってアレンジを始めました。あるくんのセリフや大きさを変えて、面白おかしく作って楽しんでいました。ランダム性で遊ぶっていうことが上手く楽しめたと感じる。', '乱数を使ったスロットとかをつくるのはいいかも', 'タイピング: 今日的にも倒せるほどに強くなってきました。
盛り上がり: 最後の時間にしゅうくんとたがいにアレンジしあがって、笑いにあふれていました。'),
  ('9520cc04-cd4f-5cfd-95e9-ef7fe61351db', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-19', '18:40:00', null, '通常', '①くじびきの問題は比較的すぐに解くことができました。条件分岐はよくわかっているようです。 ②星とりゲームでは、考え方はほぼ合っているがブロックを置く順番が変でバグになるということが多かったです。ブロックが動作する順番を一緒に考えることでその問題は解決しました。乱数や「～まで繰り返す」ブロックなど、以前やった内容を思い出して活用することができていました。', null, '盛り上がり: スプライトがどう動けばいいのかを言葉にしながら考えることができていて、論理的な思考力がついてきていると思います。'),
  ('22c6bf64-12ec-58f2-82e7-34eb1e9990a2', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-19', '16:30:00', null, '通常 / 単元別演習D-3、4 終わったらアレンジまたは自由作成', '単元別演習D-3～4については、問題の読み込みが足りず、どのスプライトにどのコードを書くかが曖昧でした。落ち着いてカードの問題を見せ、このスプライトが押されたときには何がおきると書いてあるか、ゆっくり問いかけると納得していました。問題文に対応するコード自体は自力で作成できていました。 D-4の問題では、ジャンプが未履修だったようなので、ジャンプの部分だけ一緒に作成しました。ジャンプの動きに繰り返しの変数を入れるとジャンプの高さが変わり、ジャンプの動き全体を繰り返すとジャンプの回数が変わることを、両方のコードを作って確かめました。 演習の後は、「おまつりを完成させたい」と熱心に作成していました。', null, '盛り上がり: 問題だけを渡すと、まだ何をしていいのか迷ってしまって「できない」となってしまいますが、プログラミングをやりたいという意思は強いので、どこから手をつければよいのか道筋を示すだけで納得し、熱心に作成することができていました。'),
  ('95fb4312-26fa-55d7-94f5-32c00be6aff5', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-19', '16:30:00', null, '通常 / 自由作品', '最初にくじ用の問題にチャレンジしました。くじの数による条件分岐を考える問題でしたが、さらっとできていたので、なぜそうしたか聞きました。条件の範囲を被らないことを理解していてよかったです。 そのあと、自由作品にしましたが、あまり思いついて稲層だったので、走り幅跳びのゲームを作ることにしました。今日はゆるくにやっていたせいなのか、なかなか作り始めようとせず、コスチューム変化に夢中でした。こんなようなことは初期のころはあり、最近はなくなって自走できると思っていました。だから、おうすけくんはある程度のスタートダッシュをしてあげてから自走するようにした方がいいと思った。左右に交互に押す仕組みでは、それをどうゆう風に表現したらいいか迷っていたので、元から用意してある変数に注目させました。すると、左、右の変数を見て、スイッチみたいに帰ればいいのと質問が飛び込んできたので、過去にやったことが反映して勘が働いていました。', null, '盛り上がり: コスチュームの独特な奇抜さは面白いものもあって楽しく作っていました。'),
  ('40567e3a-8751-554e-917e-1f43134ea10b', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-19', '16:30:00', null, '通常 / 条件分岐の整理、自由作成', 'くじ引きの条件分岐の順序については自分で整理できていて、きちんと解けていました。 コンテスト作品をもっとブラッシュアップしたいという希望があり、後半はスズリンパの続きを作っていました。 タイトル画面をもっと充実させて、そこから解説画面などにもとべるようにしたいそうです。 タイトルのフォントがScratchにあるフォントでは物足りないとのことで、Canvaなどを使って作成することにしていました。', null, '盛り上がり: クイズも自由作成も、楽しそうに取り組んでいました。 賞状がきたら見せてくれるそうです！'),
  ('8f9732af-cf3d-5bb6-90b4-0f92cb21dd13', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '3d62819a-addc-5584-afc3-251fdb7abc04', '2022-12-17', null, null, '通常 / コードの振り返りをしよう', '今日は、問題を解くことができれば、くじ引きができるレッスンでした。 難易度の低い問題はつまらずに解いていました。 No.8の問題では「○と○秒言う」のブロックに空白を打ち込むと表示が消える事を知らなかったので、そのことを教えてあげると解けました。 文字の入れ替えでは順を追ってスクリプトを確認すると、自分で変数を増やして数値を保管することに気づけました。 理解するまで何度もスクリプトを確認しましたが、集中して取り組んでいて素晴らしかったです。', null, '時間帯: その他'),
  ('8980bbe8-bf87-5cce-93c0-466629b444a2', '6161701a-a37e-5581-90fb-a00d0962a75d', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-17', null, null, '通常 / くじ引き用問題でコードを習おう', 'まだ経験が浅いながらもくじ引き用問題にチャレンジしました。まだ習っていないコードとかもあったので、基本的に、誘導的に作り上げていき、出来上がった結果を確認して理解してもらうようにしました。優しめのブロックの修正では、ずっとを入れるところなど自力で来ていたので、初回のことが理解が残っているように感じました。', null, '時間帯: その他'),
  ('d160f3bf-a473-5b9b-91bf-703a5f0e8535', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-16', '18:40:00', null, '通常 / 条件分岐の使い方になれる', '条件分岐のいろいろの使い方に慣れてもらうために、単元別演習F条件をやりました。町長が追いかけるゲームでは、滑らかに動かすことが上手くできていなかったので、げうようにやってくじ引きの4匁を振り買ってもらい、どうゆうコードを使っていたが確認してもらいました。そして、動きにのコードには歩数を決めるもの、向きを決めるもの、または両方を動かすものがあることを確認しました。 ひよこタッチゲームでは、特に迷うことなく、条件分岐をうまく使えていてスムーズにできました。 雪だるまの発射では、動きはできていたが、指定するコード「まで繰り返す」が使えていなかったので、もう一度感が直してもらいました。そこで、作り直したコードは正常に動いていただが、端まで繰り返すの後に端に触れたらの条件がくっついていて、無駄であることの理由を考えてもらいました。そして、雪玉が戻る行動が座標でしていいたので、スプライト指定の方がいい理由も一緒に考えました。それなりに自分のことで言い割らせていたのでよかったです。敵の当たり判定では、何秒動かすの後に触れる条件が付いていてバグになって言いました。ここは時間がなかったので、並列に作って同時作業ができることを教えました。 ここに関して、ロボットの星取りゲームをいったん触れさせるのもいいと思う。', null, null),
  ('8b0befb0-62e6-55da-a929-3ed8ad527277', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-16', '18:40:00', null, '通常 / 福引クイズ、コードモンキー（関数）', '福引クイズの初級問題は、さすがに問題なくスラスラ解けていました。 チャレンジ問題は、問題文だけ読んで少し混乱が見られたので、かごと飴玉を見せたところ、「一時保存」の意味がわかったようで、その後は自力で完成できていました。 コードモンキーの典型的なgoto関数の使い方にはずいぶん慣れたようで、スムーズにできていましたが、数字を入れる場合とものの名前を入れる場合の使い分けに少し混乱が見られました。', null, '盛り上がり: コードモンキーの関数にも慣れてきたのか、試行錯誤しながらも自力で解決できる場面が多く、楽しそうに取り組んでいました。'),
  ('eb5e83f7-e589-5eea-a7e6-991ce358610c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-16', '17:30:00', null, '通常 / コードの復習をしよう', '今日はくじ引きのためにクイズに茶連視しました。開始前からやっている姿が気になっていたのでやる気は満々でした。初級編は、どういったものを作ればいいか少しわかりにくかったので、正答例を見せながら作っていきました。5問目のセリフの表しからの考え止まってしまってが、自力ですべて解くことができました。チャレンジ問題では、コードだけではわからないようにしていたので、ヒント文をよく読んでもらいました。そこで、3つ目の変数が必要なことがわかりました。あめとかごで動きを体験させてもらい、コード作成には変数のコードが今一度どうゆうものなのか確認しながら作って完成できました。', null, '盛り上がり: 全部参加証だったので、景品があった子に裏山がっていました。'),
  ('7ba86f6b-3b25-50be-af51-175c77eb579d', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-16', '17:30:00', null, '通常 / 福引クイズチャレンジ、単元別演習F', '初級問題は、問題の意味の説明があればそれなりに解けていましたが、初めから自力で問題を読もうとする姿勢についてはイマイチでした。 先生を呼んでそばにいてもらい、一緒に話しながら取り組むと、すぐに「あ、わかった」と気づけることも多いのですが…。 チャレンジ問題のロジックについては、かごと飴玉を用意したらすぐに「もう一つ箱がいる」と思いつくことができたので、飴玉を入れ替える手順をブロックでやってみて、という声掛けで解くことができていました。 単元別演習でも、すぐに「わからない」と先生を呼んだりしていましたが、まったくわかっていないわけではないので、ひとりで解ききる経験をもう少しさせていきたいところです。', null, 'タイピング: ローマ字部門については順調で、2級相当の結果が出ています。
盛り上がり: コードの全体像を思いつくことは、だいぶできてきています。 が、ブロックの順序（繰り返しブロックとの関連や、変数を変えるタイミングなど）が適当なまま、なんとなく作成してしまうため、思い通りに動かずに「先生～！」となることが多いです。さらちゃんが自身でできていることを認めるとやる気になっていたので、ここからもう少し集中力につなげていけると良いのですが…。 タイピングは良い級が出るのでとても頑張っています。'),
  ('4542ba6a-016f-5315-a9fd-90bb76ba0afe', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-16', '16:30:00', null, '通常 / くじ問題を通してコードの復習をしよう', 'くじ引きをやるためにクイズをやりました。初級編では1個1個のペースはゆっくりで、変数のところとスペース期の条件分岐のところで迷っている感じでした。変数のカウントアップは海底あるものを作って次にどうやるか止まっていたので、ピンポンゲームのスコアの加算の仕方を振り返りました、その復習もあって、自力で作り上げることができました。5問目は、条件分岐で「でなければ」のコードを持ってくることはできていたが、そのあとが進みませんでした。そこの考えのプロセスは「何も言わないを言う」一緒に考えやりました。 チャレンジ問題は、残り時間が少なかったので、最初から飴とかごを使って、入れ替えの作業をやってもらいました。そこで、1個ずつしか動かせない、入れられないからことから「雨を外に出しておく」ということに自力で気づけたいました。一緒に支えながらコードをくみ上げることができました。', null, null),
  ('bcd79218-890e-57b5-846c-e456d63d47d0', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-16', '16:30:00', null, '通常 / 福引クイズ、単元別演習Fで基本的なコードの確認', 'クイズには熱心にチャレンジしていました。 各問題のバグに対しても、バグになる理由や解決手段などを言語化して説明していました。 チャレンジ問題については、かごと飴玉を箱1と箱2に見立てて見せたところ、すぐに「もう一つの箱がいる＝＞変数をもう一つ作る」と思いついていました。', null, '盛り上がり: 問題チャレンジは好きなようで、積極的に取り組んでいました。 問題を解きながらも福引を気にしていて、かんたくんには珍しく「寛太は爆死した」という茶化した変数名を付けていました。'),
  ('097d4d1b-fa05-546f-abea-19fd886b7d06', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-16', '16:30:00', null, '通常 / コードの復習をしよう', 'くじ引きの用問題にチャレンジしました。初級の5問は特に迷うことなく、すらすらとけていました。チャレンジ問題では、高学年なのでまずノーヒントで挑んでもらいましたが、悩み止まってしまいました。ヒント文を読むように誘導しましたが、少し時間たって様子を見に行くと、画面上では表示はできているが、セリフの部分に直接書き替えて、できたと言い張っていました。考えはいいがずる賢いので、あとで正答例を見せて、作ったコードが説明できるようにしました。 残った時間は前まで作ったものの続きをやりました。ただ、ほかの人がくじを引いているのを見ていいて、いじっていたが、あんまり進んでいなかった気がします。', null, null),
  ('155abb9f-a28b-52ed-8190-29c5685452bc', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-16', '17:30:00', null, '通常 / くじ引き問題', 'とうきくんにとっては、最初の問題自体の考え方（演算）が難しかったようでしたが、全部いれてみて動くことをしてみました（チャレンジ精神はすばらしい！）その後の問題に関しては、待つ〜など覚えている部分はちゃんと自分で解くことができ、自信に繋がった様子。', null, 'タイピング: なし
盛り上がり: 最初の５問がかなり手応えがあったようで、チャレンジ問題にも挑戦！トライアンドエラーをすることで、どんどんコードを覚えられているなぁと今日は思いました。本当にこの半年でとても成長したと思います。'),
  ('4031978f-f293-540d-8c56-5ecd9d0c6efd', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-16', '17:30:00', null, '通常 / くじ引き問題と単元別演習Gの１まで', 'くじ引き問題の初級５問に関してはあまり考えなくてもスラスラ解けていました。ただチャレンジ問題に関しては変数の使い方自体はきちんと覚えているようでしたが、パズルのように組み合わせでコードを書くことはちょっと難しかった感じ。 Gの演習に関してはジャンプで下がるのが演算を使ってやるというのはまだ苦手そう。変数の使い方はちゃんと覚えているので、そこをうまく使いこなせるようになっていければさらに進化しそうだなと思いました。', null, 'タイピング: なし
盛り上がり: くじ引き問題のように何かがもらえるみたいな感じでやると集中！５等があたって嬉しそうでした！'),
  ('fadee90c-23d4-538f-9eba-74bb07690b9d', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-16', '16:30:00', null, '通常 / くじ引き問題５問と前回の復習（レースゲーム）', '今までの成果が問われたくじ引き問題でしたが、まこちゃんもちゃんとずっと〜や待つ〜は覚えていて、演算と変数以外の問題に関しては難なく答えられていました。少し早めに終わったのでレースゲームをやったところまでの復習。やっぱり変数の問題に関しては、変数を〜にする、ずつ変える〜のを忘れていたようで、どうしてもうさぎとワシの順位を変えられずにいたので、そこをもう一度根気良く自分で確認してもらうようにしました（ピンポンを見せながら）', null, 'タイピング: なし
盛り上がり: くじをひけたこと、そして自分が覚えているコードがあることに多少は自信を持ってくれた様子でした。'),
  ('fcbdd4d2-71ae-5f9f-8ad5-6c53a00080de', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-16', '16:30:00', null, '通常 / くじ引きの問題５問＋チャレンジ問題', '初めはバグになっているということがわからなかった様子ですが、ヒントを色々と渡しながら進めてみました。 ちなみに最初の１問目はまだたくやくんがやっていない、演算の問題だったためつっかかってしまっていましたが、他の問題（ずっと〜、待つ）などは簡単にクリアしていました。', null, 'タイピング: なし
盛り上がり: チャレンジ問題に関しては、まみ先生とも相談しながら行っていたようでしたが、なんとか変数の箱の概念が理解できた様子でした。頑張った甲斐があったのか3回ともくじが５等になってとても嬉しそうにしていました！'),
  ('c265ce9c-c84e-5876-ac55-fbaf6e766cf6', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-09', '17:30:00', null, '通常 / ジャンピングゲーム 応用 背景スクロールとジャンプの組み合わせ', '基本操作コースで作成したジャンプゲームを何度か開いて思い出しながら作成しました。 最初は完全に忘れていると言っていましたが、自分が以前作成したものを一度プレイしたら思い出したようで、基本操作コースで学習した内容は自力でできていました。 敵に当たった時の効果も、「色の効果」を使うというヒントだけでできていました。 ゲームに関連付けるところまではできませんでしたが、マリオのような背景やキャラクター、コインの動きを付け加えて楽しんでいました。 背景を動かす座標も、自分でよく考えて納得していました。', null, '盛り上がり: 背景を動かしたり、マリオのようなキャラクターの動きを作りながら、興奮気味に喜んでいました。こういうものを作りたい、という意識がとても強かったです！'),
  ('e956c9f3-5fae-5785-9eb7-432209039732', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-09', '16:30:00', null, '通常 / ピンポンゲーム 変数の使い方、角度、乱数', 'ピンポンゲームの見本を見せたら、見たことがあるゲームだと喜んでいました。 たまたま、ピンポン玉をだ円形のスイカにしていたため、「まわす」ことによって動きがどう変わるかわかりやすく、実際にプレイしながら角度を変えて、楽しそうに調整をしていました。 跳ね返った時の角度の乱数を学習すると、ゲーム開始時の角度も乱数にした方が面白いとアレンジをしていました。 スコアの変数を変えるタイミングをメッセージで作成していました。時間切れのため、こちらの検証は次回にまわしました。', '変数を変えるタイミングについて検証していきたい', '盛り上がり: ピンポンゲームは作るのを楽しみにしていたようで、スプライト作成から生き生きと取り組んでいました。 自力で作成して思いどおりに動かなかった時に（ゲーム開始時にピンポン玉が水平に動いたときなど）、どうしてだろうと考えて解決しようとしていくことができていました。'),
  ('26d2e41c-cadc-5758-a7b3-1b2e477a66f8', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-15', '17:30:00', null, '通常 / くじびきの問題を解く、幅跳びゲームのイメージをつかむ', '①くじびきの問題は、比較的すらすらと解くことができていました。ただ、マウスに向かってスプライトを動かす問題では難しく考えすぎていたみたいです。スプライトがマウスに触れているか否かで条件分岐させようとしていましたが、「もっと簡単にできるよ」と伝えると、ずっとマウスに向かって動き続ければいいのだと気づきました。 ②幅跳びゲームでは、左右のキーを交互に押すことでスピード変数の値を変え、ネコを走らせることができました。以前のレースゲームでやったことを思い出して、キーの長押し防止のためのコードも書くことができていました。流石に今日終わらせるのは厳しかったようですがそれでもスピーディーに作っています。', null, '盛り上がり: 「一週間の中でこの教室に来る日が一番楽しみ」と言ってくれました。'),
  ('01f55dbd-4ed1-5b33-a325-3ed27fc43ef7', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-15', '17:30:00', null, '通常 / 「～ではないまで待つ」の習得 【Prg】23 走り幅とびゲームを作ろう', '福引という目標があったせいか、問題文を読んで解く形式でもとても一生懸命に取り組んでいました。 チャレンジ問題では、何度やっても箱1と箱2の中身が同じになってしまう結果にとても悩まされていました。入れ替えを同時にはできないことは、容器と飴を使った動作で両手で一度に入れ替えることができないということで納得していました。 「箱1を箱2にする」ブロックの意味にかなりの混乱が見られ、「箱1の中身を箱2の中身にする」のか、「箱1の入れ物そのものを箱2に変えて中身はそのまま」なのか、イマイチ理解しきれていないようでした。図解と、実際の容器と飴を入れ替える作業でなんとなくのイメージはつかめたようでしたが、同じ内容のブロックが重複していたりと最後まで苦戦していました。', 'チャレンジ問題はなんとかクリアできましたが、いじっているうちにできてしまった要素も強かったので、一時保存する場所としての変数の利用は、またチャレンジしてみてもよいかもしれません。', '盛り上がり: 時間いっぱいまで、「これもう無理！」と言いながらも投げ出さないで取り組むことができました。最後は、1行ずつ箱の中身をチェックしながら考えて、なんとか完成させることができました。'),
  ('6c856d59-981e-5273-8f88-22abba0da711', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-15', '17:30:00', null, '通常 / 今までのコードの復習をしよう', 'くじ引き用の問題に取り掛かりました。初級編では、ゆきちゃんによくある文章を最後まで読まない癖もあって、最終的に何を作ればいいだっけ？と止まってしまうことあるが、読むように催促したり、解答例を見せたりしてしました。コード作成自体には時間はかからず進めていました。チャレンジ問題では悩んで完全に止まっていたので、まず、プリントに書いてあるプログラムは同時作業することはできないヒントを注目させて考えました。そこで、1つの動作しかできないから、もう1つ変数が一つ羊ことに気づいてもらいました。次に、色の違う鉛筆を1課ずつ動かして入れ替えてもらうヒントを与え、円ピンの入れ替えの動作はできていたが、その動作をコードに落とし込むことができずに悩んでいました。その最中、紫のコードのところでその操作を行っていて勘違いしていました。だから、元から作ってあるおコードがどういう意味をしているか確認を行うと、その説明はできたので、そこで勘違いしていることに気づき、あとは自力で時間をかかりながらも入れ替えのコードつくりことができました。 このチャレンジ問題をする前から変数は苦手って言っていたので、次回からはその克服をできるようにすることをすればいいと思う。', null, null),
  ('c3d42a77-00f6-58c7-91f8-b99867502b1a', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-15', '16:30:00', null, '通常 / 福引チャレンジ問題', '文字列の結合については、自分で演算ブロックを見ていて「＋」の代わりに「りんごとばなな」を使うことに気付くことができました。 繰り返し（気合いだ―！）については「〇秒待つ」ブロックを使うことには気づけたものの、数字がどうしても全角のままにしてしまうことが多く、苦戦していました。 変数については、過去の自分の作品（追跡ゲーム）を見て変数の基本的な使い方を思い出したらすぐに解けていました。 No.20の繰り返しについても、同じく追跡ゲームを見直しさせたら気づきました。 No.35については、「スペースキーが押されたとき」と「押されていないとき」にわけて考えようとしていたので、条件分岐のelseがあるブロックを使う方向で誘導しました。 「何も言わない」＝「かくす」で考えていて、これではスプライトが消えてしまうと悩んでいたので、「言わない」＝「何も話さない」のヒントを出したら解決することができました。', null, 'タイピング: 検定のコーナーを一生懸命やっていました。
盛り上がり: 福引の為にとても一生懸命取り組んでいました。 難しそう！と言いながらも、とりあえず自分で考えてみる、と初めから答えを聞こうとしないところが良いです。'),
  ('eb0011b8-2688-5fa1-b144-6de836da97ed', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-15', '17:30:00', null, '通常 / くじびきの問題を解く', '最初の5問の中では、変数を1,2,3,4,5と順に変えるところでつまづいていたので、最初に値を決めてそのあと繰り返し中身を変えていくという変数の基本を復習しました。 最後のチャレンジ問題は、2つの値に対して3つの変数を使って入れ替えをするという考えが難しかったようです。かごとキャンディを使って再現してみたところ、段々イメージがつかめてきました。ただ、プログラムは上から順に実行されていくという認識が足りていないせいか、新しいブロックを作るつもりで古いブロックを書きかえてしまうということがありました。最終的には全問解くことができました。', null, '盛り上がり: なにがなんでも問題を解ききってくじを引こうという執念が感じられました。これがいい方向に働けば目的に向かって努力できると思いました。'),
  ('17fa4f8e-821d-5e30-86f6-4fddf7ec8c0a', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-15', '17:30:00', null, '通常 / 変数と演算の使い方をマスターしよう', '最初にくじ引き用の問題を解きました。最初の5問は問題をぺらぺらめくっただけで特に迷うことなくすぐできました。チャレンジ問題は少し考えただけで、別の箱を持ってくればいいことに気づき、その考えをすぐにコードに落とし込むことができていました。プログラム的な考え方への理解が深まっています。 次に、走り幅跳びのゲームの作成に移りました。遊んでもらったときは連打が遅くて少しがっかりしていました。コードの作成に移ると、できるだけヒント無しで作りたいらしく、あえてヒントコメントは消して作っていました。1から作りたい精神が強くなっていると思います。たびたびゲーム画面で確かめながら、変数で左右のオンオフの切りが作れていたり、加速が仕組み作れていました。', '続きでじゃんっぷの仕組みを作るところ', '盛り上がり: 最初はくじとかに興味ない感じでしたが、周りが盛り上がっているのを見てやる気が沸き上がっていた。'),
  ('d80e457b-8102-5f90-af25-09e7ead6b7f3', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-15', '16:30:00', null, '通常 / 単元別演習F スキルの定着と短時間での効果的なアレンジの練習', '席についてすぐに福引用のチャレンジ問題から解き始めていました。ノーヒントで一時保存用変数を作ってあっさり解き終わっていました。 レースゲームと単元別演習の2つを提示してみたところ、今日は単元別演習の続きをする気分だとのことで前回の続きのF-2から取りかかりました。 設問通りに解いた後に5分間でアレンジを加えてもらい、どんなアレンジをしたのかを口頭で説明してもらいました。スプライトに演出効果をつけたり、ゲームの開始前にストーリーを付け加えたりと、毎回オリジナリティのあるアレンジを披露してくれて、楽しそうでした。', null, '盛り上がり: アレンジの幅が以前よりも広がってきていて、本人も楽しそうに取り組めていました。
備考: 福引で5等を当てて、可燃ごみ袋を選んでいました。親孝行！'),
  ('9624e57e-ea70-5788-b1a7-a63a00f5bd60', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-09', '16:30:00', null, '通常 / ジャンピングゲーム 応用 背景スクロールとジャンプの組み合わせにチャレンジ', '本人の希望で、前回のレースゲームの背景を設定して完成させました。 ジャンプゲームのシンプルなジャンプについても、忘れてしまったとのことだったので、テキストを見ながら復習をしました。 繰り返しの数をジャンプするときと降りるときとで変えていて、ジャンプがおかしいとぼやいていました。ミスの発見には、こちらのヒントが必要でした。 敵スプライトの数や形を変えることを面白がって、色々編集して楽しんでいました。 ジャンプの動きの復習とコスチュームの編集がメインになったため、背景スクロールには至りませんでした。', null, 'タイピング: ローマ字部門に何度も挑戦していました。それなりにうてていたので、エントリーしてみてもよいかもしれないです。（お母さんは、本人がやれるなら、と前向きでした）
盛り上がり: 復習がメインとなりましたが、最後まで集中してよくがんばっていました。 一度学習した内容でも、素直にもう一度学習しようという姿勢が見られたのがよかったです。'),
  ('afa000a5-64e1-55ce-8e6f-7f450fadc257', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-12', '17:30:00', null, '通常 / 条件分岐を使いこなす', 'くじびきの問題では、きちんと動くコードを試行錯誤しながら探していました。多少時間はかかったものの全問解き切り、コードの描き方のレパートリーを増やすことができました。 単元別演習Fでは、「もし～なら」を活用してミニゲームを作りました。複数のゲームで、条件に応じてスプライトを表示する/隠すことができました。座標の初期化なども含めて必要なことを忘れずに作ることができました。くじびきの問題で時間がかかってしまい単元別演習は2問ほどしか終わりませんでしたが、問題なく進んでいます。', '単元別演習の続き', '盛り上がり: 分からない問題があっても投げ出さずに続けることができました。'),
  ('5f753363-b45c-5d58-983f-c4ec48c4d7c2', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-13', '17:30:00', null, '通常 / くじ引き問題に挑戦', '変数や「～と～」のブロックはおそらく初めてみたので、使い方やポイントを説明しました。プログラムを少しずつ読めるようになってきたようにお思います。「なるほど！」と声を上げる機会も多くなってきました。最後の問題まで取り組んで福引を2回できました！また今日は、初めて使うブロックも多かったので「いろんなところにおいて試してみる」ということにも挑戦してもらいました。', null, 'タイピング: とても集中して取り組んでいました。授業の合間に取り組んだりもしていました。
盛り上がり: 最後まで終えられて少し満足そうでした。'),
  ('53452eab-8a15-57f2-8cb6-a2caeaa5b4d2', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-13', '17:30:00', null, '通常 / くじ引き問題に挑戦', '変数や「～と～」は初めて使ったので、プログラム上での役割を少し説明しました。最後の問題までかずとくんと一緒に取り組めていました。良かったです。「ずっと」の使い方だったり、「〇秒いう」「いう」の違いが少しずつ理解できてきたように思います。また今日は、初めて使うブロックも多かったので「いろんなところにおいて試してみる」ということにも挑戦してもらいました。', null, 'タイピング: 丁寧に取り組めていました。
盛り上がり: あまり楽しい内容ではなかった様子でした。。'),
  ('a150cc09-066f-5764-9312-ca1f0eb47e98', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-13', '16:30:00', null, '振替 / くじびき問題に挑戦', 'くじ引き2回目には興味がなかったようなのですが、問題には挑戦してもらいました。お母さんがくじを引きました。プログラムがうまく働かない原因をなんとなく把握して、改善方法を考えることができていました。問題が読みにくい部分は完成系を見せて作製してもらいました。しっかり考えてプログラムできていたので良かったです。 変数を扱う部分で、偶然にも0から始め、1足すタイミングをコントロールしたことでうまく足し算できていました。見本とのプログラムの違いについて確認しました。 頭の中のなかでブロック同士の関係がなんとなく整理されているようです。「もし」と「ずっと」がセットで出てきてよかったです。 紙の問題に取り組むのが楽しかったようです。時間も少し余っていたので、ドリルの問題9に挑戦してもらいました。スムーズにできて良かったです。', null, 'タイピング: 丁寧に打てていてとても良かったです。集中できていました。
盛り上がり: 問題をひとつずつ進めていくのは嫌いではないようです！！楽しそうでした！'),
  ('df6c5b3f-0938-53ff-88a9-10b5cdf4ec36', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-13', '16:30:00', null, '休み（振替対象） / ▼振替日程はまだ決まってません ▼2/10（金16:30～（中島受け1/17）', null, null, null),
  ('00fe1e74-b0cc-5a3b-96d4-fe2b164af762', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-13', '17:30:00', null, '通常 / 福引のクイズ＆福引チャレンジ問題クリア ＆「ではないまで待つ」の応用', '▼初級のクイズは楽々でした。チャレンジ問題は、最初試行錯誤していましたが、案外はやい時間に「変数をもう一つ使えばいいんだ！」と自分で気づきました。さすが！ さらに、試行錯誤して正解にたどり着きました！途中、私がヒントを出そうと箱と飴を用意しただけで「なんかわかったかも」と。数学的勘の良さを発揮しました。 ▼【Prg】23 走り幅とび を最初プレイし、「これを作るの～！無理～」と言いつつもちょっとヤル気モードを出していました。簡単に細分化（最初にこの動き、次にこの動き）と３段階までイメージし、動画を観ながらチャレンジしました。 動画 ５分ぐらいまで／矢印キーでネコを走らせるところまで。 「〇〇ではないまで待つ」はこれで、完璧にマスターできたでしょう～', '【Prg】23 走り幅とび の続き。結構、自力で作れそうなので。動きを細分化した箇所だけを指南して、まずは自分で作ってみる→それから動画で確認ができると、いいな～', '盛り上がり: 福引き４等が当たりました！ お母さんが昆布と鰹節セットを選びました。ミズキ君がすごく嬉しそうでした。'),
  ('50fc825e-cbfe-5ea4-bd2c-8b670edc3974', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-10', null, null, '基本操作コース ピンポンゲームを完成させる 変数の使い方、マウスポインターに座標が動くの考え方', 'まず、キーでスプライトが左右に動く動きはできているので、その部分からマウスで動きを変えるというコードに変換しました。多少この部分はまだ低学年の子には難しいとは思うのでいくつか追跡ゲームで練習しうてみると良いかなと思っています。 変数 ポイントがなにに、触れたら、1点を増減させるために何のコードが必要なのかを考えておらいました。 常に問いかけとして、どこかに答えが隠れているよ〜と簡単な算数を質問しながらのほうが、変数のカウントアップ、デクリーメントは慣れていくのかなと思います。 他の子でもそうですが、ポイントだけに囚われすぎると変数の使い方が偏りがでるので、慣れてきた時点で、スピードのインクリ、デクリをすこしずつ入れていくといいと思います。', null, '時間帯: その他
タイピング: タイピングは概ねできるので、単純なあいうえおなど、ふた文字のローマ字タイピングをしてみました。少し間違いはあるもののうでだめしで、６割ほどできているので次回からもプレイムで大丈夫かと思います。
盛り上がり: バグがあった部分を自分で気がつけた。マイナスの概念を質問を聴きながら発見できた！'),
  ('f5a65721-1f4f-5ba0-874d-bc0fec9fcf02', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-12', '18:40:00', null, '通常 / 演算の練習をする', '速度を変えながらのジャンプに苦戦していましたが、速さの変数も今までやってきたスコアの変数も基本のところでは同じということを理解してもらい、だんだん速さを変えながらスプライトを動かすことができました。 その後もところどころで苦戦する場所がありましたが、一緒に問題文を丁寧に読んでいくとできたところが多かったので、文章を読み込む力をつけていけるといいと思います。 最後は「〇色に触れたら」と「〇色が〇色に触れたら」をごっちゃにしてしまっていたので、触れた判定になる範囲が違うことを説明しました。', null, '盛り上がり: 難しい問題に対してもあきらめずに取り組めています。'),
  ('c8968a1d-dad0-5aef-876c-dbc4f9decc78', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-12', '18:40:00', null, '通常 / 検定問題で実力を測ろう', '最初に検定4級の問題を練習しました。コードは特に迷うことなくメッセージのやり取りも把握できていて全体的によく組めてていました。アレンジでは効果音をつけたり、1度捕まった後にもう1一度できるようなメッセージのやり取りのコードが組めていて完璧でした。 後半はくじ引きの問題に挑みました。特に迷う気配もなく淡々と進めていきました。5問目に関してはセリフを消すという表現が思いついていなかったので悩んでいましたが。ヒントを与えると自力で最後まで作り上げることができました。', null, null),
  ('bb08633a-c670-5463-81b5-48f47f2b70f9', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-12', '18:40:00', null, '通常 / ゲームの場面を切り替える', '前半はくじを引くための5問+1問の問題に取り組みました。最初の5問はすらすら解くことができましたが、最後の1問は長考していました。ヒントとして書いてあった「箱の中身を一時的に覚えておく変数を作ろう」というのを読んだ後、変数を新たに2個作って箱1と箱2をそれぞれコピーしていました。想定している回答では新たに作る変数は1個なのですが、たいきくんなりの発想で問題が解けたので良かったです。 後半は100m走の続きを作りました。メッセージを送ってスプライトを隠したり表示させたりすることで、予選から準決勝に場面を移すことができました。準決勝ではフライングの判定がきちんとできていないなどのバグは残っているので次回修正していきたいです。', '100m走の続き', '盛り上がり: 自分の頭でプログラムの書き方を考える姿勢が身についていて素晴らしいです'),
  ('ee337668-99ba-5dbf-b2b0-d90725d3c77e', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-12', '17:30:00', null, '通常 / くじ引きの問題にチャレンジしよう', 'くじ引きのために問題を解いていきました。最初、問題のコードを映して「できないじゃん」と投げ出しそうになっていたが、丁寧にこの問題の意図バグ直しを伝えたらやる気が出てきました。どこを直したらいいか口出して考えて、その結果正しく直せているのでよかったです。そして、直したポイントを書き出しておくのもえにし君らしかったです。5問目は悩み止まっていたので、セリフの言う秒数を短くして押す押さないのラグをなくそうと一緒に考えたが、秒数のあるセリフのコードに変えればいいだけで終わりにしてしまいました。そのあとはゲームから戻ることがなかったです。', null, '盛り上がり: くじの引き方がまとめてではなく1回1回引いていたので性格が出ているなと感じた'),
  ('7d96fb60-19a6-521d-9486-692f0fdb9567', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-12', '16:30:00', null, '通常 / 単元別演習Dメッセージを通して今までの内容を復習', 'くじ用の問題は1問目はそのままセリフに「プログラミング教育」書き込んでいたので、低学年なのでそこから考えさせるのではなく、正解を見せて新たに「と」のコードが使えると教えてあげました。最後の5問目のスペースキーを押す押さないでは考え悩んでいたので、セリフを言うコードはほかにもあったよね～から秒数短くするとどうなると誘導していき完成できました。最後に自分がそのコードを説明した後にもう一度ヒロト君自身の言葉でその内容を確認していたので、その学びの姿勢は良かったです。 単元別演習では前半つかれたのもあったが、ゆっくりと着実にコードは正確に組めていました。メッセージのやり取りも迷うことはなかったです。D-2まで終わりました。', null, '盛り上がり: 参加証のお菓子選びは楽しそうでした。'),
  ('b3c5b15c-9072-50c4-b598-67faff3f25e6', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-12', '18:40:00', null, '通常 / くじびきのチャンレンジ問題６問行う', '最初の５問目までは、かなりスラスラ解けていました。（５問目はみんなそうでしたが簡単すぎるため、難しく考えすぎて詰まっていましたが・・・） チャレンジ問題の変数の使い方は、あまりまだ変数を使うことに慣れていないので、一緒に考えて行いました。謎かけのようなものなので、阿弥陀籤のように図を書いて説明し、最後自分でもう一つ変数を〜にするというのも足さないといけないんだと気がついた時の嬉しさが伝わってきました。', '次回は最後なので、自由作品でもいいかも・・', '盛り上がり: 変数の部分は完全に頭を柔らかくする、なぞなぞの問題と同じなのでその部分をどう考える、頭を柔らかくしながら考えるだったので、解けた時の嬉しさがとても伝わりました。'),
  ('8225277e-5d6c-5cac-922e-c9a824fe9c13', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-12', '16:30:00', null, '通常 / 単元別演習E演算の問題すべて 計算式がない使い方、割とはるちゃんは演算んのりんごとバナナという演算を使ったことはあるものの、きちんと使えることを確認', '①チャレンジ問題までは止まることはあるものの、自力で解くことができました。 チャレンジ問題に関しては、ジャンプ変数をいっぺんに数字を変える等速の部分をあまりやっていなかったので、難しそうではありましたがヒントを少し渡し、自力で&説明までしてくれました。 ②逆にいままで難しい問題をやりすぎていたためかシンプルなコードの動きを忘れてしまっている様子。E-1で止まってしまっていて、シンプルな動きに戻してあげるのが、今後の課題かも。', null, '盛り上がり: 攻略することは好きみたいでした。問題もスラスラととき自信がでていた様子でした。'),
  ('552c94ed-c704-5c5b-a245-ce1f1d1ba56c', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-12', '16:30:00', null, '通常 / 単元別演習G演算の問題すべて 演算の計算式', '①くじびき用の問題すべて、ちゃんと自分で答えられました！特に、最後のチャレンジ胃問題に関しては、時間は多少かかりましたが、ヒントをスイッチの保管と同じ考えだよと話しただけで、解くことができました。 ②演算問題に関しては、ジャンプの部分は多少怪しいものの（＜不等号を使う部分が）それ以外４問目の問題まではすんなりできました。次回５問目、６問目、多少難しい部分に入っていますが、おうすけくんだったら問題ないと思います。', null, '盛り上がり: 問題を解くこと自体が今日は楽しかった様子です。色々考えて試行錯誤し、習ったことをきちんと使えることへの自信がついてきているように思いました。'),
  ('6bfe2741-b4c8-53b2-91e7-ffa0a18f2c70', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'bb96307d-f71d-5a14-a63c-4cc0b3646d36', '2022-12-10', null, null, '通常 / スコア以外にも変数を利用する', '最初はチーズを探せ(迷路)の続きを作りました。変数でスコアをつけるのがまだだったのですが、変数の初期化から増やしていくところまできちんと作成することができました。 後半はサメから逃げろを作りました。今まで変数はスコアに使うことが多かったのですが、今回はタイムを数えるのに使い、新しい変数の使い方を学んでもらいました。タイムを数えるのは1秒待ってタイムを1増やすことの繰り返しだということを理解してもらえたと思います。 全体的に、使うべき「ずっと」ブロックを忘れていることが多かったので、それがないと旗を押した瞬間しか動かないということを説明しました。', null, '時間帯: その他
タイピング: か行、さ行の練習をしました。ほとんどミスタイプなく打つことができています。
盛り上がり: 作ったゲームがちゃんと動いたときは特にうれしそうでした。ゆうきくんのお母さん曰く、ここでやるプログラミングが楽しすぎてお迎えに来てほしくないと言うことがあるそうです。'),
  ('191a15b8-e617-562c-8281-b10aa294c8de', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-09', '18:40:00', null, '通常 / 【Prg】19 100m走ゲームを作る(コードをよく読む/復習) コードモンキー75～', '00ｍ走：オリジナルを確認しながら丁寧にプログラムできていました。プレイヤーの速さが固定されていたので、見本でのプレイヤーの速さのコントロールについて、変数が使われていることを一緒に確認しました。最後にプログラムが止めるために考えてくれましたが、うまくプログラムが止まりませんでした。見本をもとに一緒に考え、納得してくれましたが、作ったものがうまくいかない理由がはっきりしませんでした。 コードモンキー/～83まで：関数について学習しました。関数をいろいろな方角から説明（算数の計算やスクラッチのブロックの観点から）しました。本人的には「ぼんやり分かった」そうです。最初は詰まりましたが、レベル77以降はしっかり考えながらほぼ自力で進めることができました。引数も出てきたので、次回以降よく確認しながら進めたいです。コードモンキーは次回84から進めたいです。', 'コードモンキーLv84から進めます！', 'タイピング: 集中して取り組めていました！
盛り上がり: よく集中して取り組めていました！'),
  ('88914341-86fb-553c-acbe-db593d1f96c3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-09', '17:30:00', null, '通常 / 前回の復習→すらぼーすくい（オリジナルゲーム）', '前回作った単元別演習の復習をしてもらいました。その後、レースゲームに進む予定でしたが、本人の強い希望でスラボーすくいを作ることになりました。 前回から作っていたものを見直し、ゲーム内容をもっと簡単なものにしました。ここ1ヶ月ほど私がかなり突っ込んでゲーム内容を聞いたり、そのブロックを選ぶ理由を聞いたりしてきましたが、今日は自分でよく考えてプログラムすることが出来ていました。「もし」の使い方や変数の使い方で少し躓くこともありましたが、投げ出すことなく積極的に取り組むことができていました！！！すごい！！！ 「ではないまで待つ」を使って、ゲームをよりよく改善することができていました。復習もしっかりできて良かったです。', null, 'タイピング: 15分ほど何回も取り組んでいました！目安の級がだんだん上がっていくのが嬉しかったようです。
盛り上がり: 自分の満足のいく作品になったようです！ここ最近で一番楽しそうでした。'),
  ('4c6fb0dc-df06-540a-b282-7a4acf0c7218', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-09', '17:30:00', null, '通常 / チュートリアルの「サメから逃げろ」を行って、キーを今度はマウスに変更してみるところまで（マウスは写経：参考ゲーム「腹ペコザメからにげろゲーム」）', 'サメから逃げろ：以前にやった時はあまりにも集中力が欠けていたので実際本人もやっていたことを忘れていたぐらい→もう一度最初から作り直し。 そのあと、参考ゲーム「腹ペコザメからにげろゲーム」からマウスに向かう、プレイヤーに向かうなどのコードを写経しながらコードを読み込むことをしました。 基本的な動きのコードは段々と理解し、次のフェーズは座標をさらに使いこなせるようになることかなと思いました。', null, 'タイピング: 今日は一番長くタイピングしていたように思いました。ホームポジションの部分からうでだめしで「かんたん」を選び、おおよそ２〜３文字のタイピングが80%ぐらいは解けていたようです。
盛り上がり: 写経をしている際、チュートリアルの追跡よりもさらに面白くなっていることが嬉しそうにしていました！'),
  ('8a11769e-9aba-58fa-8d6c-ee6f0de6e722', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-09', '17:30:00', null, '通常 / 単元別演習F１〜５までできるところまで行う→条件分岐を用いた時に動きのコードの順番を感覚値でやっているのをもう少し理解しながら、やってほしい', '集中がどうしても自分が好きな方向へ向きやすく、できたのが２までしかできませんでした。 ただ、１と２は彼にとってはとても簡単だったようで基本的な部分はできているなという手応えがありました。もう一度来週５（レースゲームと同じ内容の部分）をやって、違う単元に移った方がいいかもしれません。', null, 'タイピング: 1回だけ行った様子で、あまり早くタイピングするのが好きではないみたいです
盛り上がり: 単元２の問題でスライムを可愛くアレンジし、本当のゲームっぽい感じに似せていたのが今日の良きポイントだったなと思いました！'),
  ('2395765b-cab9-589d-9a12-5f0fb0183221', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-09', '16:30:00', null, '通常 / 変数のスイッチとしての切り替え（条件分岐）→バレーボールキャッチ（https://app.arspark.jp/contents/6253）', '最初に変数で０でこんにちは、１でこんばんはの切り替え機能を行いました。 今回はとても変数の使い方を自分で考えながら、ちゃんと変数の役割というのを機能させていたようにおもいます。（変数はかならず”何か”の数字の箱が一定にあって、その数字が変わる時に演算を使いながら切り替えるということ） そのあと、バレーボールで、「向きが０と１で判定する」ということを伝え、腕の向きを変えてもらいました。 →この部分は今日はとてもできていたので変数はある程度条件分岐と合わせて使えるようになりつつあるかなと思います。 ただし、ボールが跳ね返る動きを考えた時に、どのゲームと同じだったか？がすぐには出てこず、動きを昔の自分が作った作品から出してきてしまったため、跳ね返ったあとの動きを自分で考えられない＝角度、座標を使う、歩動かすなど なのでできれば毎回過去の作品からもってくるというのをさせないように、した方がいいのかなと思います。', null, 'タイピング: なし
盛り上がり: 条件分岐の部分で、いつもより理解がスムーズで最初の作ったコードの間違いやこっちだ！と修正する力がとても良くついてきたと思います！'),
  ('afef76bd-f555-583f-b494-5732cfe5e291', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, null, '2022-12-09', '18:40:00', null, '休み（未対象）', null, null, null),
  ('8610eaab-f940-5f6f-a079-d9fa9d2b9fc5', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2022-12-09', '16:30:00', null, '休み（未対象）', null, null, null),
  ('cea3409f-41e8-57ab-8980-2565282a3b7c', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-09', '17:30:00', null, '通常 / レースゲームを通してスキルを磨こう', 'まで待つと準位付けのコードの確認のためにレースゲームを作りました。最初に対戦したときは、ゆきちゃんと5分5分の戦いをしていました、コードを作り始めると、悩む暇もなく順当に長押し防止のコードを作っていき、この動きはすでに理解を持っていると見受けられた。順位付けのコードではウサギと鳥のx座標で比べて、演算で条件分岐をしていたので、付く前に道中でも準位の変数が変化しているのは面白いと感じました。承太郎君的には既存のゲームからアレンジを作るよりからはそれを活かして一から作る方がしたいそうです。 レースゲームは20分と早く作り終えたので、次にカーレースを作りました。ライン上を進むだけの条件を付けて自由に作らせました。参考に下迫が作ったものを見せたら、それ作りたいといったのでそれを作っていきました。悩んでいたので画面を見せながら、少しずつヒントを与えていき、それに近しいコードが作れていました。次回は自分が作ったコードはムズかしいかもしれないのでその続きをやるか連打を使った自由なモノを作るのもいいと思います。', null, 'タイピング: 前回よりもスコアが伸びていました。'),
  ('249007c2-556f-5dee-bdaf-75d1ff2d7b11', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-08', '16:30:00', null, '通常 / ドリル1 スプライトを動かす 角度や向きの復習', 'タイピングの後にゲームをいくつか勧めましたが、「今日は学校では調子がよかったのに、一度寝たら全部だめになった。今日は絶対勝てない日だから、勝ち負けが出るゲームはしたくない」としょんぼりしていたので、気分を変えるためにしばらく雑談し、学校でのさつまいも堀りの話になったら少しずつ言葉数が増えてきたため、「いもほりゲームを作ろうか」と提案したらようやく乗り気になってくれました。 さつまいものスプライトを自作する頃には、だいぶいつもの調子を取り戻したため、さつまいも、畑、芋を掘る手のスプライトを自作して並べたところで時間になりました。', '時間内にいくつさつまいもを掘れるか、というゲームにしたいとのことで、こちらを完成してから次の課題に進みたいです。', 'タイピング: 前回できていたのが、寝起きで思うような得点が取れなくて、泣きながら5回くらいタイピング検定にチャレンジしていました。 A判定が出るくらいの結果は出ていたのですが、ランキングが4000番台しか出せなかったのが相当悔しかったようで、1度やるたびにフードを目深にかぶって顔を隠しながら泣いてました…。 他のゲームをしようとすすめても、もう少し頑張ると繰り返すところは偉かったと思います。
盛り上がり: タイピングの得点が伸びなかったのがよほど悔しかったようで、結果を見るたびに泣いていましたが、さつまいもゲーム作りで気分を切り替えることができました。 お母さんも心配していたようですが、最後は元気に挨拶して帰っていきました。'),
  ('17b4f34b-490b-5a6d-b8cb-c90e8a4812ad', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-08', '16:30:00', null, '通常 / リストの使い方の応用', '自由作成の希望は特になかったので、前回のリストのクイズを振り返った後、おばけのかくれんぼに入りました。スプライトを変えたり、見つかった時のアクションをアレンジしたりして、それなりに楽しそうに作成していました。 リストとx座標との関係なども、口頭で説明できていました。 時間が15分ほど余ったので単元別演習F-1をやってもらいましたが、スムーズにできていました。', null, 'タイピング: 淡々とやっています。
盛り上がり: 自分でひっそりと面白いセリフや音を設定しては、少し楽しそうにしていました。 そうたろうくんの話に反応したり、ローマ字表をとってあげたりと、お兄さんらしい態度も見せてくれていました。'),
  ('06447621-8102-5c32-b26c-c22bb96aa177', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-03', null, null, '通常 / コード探求【ではないまで待つ】 レース順位ゲーム', 'ゲームの仕様は数回遊んですぐにわかったようで、アルくんのカウントダウンや動物の動きなどは、あっという間に作成していました。 さすがに、キーを押しっぱなしでは動かないようにするのは難しかったようで、「ではないまで待つ」を使う、というヒントを与えましたが、しばらく考えてギブアップしていました。 該当箇所のコードを一緒に見て説明をしたところ納得したようで、写経ではなくある程度コードを覚えた上で自分の作品にコードを加えていました。 順位等、上記以外の箇所は自力でできていました。', '検定用の練習問題を渡してあるので、答え合わせができるとよいです。', '時間帯: その他
タイピング: 楽しそうに練習しています。 英文A、和文A中学生、和文B高校生の部門を希望とのこと。
盛り上がり: 新しいコードを使いこなせるようになるのが楽しそうでした。 全部自力でできてしまうようでは、ちひろくんには物足りなくなってくるかとも思うので、毎回何か一つでも新しいスキルを覚えてもらうようにすると、本人のモチベーションが保てるかも…。 タイピングもやる気になって、年齢以上のものもチャレンジしたいと言っていました。'),
  ('d0ebc99a-bf5b-5fc0-be03-9fb20a037267', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-08', '17:30:00', null, '通常', 'レースゲームの作成中に、使っているブロックは正しいが順番を間違えているところがあったので、どういう順番で動くとよいのか考えてもらいました。 上記の記述のように長押し防止のコードができました。次の順位付けのコードでは片方がゴールについたら変数で1つ増やしたらいいという認識を自ら持てていたので順当に作り上げることができました。 レースゲームがものの20分で作り上げてしまったので、次にカーレースのゲームを作りました。ライン上に進むという条件で、進み方を特にしてせず自由に作ってもらいました。2つのキーを使って左右に回転するようにするアレンジをしていました。カーブで調節するのが面白いと感じました。次回は、コースアウトしたら減速したり、スタート地点に戻ったりするアレンジを加えてもいいと思う。', null, null),
  ('23df9c5f-0aba-51e1-b023-bf2ea0afa804', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-12-08', '17:30:00', null, '通常 / 自由作品', 'アニメーションを作成しました。ネコにボールが当たると同時にモーションを出したり、隠し要素としてリンゴを用意したりしていました。最後は今日の作品をみんなに発表してくれました。', null, '盛り上がり: 作っているものがある程度完成するまでは誰にも見せないでおいて楽しみにしてほしいという気持ちが強いようです。'),
  ('639d9526-2554-5ef0-89be-bf379574dc72', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-12-03', null, null, '通常 / ゲームを作ることを楽しむ、ゲームの動きを読み取る', 'ゲームの見本をプレイさせたところ、どういうゲームだったか口頭で説明を始めてくれたので、そのまま細分化をしてみました。 ゲーム好きだけあって細かい動きによく着目できていて、壁に当たった時も「反対側に後ろ向きに下がっている」と表現していました。 当初は前に進む歩数よりも壁に当たったときのマイナスの歩数の方が少なかったため、うまく跳ね返らなかったことが解決できたとき、とても感心していました。 チーズ（地球）の出現場所を「どこかの場所」、ゆうれい（おばけ）の出現場所を乱数にして、それぞれの違いも確認できていました。乱数に入れる座標の数値も、自分でスプライトを動かして確認して入力していました。 敵の動きも、乱数を使わないと思うように動かないことをしっかり確認してから乱数を加えていったため、なぜこのブロックを使うのかということも納得できていたと思います。', 'スコアが増えるようにするのと、ゆうれいに触れた時の動き、クリア画面などを作成する予定です。', '時間帯: その他
タイピング: まじめに取り組んでいました。
盛り上がり: ゲームを作る、ということがとても楽しかったようで、長くなる条件分岐のコードも乱数のところも、こちらの説明を聞いたらすぐに「自分でやってみる」と試して納得していました。終始楽しそうに取り組んでいました！'),
  ('4ee0edfa-a520-581f-9572-98f57ee4f100', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-26', null, null, '通常 / コード作成に慣れる サメから逃げろ', 'どういうゲームなのかはわりとスムーズに理解できたようでした。 「表示する」「かくす」のタイミングを、実際にブロックを動かしながら自分で確かめて、位置を決定できていました。', null, '時間帯: その他
盛り上がり: 一つの作品に集中できる時間は、日によって異なり、途中で他の子の作品が気になって立ち歩くこともありますが、自分の作成中はこちらの話も聞いて楽しそうに作成できていました。'),
  ('7973d513-6e9f-5107-be6c-8986ba0ba206', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '4fdbc8ec-a662-5a7b-8ed9-0dc72bc4fc1e', '2022-11-26', null, null, '通常 / 繰り返しの理解、乱数に慣れる 337拍子、さいころ', '繰り返しの使い方は大丈夫そうでした。 学芸会の後だったせいか、いつもよりお疲れモードでしたが、サイコロにおける乱数の使い方はわかったようでした。', null, '時間帯: その他
盛り上がり: いつもより疲れていたところに、ゆうきくんの好きなゲーム性やストーリー性が少ない教材だったからか、少しだるそうではありました。 それでも投げ出さずに予定していた課題をやりきったところは、頑張ったと思います。'),
  ('f8302c90-a238-5587-8d05-533e862eedf4', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-06', '17:30:00', null, 'レースゲームで、「ではないまで待つ」と「順位の付け方」をマスター', 'みんなでレースゲーム（連打勝負）をした後（盛り上がらなかったですが、、、）、レースゲームの素材だけで、書かれたヒントだけで自力でどこまでできるかやってみて～と促したところ。主に２ヶ所でつっかっかりヒントを求めてきました。 １）キーをずっと押していると進んでしまう →「ではないまで待つ」というブロック覚えてる？という問いかけだけで、すぐに気づき修正できました。 ２）順位をどう表示させるか？ →何度も見本のゲームをやって、キーを一つ一つ押しながら動作を確認していました。 →最初、「順位＝１なら１位と言い、順位を１づつ変える」という惜しいコードを考えました。それによって、全員２位になるという現象が起き、それを検証する過程がとてもいい試行錯誤になりました。 →最後は、正解を手順でヒントを出しをしたところ、自力で実装できました。', null, 'タイピング: 自分で好んでやっている？ようで。他の子の準備をしていたら、寿司タイピングを黙々とやっていたので、そのままにしました。好きみたい。
盛り上がり: 確認しながら、考えながら取り組んでいました。見本のゲームで動作を何度も確認している姿はプロっぽかったです。 とにかくゲームやるのが好きなんだよね～、課題が終わったら「アレンジはいいや、ゲームやる」と。ゲームやりたいモチベーションで課題を早く終わらせるというパターンのようですが。それはそれで、いいね(^^)v'),
  ('d1cc777f-4cb5-52cd-b179-6e02088bbe72', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-06', '17:30:00', null, '通常 / 「〇〇ではないまで待つ」のコードの使い方をマスターする', '最初に、みんなでレースゲームをやり、連打ゲームを作るという話をしたところ、ちょっと嬉しそうでした。「これできるの～！」と。 「もし〇〇なら」で動かすことは自力で作成できました。 ただ、「〇〇ではない」のブロックの使い方がわからず、そこは見本をみて実施。 次に、クマのスピードが速いので「乱数」を使っていろいろなスピードがでるようにしては？というお題を出したところ。乱数を忘れておりました、、、、( ;∀;) さらに「クマのスピード」が表示されるようにしよう！というお題で、「変数」と「乱数」の組み合わせに苦戦しました。ヒントをかなり出しましたが、理解しながら作ることができました。', '今まで、「変数」はスコアでしか使ったことがなかった。今回、変数と乱数を組み合わせたの使い方をはじめてやってみて「なんとなくわかった」とのこと。連続して、変数と乱数のいろいろなパターンに取り組むといいかな。', 'タイピング: 毎日タイピング 第 I 類 文字入力 第５部和文Ａ（小学生低学） を練習してみた。 ひらがなのみで、変換しない方法を知らず、つい漢字変換してしまいスコアゼロでした。 ただ、タイピングはある程度できるので、次回、漢字入力のレベルで実施。 本人は毎日タイピングはやりたいそうです。 （不合格がない、級判定と言ったら、じゃあやると((´∀｀)
盛り上がり: ゲームらしい動きのものを作ったのと、レベルの高いコードというイメージがあり、意欲的でした。'),
  ('639882a0-d523-5ce2-a55f-08f5f788edf3', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-06', '17:30:00', null, '通常 / 世界を創造しよう（知ってることもきっと多いので復習を兼ねて）', '01：「見た目」にありそうなことは自分で気が付いてくれました。秒数の欄に大きな値を入れて遊んでいました！ 02：「スペースキー」を押したときにプログラムが動くことを強調して説明しました。「どこかの場所へいく」は自分で考えられていました。秒数でコントロールすることを提案しました。大きな値を入れすぎていたのですが、かずとくんの提案により10秒で挙動を確認することができました。 03：キーが押されたときにプログラムが動くことに注目してもらいました。座標ではなく、向きと歩数でプログラムしてもらいました。角度はまだ慣れていないようです。背景・スプライトをオリジナルにしてコスチュームが変わるプログラムも追加しました。とても楽しそうでした。', null, 'タイピング: 集中して進めました！！タイピングは嫌いではないようです。
盛り上がり: 棒人間がちょこちょこ動くのが好きみたいです（YouTubeでそんな感じの動画をよく見るそうです）'),
  ('f180d679-9ba3-5c6a-8abb-aaf066d43354', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-06', '17:30:00', null, '通常 / 迷路チーズ①動きのみ ねずみの動き、チーズの動き（ここで乱数使う）のみプログラムを作りたい ポイントは「壁をつっきれない」', 'ねずみの動きを一緒に復習しながら作りました。歩くときは「向きたい方向を向いてから前に進む」ということを確認すると、角度のブロック・〇歩すすむのブロックを持ってくることができました。角度はまだ定着していないようです。壁に当たったときの動作については、「壁に当たったなら」の部分を自分で色判定にすることを考えられていました。すごい！見本を見せて壁にぶつかったときにネズミがわずかに後ろに下がっていることを確認してもらい、マイナスを使うことを提案しました。 チーズのプログラムでは「どこかの場所へ行く」を使えていました。枠外にはみ出てしまうことに気が付いたので、乱数を風習しつつ座標でコントロールしました。座標の理解があまり進んでいなかったので時間がかかり、乱数の説明まで行きつきませんでした。一通りプログラムして動作を一緒に確認しましたが、まだ説明が必要だと思います！！', 'できればプログラムを復習しつつ乱数の話をしたいです。', 'タイピング: 自由時間にポケテピを進めていました！PlayGramにも問題なく挑戦できています！
盛り上がり: 後半は自分から喋ってくれることも多かったです！'),
  ('927cc6f2-70e7-5b53-956d-3eb1d57365c5', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-06', '16:30:00', null, '休み（未対象） / 体調不良とのこと', null, null, null),
  ('66edd865-953e-5666-b5af-8d355fd91ee9', '9fa414fa-958c-54ca-a3e6-d0d8dc0eae6b', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-06', '16:30:00', null, '休み（未対象） / 体調不良とのこと', null, null, null),
  ('5a7e595d-2dba-5fc2-82de-d8a180fad436', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-05', '17:30:00', null, '通常 / 長押し防止と準位の変数を理解しよう', '長押し防止と準位の変数を理解するためにレースゲームを作りました。最初に、しゅうくんと遊んでもらい、ほとんど勝てなくて悔しがっていました。作り始めると、ゆっくりと考えながら作っていき、長押し防止のコードでは素材のみを渡しても進まなかったのでコードを見せ、理解を伴わせるように作りました。作っている最中はめんどくさいといいつつも、手を止めずに考えを持ったコードの試しを行っていてよかったです。そのような努力はすべては作り終えていないが準位のコードを作っているときに感じました。', null, null),
  ('0bd5c0d6-79c4-5923-b9ce-cae6fcd24b99', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-05', '17:30:00', null, '通常 / レースゲームを振り返り作ろう', 'えにし君と一緒にレースゲームを作っていきました。以前作ってあるので、息良い良く作り始めてたが、まで待つとでないの長押し防止のコードのところが曖昧になっていました。それで、補助のドリルのコードを見ながら作ったが、自分が作ったコードに対して説明してみてと聞いたところ、ノータイムでわからないと返事か帰ってきました。しゅうくんはただ作るだけで理解しないことが多いので、作ったコードに対して理解を持ってもらうように紙に書いて位置から説明してあげました。そのあと、修君に自分の言葉で説明してみてと頼んだところ、説明できていたのでそこは大丈夫だと思います。次に、順位付けのところではなんとなく変数を使うことは覚えていて完全に忘れていました。片方だけゴールさせた状態にして「どこで順位を変えればいい？」と言いながら画面とコードを一緒に進めながら作り上げました。これは多少不安定なところもあるので、次回最初に修君が説明できるように聞いた方がいいと思います。', null, null),
  ('287d6090-35dc-5829-806a-1d223c882707', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-12-05', '18:40:00', null, '通常 / 今まで作ったゲームを参考に100m走を作る', '最初は自力である程度コードが書けていたのですが、マウスを長押ししても動くようになってしまっていました。そこで以前作ったレースゲームを思い出してもらい、マウスをクリックして離すまでが1セットになることを説明しました。すると、多少時間はかかりましたが「～ではないまで待つ」を使うことができました。いい復習になったと思います。また最初に作ったものだとプレイヤーの走る速度が一定だったのですが、元のゲームみたいに加速がつくようにしたいと言って、変数で速度が変わるようにしました。一回戦から準決勝に移る時は、メッセージを送って一回戦のキャラを隠すことができました。', '続き', '盛り上がり: ゲームを作ることを楽しみながらやっています。'),
  ('6a61e571-9e8c-56e3-93e3-28c3c9fe3102', 'ec5baeb0-d065-53b9-a675-d99033f1812e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-05', '16:30:00', null, '通常 / 変数による速さ変化やまで待つを習得しよう', '連打を活かした100ｍ走を作っていきました。最初に、皆でレースゲームで対決し過去に作ったゲームが体験してもらいました。そして、自分で作ったレースゲームを参考にコードを組み始めると、長押し防止のコードはスムーズに作れました。ゴール条件がレースゲームと違っていて悩んでいたので、あまりヒントを与えすぎずに、猫で変化しているものは何？から誘導していき、自ら座標を使って条件が作れることに気づきました。次に、変数を使って連打によって進む速さが変わる仕組みをまずはのーヒントとで作ろうとさせました。だが、悩んでいてあちこちにいじってその作業に進もうとしませんでした。動きと同様に変数の仕組みを作ればいいと理解できて、作れました。余裕があれば、原則の仕組みも作ろうとしたが作りませんでした。ステージ移動も変数条件で分岐できることも把握できてよかったです。', null, '盛り上がり: 思うように進まない場面が少し多くて、木がよく散っていました。'),
  ('b4de6b49-52ea-5546-b9c3-f75dbbb44543', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-05', '18:40:00', null, '通常', '高学年なので、最初に今自分ができる動きをやってもらいました。その上でいくつか動きのコードを作りにはパターンがあるよと話し、どれが一番自分の想像とマッチしているのかを選んで作成してもらいました。 また杖の動きに関しては、大きさを変える（繰り返し）で金魚を釣るというので作成、最後に変数でポイントを増やす部分が、触れたら〜と別に書いていたので、変数のコードをが無限に増える事態に。そこをもう一度教えたら納得していました。', '変数のどれか', 'タイピング: 体験版で行いました。多少難しかった様子。スペースキーに気を取られていたみたいです。 またBの行が苦手だそうでした。
盛り上がり: 自分の作品をひとまず作り切ったという達成感が今日は一番感じられました。 お母さんにも見せて、褒めてもらえることがとても満足していました。'),
  ('ae82b20c-3179-5962-ac83-4ef2b320318a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-05', '16:30:00', null, '通常 / レースゲーム がほぼメイン 一度100m 走をやってみて〜も含めています。', '一度レースゲーム自体はやったことがあるというものの、初回のレースゲームに関しては〜ではないまで待つは使ってないので、それを踏まえながら100mの方で同じコードを入れてみて作成してみました。 この連打の部分は、セットと考えて今後は作るといいよと話したら、理解したようで〜ではないまで待つがないだけで、こんなにゲームが変わることに喜んでいました。', null, 'タイピング: なし
盛り上がり: 変数の使い方に関して、今回はステージが変わるというのも学びました。ちょっとひろとくんいは難しかったみたいではありましたが、文章を構成するのが得意な子なので、順番に、こうなったらこうなる、というヒントをあげるだけで、コードを書くことは出来ました。 理解が早く、素晴らしい！'),
  ('761d5097-2db3-538d-a3e3-320ebb9ee3e1', 'ea0c0f46-be7d-5205-b8ee-f848304a7e15', null, null, '2022-12-05', '17:30:00', null, '休み（未対象）', null, null, null),
  ('0b0d8699-b097-5529-a5b8-3029cbb9db01', '51e2226d-51fc-52c1-afb9-84ab378d517c', null, null, '2022-12-05', '18:40:00', null, '休み（未対象）', null, null, null),
  ('9245eed6-3dd4-5f54-b32c-d60671b37977', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, null, '2022-12-05', '16:30:00', null, '休み（未対象）', null, null, null),
  ('54d00ade-f61c-5e3f-a728-5a0dfb744400', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-02', '16:30:00', null, '通常 / レースゲームをヒントありでどこまでできるか？（初回） 問題は変数の使い方の部分', '〜ではないまで待つの部分に関しては、たっちゃんは初めて習う単元でもあるので、演習問題Fを交えながら、実際にレースゲームを作ってもらうことにしました。 順位の部分で変数を使う場合、どうしてもゴールの風船に変数を１づつ変えるとコードを書いていたので、途中で軌道修正のため「だれが、なにに」の順番で考えてみて〜と話して、実際のプレイヤーが触れたら変数が動くというのに気づいてもらいました。', null, 'タイピング: なし
盛り上がり: 自分で最初から作ってみる！とはなしていて、かわいいキャラクターを使ってゲームを再現。自分なりのこだわりがあることはとても素晴らしいと思います。また、ヒントを出した時に、「小さいなるほど」が本人にもあった様子なので、そういう部分をもっと多くしてあげたいと思います。'),
  ('146d0452-77ea-5db6-a010-ac25c2323803', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-05', '16:30:00', null, '通常 / レースゲームとらくんは、自力でどこまでできるか？ https://app.arspark.jp/projects/23703/editor', '前に動かすことはできるものの、やはり〜ではないまで待つのコードを忘れていた感じ。 ただ、少しだけヒントをあげると実際に自分で作成することができました。 しかし変数で順番を判定するという部分を、メッセージで判断しようとしているので、このままだと変数で順番という概念を表すのができない状態でおわってしまいました。 今、とらくんの頭の中では、 変数＝ジャンプ（もしくは速さ）、得点だけの概念になってしまっているので、順位という箱での使い方を再度おさらいした方がいいかなと思いました。', null, 'タイピング: なし
盛り上がり: 自分なりに、素材を使わずに自分の好きなキャラクターでゲームを作成、背景をペンツールで描いたり自分なりの世界を表すことに楽しみを覚えていたようです。'),
  ('b415a7b3-eb19-5c5e-8534-ffb34621c3ad', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-02', '17:30:00', null, '通常 / レースゲーム→ある程度こちらが誘導してあげる【単元別演習】F条件分岐をやってから', '最初にみんなで遊んだのがよかったのか、ある程度集中して行なっていたように思います。最初に単元別Fを見せてから、これとほぼ同じだよ〜、連打の意味はこのコードで書いているよ〜と話しながら作成。意外にちゃんと自分で考えて、風船に当たったらちゃんと止まるなどコード自体を覚えていました。', null, 'タイピング: なし
盛り上がり: 遊んだのがきっかけになったか、とてもゲームを作るぞ！という意欲につながっていました。その後に時間が多少余ったので、自分でお絵描きしたいとのことで「ドット絵」でマイクラを描いていました。今日は1時間みっちり、ちゃんとコードの順番もこれがこう動くんだよと話しながら学習していたので、今までの写経も意味があるものだったのかなと思います。'),
  ('0bf702bf-1545-53ec-8f52-a8723bdf1695', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-02', '18:40:00', null, '通常 / レースゲーム（https://app.arspark.jp/contents/24442）を新規で作成、連打しないとキーが操作できないのをどう克服するか？', 'さすが高学年&週２きていることもあってか、変数の使い方はとても慣れてきています、 レースゲームを行なっている時は、連打の部分だけわからなかったぐらいで、その他はヒントなしで、すらすらとコードを入力。 だるまさんがころんだ、も同じ考え方だったので、動きに関してはほぼ問題ナシ。 ここで判定ですが、向きの部分でコスチュームで判定ではなく90度の向きで判定すると最初は答えていました。もちろんそれでも正解だけどコスチュームでというのもあるよと話し、正解が２つある、もしくはそれ以上あるということを学んでいました。', null, 'タイピング: 100/122 正答率18%に上がってきました。
盛り上がり: 連打の部分ですが、どの並びで入れるか？に悩んでいました。ただ、ヒントを与えると「なるほど、そっか！キーを打ってるから、ここに入れないといけないんだね」と言っていたので、次回も楽しみです。'),
  ('35df8b40-04d9-5092-a1f8-9953584f65c2', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-12-01', '17:30:00', null, '通常 / レースゲームの作成、「～まで待つ」の活用', 'キーが押されたらキャラクターが動くようにするときに「もし～キーが押されたら」を使っていましたが、それだと長押しでも動くようになってしまうことに気付いたので、「～まで待つ」を使った方法を伝えるときちんと直すことができました。変数を使って順位を表示するところは自力で作れて、ゲームとして一通り完成することができました。', null, null),
  ('09cad873-8a54-5096-b979-0d8f207986b4', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-12-01', '17:30:00', null, '通常 / レースゲームを作る', 'レッスン時間の最初のほうもゲームを遊んでいるのはいつものことなのですが、今日はずっと渋り続けてしまいコードは少ししか書けませんでした。興味をもってもらえるように説得を試みたものの「めんどくさい」「先生がやってよ」などと言い、ゲームを遊び続けてしまいました。まさきくんがいつもやっている自由創作ではなくみんなと同じ内容に取り組ませようとしたからかもしれません。少しだけ書いたコードは、自由作品でよく使っている「ずっとどこかへ行く」です。', null, null),
  ('9a6b01be-cbc9-52df-bd63-c003f85abb8f', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-02', '18:40:00', null, '通常 / レースゲーム復習', '＜レースゲーム＞動物の動かし方はバッチリでした。キーの押された（離された）タイミングと、動物が動くタイミングに注目してもらい、細かい部分まで気が付くことができました。順位のつけ方は苦戦しました。「1位にする」という意識が根強かったので、、変数はスプライト間で共通なこと、ゴールした順に順位が増えていくことを伝えました。変数に1足すプログラムがとてもスマートで良かったです。 ＜コードモンキー＞関数で躓いているようだったので、少し戻ることにしました。70~74まではfor文がメインでした。for文を使うことは出来ていましたが、その使い方はまだ定着していないようです。本人の問題の考え方がポイントかなと思います。次回は75から続きをやりたいそうです。', 'コードモンキーLv75から進めたいようです！！', 'タイピング: 小学校高学年モードに挑戦してもらいました。丁寧に取り組めていました。
盛り上がり: 集中して取り組めていました！'),
  ('cd04afb8-8017-5026-b74b-f2670d7ad46b', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-02', '17:30:00', null, '通常 / 単元別演習・レースゲーム（～まで待つ）', '何をすればいいのかが分からず、手が止まっていました。やらなければいけないことを話しながら整理し、ひとつずつ進めました。 表現したい事象を自分の言葉で説明できていましたが、プログラムの言葉で整理するのが難しそうでした。「～ではない」と「～まで待つ」を組み合わせてプログラムすることを提案しましたが、あまり理解できていない様子でした。クマの動きにもかなり苦戦していました。見本は何回も見せたのですが、見本の動きも納得できていない様子でした。最後はずっと進み続けてしまうことに気がつき、「～まで繰り返す」を使って工夫していました。メッセージの送るタイミングを考慮せず、クマの初期位置もうまく決められていなかったので残念でした。作品は完成しました。', null, 'タイピング: 集中して取り組めていました！
盛り上がり: すんなりタイピングから始められていて素晴らしかったです！！'),
  ('fcf1509b-44b9-574c-bc10-21ddcb379d97', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-12-02', '17:30:00', null, '通常 / レースゲーム（～まで待つのブロック、順位のプログラム）', '＜F条件分岐＞押しすると猫が動き続けてしまうプログラムの欠陥に気づいてくれたので、「まで待つ」「ではない」のブロックを使うことを提案しました。うまくそれらを組み合わせて作れたようです。熊の動きはスムーズにプログラムできていました。 ＜レースゲーム＞メッセージの送られ方をきちんと把握してプログラムすることができていました。動くタイミング（キーが押されたときに動くのか、話されたときなのか）は自分がつくったものと見本を比較して、キーが離されたときに10歩動くことに気づいてもらいました。順位のプログラムは難しかったようです。あまり理解できていない様子なようです。作品は完成したようです。', null, 'タイピング: ミス率がとても小さく、集中して取り組めていました！！
盛り上がり: 後半はかなり疲れた様子でした。'),
  ('0b04106f-2764-580d-95b4-86d906c94c28', '13bd73d0-f535-5291-8362-6712e5cd7384', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-02', '16:30:00', null, '通常 / レースゲーム（https://app.arspark.jp/projects/4256/editor/）', 'うさぎとオオハシの動き自体に関しては問題なく、条件分岐のコードを使って書くことができました。本人にとっては初めて連打のコードを習ったので、その連打のコードをどの順番で入れるのか？が悩んでいたようでした。 また判定の部分で変数の順位の理解が、まだやってなかったので完璧ではなかったみたいなので、次回変数の使い方やルールをやった方がいいかもしれません。', null, 'タイピング: なし
盛り上がり: 動きに関してはサクサク自分で解けていましたので、自信がある面持ちでチャレンジしてくれていました。クラスが終わった後に、前にやった単元を利用して迷路ゲームを自作したものを見せてくれました。→ちゃんと復習することができていてすばらしい！'),
  ('42c33a70-d36d-5971-b148-ca6534beef29', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-02', '17:30:00', null, '通常 / https://app.arspark.jp/projects/4256/editor/', '動きまでに関しては、概ね覚えていた様子でしたが、やはり〜押されたならないまで待つというコードの存在自体は忘れていた様子でした。ただ、ヒントを出すと「あ〜それか！」と思い出した様子だったので、動きの部分に関しては問題なさそうです。 ただ変数の使い方で、そもそも変数の使い方ルールがあやふやみたいなので、もう少ししっかり目、何度か繰り返し変数を使いこなせるようにしてあげたいと思います、', null, 'タイピング: うでだめしをして、だいぶタイピング早く打てていた様子でした。'),
  ('6367357e-b06f-5c9f-866c-2c97417f4fae', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-12-02', '16:30:00', null, '通常 / レースゲーム（https://app.arspark.jp/projects/4256/editor/）', '最初にみんなで連打ゲームをやろうということにして、競争させてからレースゲームを作るにしました。 順番に動作から、キーを連続して押したらどうなるか？など確認しながらやってもらい、ヒントとしてキーが押されたらないまで待つのコードを使うとずっと押しても動かないようにするへとコードを書いてもらいました、 押されたならないまで待つまでは、自分のちからですべてコードを書くことができていました。条件分岐でちゃんと使うことを理解していた様子。 風船に当たったら、という部分の使い方が変数になるので難しいですが、ここはまだやってない単元の部分なので、次回ピンポンをやりながら変数の使い方ルールを教えていきたいと思います。', null, 'タイピング: なし
盛り上がり: 連打ってこういうふうにコードを書くんだ！とわかった時に、なるほど！と理解していた様子で、とてもゲームを作成すること自体が楽しくしていた様子でした。'),
  ('f63541bf-12ec-5519-a6af-4a2c1dd2eba8', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-12-01', '17:30:00', null, '休み', null, null, '備考: 振替対象'),
  ('60773028-19c4-5fb2-a6e0-267db9ae5f5c', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-01', '17:30:00', null, '休み', null, null, '備考: 振替対象'),
  ('865721e6-0732-5d9b-8976-3e03ae76135f', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'e6677eef-384f-5c4c-a46d-9ad0d4c055ab', '2022-11-25', '16:30:00', null, '休み', null, null, '備考: 振替対象'),
  ('73a8bfeb-1ca6-5a86-a793-3d30793d8035', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'e6677eef-384f-5c4c-a46d-9ad0d4c055ab', '2022-11-21', '18:40:00', null, '休み', null, null, '備考: 振替対象 ⇒11/22に振り替え'),
  ('82e7caa9-5ed6-583e-8e32-cf8710965491', 'e17fbd99-e7bb-5a30-b401-9db822e69cec', null, 'e6677eef-384f-5c4c-a46d-9ad0d4c055ab', '2022-11-21', '18:40:00', null, '休み', null, null, '備考: 振替対象です。'),
  ('67f5b494-a3b5-5740-8de7-5d192ba36236', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-01', '16:30:00', null, '休み', null, null, '備考: 下校途中にけがしたとあり ⇒振替対象ではありません'),
  ('3b8e5b60-e8a2-5e3a-ab57-7ba1fd75ae3f', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-12-01', '17:30:00', null, '通常 / まで待つと細分化に理解して使おう', 'まで待つと細分化の練習のためにレースゲームを作りました。最初に3人でと手も熱中して遊んでもらいました。次に細分化を取り組んでもらうと、各スプライトごとの動きがほぼ正確にとらえることができていました。ただ、ウサギなどの動作「がキーを押したら」だけと簡素な説明だけの条件になっていたので、「長押しはできない」ことを強調できるように補助しました。コードを作り始めると、長押し防止のための「ではない」と「まで待つ」をすぐ持ってこれていました。作り方は知識として知らなかったが、その場考えでたそうでセンスが良かったです。順位の変数は最後までバグが残ったが、大方全てスムーズに作り上げることができました。その後、アレンジとして、変数でゴールまでの距離を百分率で表したいというアイデアが発想が面白くてよいと思いました。けど、表現の仕方に悩んでいたので、座標を使ってみたらと助言したり、演算方法に悩んでいた時は簡単で数字に直して変数の計算をわかりやすくしたり手助けしました。結果的にうまくできたのでよいクォリティーなものが完成しました。', null, 'タイピング: 学校のパソコンとキーボードが違うみたいで苦戦していた。
盛り上がり: なものが完成しました。'),
  ('c59ad12d-b038-5396-98b1-a0fa45af7957', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2022-12-01', '16:30:00', null, '通常 / これまで使ったコードの復習／前回難しいジャンプをやったが、うろ覚えの部分もありそうだったので。基礎の確認', 'ドリルのコンプリートと、前回のジャンプのアレンジ（10mまで進んだらゴールという設定）と、どっちがいい？と聞いたところ、前回のジャンプが「かなり難しかった～」とのことでドリルをチョイス。 難しいコードを覚えてしまったので、複雑に考えてしまう傾向があり。 ブロックを３つだけ取り出し、「これだけを使ってやってみよう」と促したところ。 「〇度まわす」の使い方を忘れてしまったようで、しっかり向きと進むコードを復習しました。「１秒まつ」のコードで全角だったのでカウントされておらず、全角と半角の違いも学びました。', '「ドリルコンプリート」はシートのハンコを埋めるイメージで。かなり基礎だけれど、もう一回振り返ってもいいかも。小さなコードの違いを確認しながら、ゆっくり進むのでよいかね。', 'タイピング: ももたろうタイピングの検定にチャレンジ。タイプミスが少なく、最初にBスコアで再チャレンジするとAスコアに急上したのでヤル気マックスに！ 「も一回、も一回」と結局４回やった。順位800位から315位までアップ！ 文章を打つのは少し時間がかかるものの、アルファベットの位置をだいぶ覚えてスピードアップしています。
盛り上がり: タイピングに自信が少しでたようで、かなり盛り上がりました。 せっかくタイピングを覚えたので、「ファイルの名前も自分でつけよう！」と促すと、喜んで入力表をみながら名前を入力していました。'),
  ('83affc82-2398-577a-97bc-bb758c4aa3b7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2022-11-24', '17:30:00', null, '通常', '★お願いごと★ ↑前回の記録 「条件分岐のドリル」となっていますが、 ⇒正しくは「アルスパーク/単元別演習 F1～3」ですね。 「ドリル」と「単元別演習」は2種類別なので、区別しておいてくださ～い。 また、両方とも「何番を実施したか」を記録するようにお願いしますm(__)m', null, null),
  ('77a6c30c-e721-5536-971e-d95eb4a9b763', '90dcd5c1-f4a7-5da5-8623-220cd9cb625b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-25', '18:40:00', null, '通常 / 変数11：ネスト ある処理の中に同じ処理〜 スイッチが２個だけではなく何個も増えた場合どのようにコードを並べるのか？', '最初に変数の理解から再度おさらい▶︎スイッチでの変数の使い方で２個→３個増えた時に、もし〜でなければを重ねて使用する、それがどの場所にくるとあっているか？コードが重なり合うことで見えにくくなるので、そこを大切にしながら、ネストの使い方を学びました そのあとコードモンキーを８０〜行いました。', null, 'タイピング: 大会には出場する予定▶︎今回は英語のタイピングにチャレンジしてもらいました。本人にも難しかった感じではありましたが、さすがコードモンキーを行なっているためか同じ年代の子達よりかはタイピングできているように感じました。
盛り上がり: ネストの部分では、もし〜でなければが多少使い慣れてないのでもし〜を2回使ってコードを書いていましたが、考え方自体はやはりちゃんと理解ができている感じだなという様子。 コードモンキーに振り返った際にその部分がやはり出てきたので、自分でもやったことの振り返りで楽しく授業していました。'),
  ('dadfc8b0-9a82-510d-8a43-629cc228784d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-25', '17:30:00', null, '通常 / メッセージの役割理解 じゃんけんのキーを押したら手が変化するhttps://app.arspark.jp/contents/4456 スロットマシーンを動画をみて作成する https://app.arspark.jp/projects/4971/editor', 'まずメッセージを送り合うことの意味からはじめてみて、一度チュートリアルを見ながら作成したあとに再度口頭で説明してもらいました→その後に、スロットマシーンをやってもらって、じゃんけんと同じコードを使わないと順番に数字が止まらならいということを説明、動画をみながらやるのは苦じゃない様子でした。', null, 'タイピング: か行までは自分でも練習しているためか、すらすらとタイピングしていました、本人はプレイグラムの方が好きそうなので、今後はそちらで行っていきたいと思います。
盛り上がり: 以前よりも落ち着いた様子でコードの理解をきちんと言葉でしようとしていました。自分でもコードを読める楽しさがわかってきた感じで、ゲームを作る楽しさを今後も深めていけたらと思います。'),
  ('80df259c-2a71-5226-8685-2ea742cba5ce', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-26', '17:30:00', null, '通常 / 変数の使い方⑤-⑥：if 目印の役割 スイッチの中身も切り替え 変数の使い方のスイッチの部分、ハルくんにとって少し難しい単元かもですが、彼にとっては必要なスキル', '０と１で切り替えるということの理解をまずしなくてはいけなかったと反省、そもそもハルくんの中で数字がどうしてスイッチの切り替えの役割を果たしているのかを最初に理解するところから話さないと今回の単元は彼にとって難しいものになってしまった気がしています。 なので、パソコンのスイッチon オフを最初から説明し、PCなど機械系は数字でしか理解できない→だから０と１があることの大切さを話しました。', null, 'タイピング: 練習問題、すぐ終わってしまったので、次回お母さんに聞いて参加しても大丈夫そうであれば大会に出場させてあげたいです。
盛り上がり: 今回の単元は彼にとって難しいものになってしまったものの、自分の作品をつくるという意味では意欲的に行ってくれていました。またスイッチの後の動作に関してがちょっと理解ができてない様子なので次回はそのバグっぽい感じになってしまうことを少し手直ししながら、新しく少し簡単なもので進めていきたいと思います。'),
  ('9945f1a0-9d42-5a0f-9034-8e996cb35966', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-26', '16:30:00', null, '通常 / 先週の振り返りで「だるまさんがころんだ」の判定を、コスチュームで判定できることを教えてあげる→ジャンプ基本操作コース09', '最初に判定の部分で条件分岐を使って表現しようとしていました、もちろんそれでも悪くはないのだけど、もっと短くコードを書けるよと話しテキストを参照。→ここで〜まで待つを「なるほどそういう使い方もあるのか」と再確認していたようでした。', null, 'タイピング: だいぶタイピングにも慣れてきた様子です。ちょっとだけ腕試し（かんたん）をしましたが、正誤率も良くなってきているので、難しいものでも大丈夫かなと思います。
盛り上がり: 条件分岐でできることを自分なりにすらすらとかけることが何よりも素晴らしい！そしてそれが間違いでもなく答えはいくつもあるのか！と理解していることが楽しそうでした。'),
  ('577eca0e-c8ab-5360-bdb5-7f5bf384d68f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-26', null, null, '通常 / ピンポンゲームを作る', '最初ボールが横方向に動いてしまったので、斜めに動かすにはどうすればいいかな？と聞くと初期の角度を変えることができました。また、ボールを壁で跳ね返すときに「端に着いたら跳ね返る」を自分で使えていました。ただ、ボールがバーに当たって反射するときも「端に着いたら跳ね返る」を使おうとしていたので、この場合は当たった時に角度を変えればいいよねと言うと理解して修正できていました。', 'ピンポンゲームの続き', '時間帯: その他
タイピング: 集中してやっていました。
盛り上がり: こうしたら面白いゲームになるよ！などと楽しく話しながら作成を進めていました。'),
  ('d6d914e0-0b88-59fe-9e6e-bf53d64cc4d8', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-26', null, null, '通常 / だるまさんが転んだを作る', '音に関するバグが出たときに、音を出すときは「～を鳴らす」「終わるまで～を鳴らす」の2つの方法があって使い分けが必要なことを説明しました。最初はだるまさん(鬼)が振り返るときに180度回転させる方法をとっていましたが、コスチュームを変えて振り返らせることでコスチューム番号を負けの判定に使えるということを伝えました。また、音のピッチを変えるときに乱数を使い、乱数の用法を一つ増やしました。一通り作り終わるといくつかアレンジを加えていました。オープニング画面を作ったりゲーム難易度を変えられるようにしたりとアイデアが多彩でした。全体として、試行錯誤してコードを直していく姿勢が身についていたと思います。', null, '時間帯: その他
タイピング: かなりすらすらとタイピングできています。
盛り上がり: 自分の考えていること、できたこと、分からないことを積極的に話してくれました。また、レッスン時間が終わってもアレンジを作り続けていてとても楽しそうでした。'),
  ('da789ed9-4684-5d08-ba4c-e88b3d2c0ff7', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-19', null, null, '通常 / チーズ探せ（https://app.arspark.jp/projects/22704/editor）▶︎スタート地点の座標の確認、虫の動きを作る（角度）', 'スタート地点を設置しないとすぐゲームオーバーになってしまうので、座標で最初に指示することの理解。虫の動きを作る際に、角度を用いて動かすことを行いました。邪魔者を作る時に虫の動き自体は角度を用いならができましたが、演算で動きを分けるという部分に関しては写して作成しました。', null, '時間帯: その他
タイピング: 一生懸命頑張ってタイピングを練習していました。
盛り上がり: 幽霊の動きを作る際に自分なりに、角度をつけて動かしたほうがおもしろいと話していたのでそのまま作成▶︎動きがたくさんあるものに関してはとても楽しそうにしていたので、迷路ゲーム、や敵がいる系のゲームなどたくさんやるといいかなと思います。'),
  ('ca3ef980-aee4-589a-bfa9-020eb628a7d7', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2022-11-19', null, null, '通常 / スロットマシーンのゲームで、乱数をコスチュームで入れられることの確認 メッセージの使いどころと受け取りが必要だということの理解▶︎チーズを探せ', 'スロットマシーンはチュートリアルを見ないで作成していたので、判定の部分でメッセージを使う場所ともし使うなら受け取り手が必要なんだよと言うことを話しました。 チーズを探せでは細分化をしてもらった後に、ネズミの動きを壁に当たる判定を考えました。ヒントを伝えるだけで、跳ね返るのは進んだ分だけ戻ればいいというのを理解したようで、一個一個それぞれの左右上下に戻るコードを入れてくれました。', null, '時間帯: その他
タイピング: 英文でもかなりできているので、もし本人が希望すれば受験させてあげても良いかと思います、
盛り上がり: スロットマシーンでメッセージの受け取りや主語が違うだけでも変わることを理解した際に、正解はいくつかあるということを学んだ様子で嬉しそうでした。 またチーズを探せでは、動きのバリエーションを持たせるために色々なコードを組み合わせると楽しくなるということを知ったようでした。'),
  ('d4bf3fee-c828-5525-a1bb-31d7e6cba27b', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-25', '17:30:00', null, '通常 / 鏡・きも目玉・スクロールなどで、プログラミングを楽しむ！', '難しいように思えて混乱していましたが、分かる範囲でプログラムを初めてもらうとなんとなくプログラムが分かったようでした。鏡の部分が透明になっているカラクリにも気づけました。「最背面にする」というアイデアはすぐにでなかったものの隠れている、見えないという言葉はすぐにでてきました。最初の位置もきちんとプログラムできていて良かったです。', null, 'タイピング: すこし文字数が多かったですが、根気強く取り組めていました。
盛り上がり: すこし眠そうでした。'),
  ('218e5d0d-e63b-5fb9-bf3b-979a758a9e5b', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-25', '17:30:00', null, '通常 / 金魚すくいの続き', '金魚すくいの見た目が徐々に変化する部分を作成しました。「2回クリックしたら見た目をかえたい」とのことだったので、クリックする回数を数えるために変数を使うことを提案しました。提案した変数の使い方があまり理解してくれていませんでした。「〇〇変数が2になったら～」の部分も、自分からでてきませんでした。今までやったことが少し忘れているのでしょうか。。心配です。 プログラムを最後まで確認しないことが多かったです。論理関係を把握するのが苦手なようです。 クリック回数を2回にしたり、使うスプライトの数を減らしたりするとプログラムしやすいことをアドバイスしましたが、変更したくないようです。来週も続けたいとのことでした。', null, 'タイピング: とても良い点数が取れたみたいです！張り切って報告してくれました！
盛り上がり: 眠そうでした。'),
  ('833f44c9-c1a6-5ce7-9761-aa787dd84fc5', '145b3905-82be-56ed-aaeb-fdbd157af9d4', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2022-11-25', '18:40:00', null, '通常 / スロットの続き 最後の判定をチュートリアルを見ながら', '最後の判定部分をチュートリアルをみて作製し、その後一緒に確認しました。メッセージを送るタイミングを間違えていたようです。ずっとともしの関係性について注意するようにお願いしました。音を鳴らすときに「最後まで」を忘れがちです。 プログラムがうまく働いていないときに気づいて、自分から確認できるのがとても良い。たくさんのコードを知っているので、使い方がキーだよという話をしました。 【小技】鏡のプログラムを作ってくれました。背景の青い部分がスプライトであるというカラクリを説明すると、最背面、最前面のアイデアがすぐに出てきてよかったです。スムーズにプログラムできていました！', null, 'タイピング: 少しミス率が大きかったですが、集中して取り組めていました。
盛り上がり: 浅川ランするみたいです！2km！！すごい！！！'),
  ('e9620030-1842-5fac-8dc9-8f6c90143581', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-24', '17:30:00', null, '通常 / 条件分岐を復習しよう', '先週まであたし言ことを学んできたので、今日はゆったりと条件分岐のドリルを承太郎君とともにやって行きました。最初の方は承太郎君に少し遅れながらも自力で作ることができました。途中、少し悩んでいたところがあったが、ドリルの文章を読んでいなかっただけでした。分子賞をしっかり読み取ることがまだ少し未熟な感じがします。承太郎君ができてない所を言おうとしたが、ちょっと待ってと止めているところが自力で作る方向に向かったいてよかったです。そのあとのドリルのアレンジでは2人でアイデアを共有しながら作っていたのでよかったと思います。', null, 'タイピング: ミスったら最初からやり直す癖を直してほしい
盛り上がり: 2人でしゃべりながら気を損ねることなくできていた'),
  ('7e6e3f82-c0c0-5924-9e7c-9f5b751ab67f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2022-11-24', '17:30:00', null, '通常 / 条件分岐を復習しよう', '先週まで新しいことを学び続けたので、ゆったりと条件分岐のドリルを行いました。ドリルの内容は承太郎君にしては容易にできるものだったので、文章を読み取り作ることができました。正答例と見比べた時、球を発射するコードのところで、球が元の位置に戻るコードが「へ行く」でなく座標でになっていたので、なぜ正解例の方がいいと思う？と質問して見ました。返答に悩んでしまっていたので、雪だるまに動きをつけると、座標だと雪だるまでまで球がもどってこなくなるよと教えたところ、納得した表情をしていました。そのあとの3つのドリルからどれ１つにアレンジを加えました。上下に動いていてピンポイントにねらって打つゲームに作っていてよかったです。 その後、以前コンテストで作ったゲームを個人的に作りなしているゲームを見せてくれました。そこで、段差を上った時に、段差から降りれないバグになっていたので、次回はそれの手助けになるよう、重力ジャンプを教えてもいいかもしれません。', null, 'タイピング: 検定を受けるそうで必死に練習しました
盛り上がり: ゆきちゃんと喋りながら突っ込み突っ込まれ楽しくやっていました。'),
  ('95675a81-6b96-5c67-ae3e-ebadbbcd0d66', 'b2246586-4496-52f9-a825-be2488a00a31', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2022-11-24', '17:30:00', null, '通常 / ゲーム作成', '今日は最初の方は面倒そうにしていましたが、途中から追いかけっこのゲームを作っていました。時間が余ったので、アレンジしてみたら？と言うと、取ったら使えるアイテムを付け加えていました。ただ未完成らしく詳しくは見せてくれませんでした。', null, null),
  ('9fd648fa-9fe6-533f-8e0e-f0db7572577a', 'cf94ca77-6621-5a19-b35e-6f2e124107d6', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-22', '17:30:00', null, '通常 / 簡単な条件分岐に慣れる', '使用するブロックがかずとくんと似ていたので、何度も見比べながら楽しそうに作ってくれました。 アルくんの向きを上下移動の時には変えないようにすることも、一度で覚えて作成できていました。 条件分岐のときにずっとを使うこともよく覚えていました。 アルくんが隠れるときに食べる音を入れたり、コスチュームに落書きしたりと楽しそうにしていました。', null, 'タイピング: まだうまくいかない部分もあり、難しくなるとお兄ちゃんに席を譲っていました…
盛り上がり: 何度もかずとくんの作品と見比べて、お互いにプレイさせ合ったりしながら、楽しそうに作成できていました。 「これを作ろう」「今度はこういう動きを作ってみよう」のようなこちらの提案にもやる気を見せてくれるようになりました。'),
  ('34a0694a-4cdd-5f56-8bfe-b87c40c9ba33', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-22', '17:30:00', null, '通常 / 条件分岐と変数の定着、金魚すくい完成', '条件分岐は比較的覚えていたようで、戸惑いなく作成できていました。 変数については「スコアには変数を使う」ということは覚えていたものの、使用するブロックに迷ってしまったため、復習が必要でした。 変数を作成してスコアがカウントできるようになると、「得点がたまったらクリアにしたい」と自分からアレンジを始めて完成させていました。 クリアのスプライト表示のときに音を入れることを提案したら、楽しそうにやっていました。', null, 'タイピング: 自分のアカウントではクリアしてしまったからといって、そうじくんのアカウントでも進めていました。タイピングが楽しそうでよくできているので、お母さんに毎パソのチラシを渡してお勧めしてみました。本人はやってもかまわないけど、という感じでした。
盛り上がり: 使えるブロックが少しずつ増えてきたせいか、作成を楽しめているようでした。 自分のアイディアを自分の知識で形にすることを喜んでくれているようでした。'),
  ('f62fbaa5-5605-54bf-9aa1-75397ea45742', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2022-11-24', '16:30:00', null, '通常 / 前回の続き アルスパーク/初級 ジャンプゲームを作ろう！ 草1が動いていないので、そこの見直しから（繰り返しの中に入れるべきブロックとそうでないブロックの見極め、「座標を○ずつ変える」と「座標を○○にする」の違いの復習）', '前回作成したコードでは草が動かなかったので、コードを上から順にみてそれぞれがどの動きをさせているかを確認してきました。 一つ一つのブロックについて、きちんと説明ができました。x座標のプラスマイナスと、不等号の関係が少し曖昧だったので、手動でスプライトを動かして座標の動きを見ながら、スプライトがどの位置にきたときにどういう動きをしてほしいのかを考え、繰り返しの中に入れるべきコードと外に出さなければいけないコードを見つけることができました。 木のコードは基本的には写経をしながら、1行ごとにここで何をしているのかをそうちゃんに説明してもらいつつ進めました。なぜここで乱数を使っているのかも、大体の想像はついているようでした。 乱数の数字とコスチュームの関係や、木の高さをy座標の乱数で変えていることも「わかった」と言って面白そうにしていました。', 'みずきくんのリクエストで、10メートル進んだらゲームクリアを作成したいそうです。', 'タイピング: ローマ字一文字の反応はかなり早くなりましたが、単語になるとまだ少し難しいようです。
盛り上がり: 写経とはいえ、基本的に自分が何のコードを書いているかをわかっているようで、「こんなに演算式を使うのすごい！」「これは乱数を使うのねー、ふーん」などとコメントしながら楽しそうに作成していました。 ゲームが完成できたことが嬉しそうで、みずきくんやお母さんに得意そうに披露していました。
備考: お誕生日祝いに箱根に旅行に行って、黒たまごを食べたそうです。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
